-- Phase 7 INSERT part 02/6 (250 cards)
-- 자동 생성: scripts_phase7/02_json_to_sql.py

insert into public.qas
  (doctor_id, type, category, status, published,
   question, answer, keywords,
   post_year, post_slug, external_url, pubmed_ref,
   created_at, updated_at)
values
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$아토피 피부염 관리에서 가장 중요한 것은 무엇인가요?$AAQ$, $AAA$아토피 피부염 관리의 가장 중요한 핵심은 **기승전 보습**입니다. 무너진 피부 장벽을 복구해 주는 게 제일 중요한데, 그 중심 역할을 하는 게 바로 보습제예요.

피부 장벽은 전쟁의 최전방과 같아서, 무너지면 먼지·세균·곰팡이·진균 같은 외부 침입자로부터 방어를 못 하게 되고 결국 피부염과 가려움증이 생깁니다. 피부 장벽의 주요 성분은 줄임말로 세콜지, 즉 **세라마이드, 콜레스테롤, 지방산을 함유하고 있는 보습제를 사용하는 것**이 제일 좋습니다. 또한 스크럽이나 필링제, 때타올로 미는 행위는 아토피 피부에 자극이 되어 뒤집어질 확률이 높으니 자제하고 보습제로 덮어주셔야 해요. 샤워는 약산성 세정제로 미지근한 물에서 10~15분 정도 가볍게 씻고, 뜨거운 드라이기 대신 **씻고 나서 물기가 살짝 남은 상태에서 3분 이내에 보습제를 충분히 발라야** 합니다.$AAA$, array['기승전보습', '세콜지보습제', '피부장벽복구', '약산성세정', '3분보습']::text[], 2023, 'Y0Eeq3BQU5w-2', 'https://youtu.be/Y0Eeq3BQU5w?t=260s', null, '2023-07-11 00:00:00+00'::timestamptz, '2023-07-11 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$아토피 피부염에 음식을 제한해야 하나요?$AAQ$, $AAA$음식 제한은 주로 3세 미만 소아에서만 효과가 있을 수 있고, 그 이상 연령에서는 무분별한 제한이 오히려 해롭습니다. 음식물은 **주로 5세 이하, 특히 3세 미만의 소아에서 증상을 악화시키는 요인**으로 작용할 수 있어요.

아이가 특정 음식을 먹을 때마다 증상이 악화된다면 그 음식의 섭취를 제한하면 어느 정도 도움이 될 수 있습니다. 하지만 그 이상 연령대의 소아나 성인은 음식물이 피부에 미치는 영향이 크지 않은 것으로 생각되기 때문에, **너무 무분별하게 음식물을 제한하면 오히려 영양 결핍이 될 수 있어** 조심해야 합니다. 특정 음식의 알레르기가 의심된다면 무작정 제한하지 마시고 꼭 전문의 진료를 보고 정확한 검사를 통해 결정해 주세요. 또한 민간요법은 대부분 안전성이 입증되지 않았고, 가뜩이나 피부 장벽이 깨진 아토피 피부에는 심한 자극이 되어 증상이 악화될 수 있어 피하시는 것이 좋습니다.$AAA$, array['아토피음식', '음식제한', '영양결핍', '알레르기검사', '민간요법']::text[], 2023, 'Y0Eeq3BQU5w-3', 'https://youtu.be/Y0Eeq3BQU5w?t=443s', null, '2023-07-11 00:00:00+00'::timestamptz, '2023-07-11 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$아토피 피부염에 도움 되는 영양제나 목욕법이 있나요?$AAQ$, $AAA$달맞이꽃 종자유와 일부 유산균이 보조적으로 도움이 되며, 오트밀이나 쌀겨를 푼 목욕도 증상 완화에 좋습니다. 달맞이꽃 종자유는 **감마리놀렌산 등의 필수 지방산을 함유**하고 있어 종종 보조 치료로 사용돼요.

아토피 피부염에는 피부 내 필수 지방산 대사 이상이 동반된다고 알려져 있어서, 달맞이꽃 종자유가 호전 상태 유지에 도움이 되는 것으로 보고 있습니다. 비타민 D나 락토바실러스균, 비피더스균 같은 유산균도 일부 연구에서는 효과가 거의 없다고 보고되지만 부작용이 거의 없어 보조적으로 권유됩니다. 피부염이 심해 세정제만 닿아도 따끔거리는 분들은 **오트밀이나 쌀겨, 녹말가루를 욕조에 풀고 15~20분 정도 몸을 담그면** 증상 완화에 도움이 돼요. 실내 온도 18~21도, 습도 40~50%로 유지하고 면 소재 옷을 입는 생활 수칙도 함께 지키는 것이 좋습니다.$AAA$, array['달맞이꽃종자유', '감마리놀렌산', '유산균보조', '오트밀목욕', '실내습도']::text[], 2023, 'Y0Eeq3BQU5w-4', 'https://youtu.be/Y0Eeq3BQU5w?t=663s', null, '2023-07-11 00:00:00+00'::timestamptz, '2023-07-11 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$제모 레이저 한 번 받으면 털이 다 없어지나요?$AAQ$, $AAA$제모 레이저는 한 번에 모든 털이 제거되지 않으며 보통 한 달 주기로 4~5회 받는 것이 기본 프로토콜입니다. 모낭 안의 멜라닌 구조물을 레이저로 타깃해 열로 변환시켜 모낭 전체가 파괴되고 탈락하게 만드는 원리입니다.

그런데 모발은 생장기, 퇴행기, 휴지기로 주기가 나뉘는데 레이저는 **주로 생장기 모발만 타깃**하기 때문에 한 번의 시술로 모든 털을 제거하기 어렵습니다. 또한 개인마다 피부색, 털의 굵기, 시술 부위에 따라 효과와 필요 횟수가 달라요. 백인은 털 멜라닌 함량이 낮아 레이저 흡수가 약하고, 피부색이 어두운 분은 색소침착이나 화상 위험 때문에 에너지를 한없이 올릴 수 없습니다. **한 달 주기로 4~5회를 기본 프로토콜로 안내드리고** 부족하면 추가 시술이 필요합니다.$AAA$, array['제모레이저', '모발주기', '시술횟수', '생장기모발']::text[], 2023, 'zILE8aFlmrY-1', 'https://youtu.be/zILE8aFlmrY?t=171s', null, '2023-07-13 00:00:00+00'::timestamptz, '2023-07-13 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$제모 레이저 받으면 털이 더 굵어지고 땀이 더 나나요?$AAQ$, $AAA$제모 레이저로 털이 굵어지는 것은 오해입니다. 모발 구조 자체가 밑으로 내려갈수록 더 굵어지기 때문에, 윗부분만 제모되었다가 다시 자라 올라오면 굵게 느껴지는 것입니다.

실제로 레이저가 **모발 자체의 두께를 증가시키지는 않습니다**. 다만 일부 분들은 역설적 다모증이라고 해서 레이저 후 주변으로 털이 더 자라기도 하는데, 주로 피부가 어두운 분에게 잘 발생하고 모낭 손상보다 낮은 에너지가 오히려 모발 주기를 촉진해 생기는 현상이에요. 땀이 더 난다는 것은 **털이 있을 땐 땀이 털에 묻어 증발했지만 제모 후엔 피부에 바로 맺히면서 흐르는 느낌**으로 더 많게 느껴지는 것입니다. 역설적 다모증도 다시 골고루 제모 레이저를 하면 없어질 수 있어 크게 걱정하지 않으셔도 됩니다.$AAA$, array['역설적다모증', '털굵기', '땀배출', '제모속설']::text[], 2023, 'zILE8aFlmrY-2', 'https://youtu.be/zILE8aFlmrY?t=303s', null, '2023-07-13 00:00:00+00'::timestamptz, '2023-07-13 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$제모 레이저 받기 전후 어떻게 관리해야 하나요?$AAQ$, $AAA$제모 레이저 전에는 시술 하루 이틀 전 면도로 털을 잘라두시는 것이 좋고, 시술 당일 면도는 피하시는 게 좋습니다. 색소 구조를 타깃하는 시술이라 털이 길게 자라 있으면 화상 위험이 있기 때문입니다.

다만 **왁싱이나 털을 뽑는 것은 타깃 구조까지 제거**되니 피해 주세요. 시술 후엔 쿨링이 가장 중요해서, 사우나나 땡볕에 오래 있는 것은 피하시고 보습제를 차게 해 여러 번 덧발라 주세요. 시술 당일 피부의 붉은 기는 보통 하루 이내에 가라앉지만, **시간이 지날수록 부기가 심해지거나 오래 가는 경우는 화상 또는 연고에 대한 알레르기 피부염일 수 있어** 바로 병원에 내원하셔야 합니다. 시술 장비의 냉각 장치와 사후 쿨링 처치는 모두 피부 표면을 열로부터 보호해 부작용을 줄이려는 과정입니다.$AAA$, array['시술전면도', '쿨링관리', '왁싱주의', '부작용대처']::text[], 2023, 'zILE8aFlmrY-3', 'https://youtu.be/zILE8aFlmrY?t=406s', null, '2023-07-13 00:00:00+00'::timestamptz, '2023-07-13 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$집에서 쓰는 홈케어 제모 기기도 효과가 있나요?$AAQ$, $AAA$홈케어 제모 디바이스는 병원용 레이저와 작용 원리는 같지만 강도가 훨씬 떨어져 효과 측면에서 차이가 있습니다. 인터넷에서 판매되는 주로 IPL 제모 기계 형태이지만 의료기기 등급이 달라요.

사람마다 털의 굵기와 피부색에 따라 적정 에너지가 다른데 혼자서는 이를 조절하기 어렵고, 잘 모른 채 계속 사용하면 **피부 변색 같은 부작용이나 화상 위험**이 있을 수 있습니다. 그래서 권고드리는 것은 식약처에서 허가받은 제품인지 허가번호를 확인하고 구매하시고, **사용 설명서를 꼼꼼히 읽어 허가받은 부위에만 사용하시는 것이 좋습니다**. 같은 의료기기라도 병원 장비는 가장 높은 등급으로 홈케어 기기보다 출력이 훨씬 강하기 때문에 효과 차이는 당연히 존재합니다.$AAA$, array['홈케어디바이스', 'IPL제모', '식약처허가', '출력차이']::text[], 2023, 'zILE8aFlmrY-4', 'https://youtu.be/zILE8aFlmrY?t=520s', null, '2023-07-13 00:00:00+00'::timestamptz, '2023-07-13 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$백반증 신약 옵젤루라는 어떤 약인가요?$AAQ$, $AAA$옵젤루라는 면역 과정을 차단하는 JAK 억제제 크림 제형의 백반증 치료제로, 주성분은 룩소리티닙입니다. 미국에서는 2022년 6월, 유럽에서는 2023년 4월에 성인 및 청소년 얼굴 백반증 치료제로 승인된 세계 최초의 백반증 전용 신약입니다.

과거에는 스테로이드, 프로토픽, 엘리델 등을 사용했지만 모두 아토피나 건선 같은 다른 질환에서 승인된 약이었지 **백반증 치료에 승인된 약물은 없었습니다**. JAK 억제제는 면역 신호 전달 체계의 수용체 부분을 차단해 류머티즘 관절염이나 궤양성 대장염에서 먼저 사용되다가 피부 질환에도 효과가 발견됐어요. **피부 흡수가 가능할 만큼 분자량이 작아 크림 제형으로 개발됐고**, 백반증 부위에만 발라 전신 부작용 부담을 크게 덜어낼 수 있다는 장점이 있습니다.$AAA$, array['옵젤루라', 'JAK억제제', '룩소리티닙', '백반증신약']::text[], 2023, 'U6JCjZHJ6a8-1', 'https://youtu.be/U6JCjZHJ6a8?t=0s', null, '2023-07-17 00:00:00+00'::timestamptz, '2023-07-17 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$옵젤루라 얼굴 백반증 치료 효과는 어느 정도 인가요?$AAQ$, $AAA$옵젤루라 크림을 6개월간 하루 2회 바르면 얼굴 백반증이 75% 이상 소실된 환자는 약 29.8~30.9%로 3명 중 1명꼴이며, 90% 이상 소실된 환자는 15.3~16.3%로 6명 중 1명 정도였습니다.

총 **674명이 참여한 두 건의 임상 시험** 결과로, 1년간 발랐을 때는 51% 환자에서 75% 이상 소실, 31% 환자에서는 90% 이상 소실을 경험했습니다. 1년 도포 시 가장 흔한 부작용은 도포 부위 여드름 6%, 가려움증 5%로 치료를 중단할 만한 심각한 부작용은 발생하지 않았어요. 다만 **약을 중단하면 백반증이 다시 재발**할 수 있어 JAK 억제제는 완치보다 면역 반응을 멈춰 효과를 보이는 약입니다. 효과적이고 안전한 약물임이 임상 시험으로 증명된 셈입니다.$AAA$, array['옵젤루라효과', '임상시험결과', '재발가능성', '부작용프로파일']::text[], 2023, 'U6JCjZHJ6a8-2', 'https://youtu.be/U6JCjZHJ6a8?t=252s', null, '2023-07-17 00:00:00+00'::timestamptz, '2023-07-17 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$옵젤루라는 모든 백반증 환자에게 효과가 있나요?$AAQ$, $AAA$옵젤루라는 모든 백반증 환자가 아닌 비분절형 백반증, 신체 10% 미만 범위, 백모가 없는 환자를 대상으로 임상 시험이 진행됐기 때문에 적용 범위에 한계가 있습니다.

첫째, 분절형 백반증 환자에게는 이 결과가 적용되지 않습니다. 둘째, 전신에 광범위한 백반증 환자에게 얼마만큼 효과를 보일지는 알 수 없어요. 셋째 가장 중요한 점은 백모 환자가 연구에서 제외됐다는 것인데, **백모는 백반증 치료 경과를 예측하는 가장 중요한 요소** 중 하나입니다. 백모가 없으면 엑시머나 광선 치료로도 잘 되지만, **백모가 많으면 수술적 방법을 고려**해야 하는 경우가 많아 옵젤루라가 엑시머 레이저 치료를 완전히 대체하기는 어렵습니다. 새로운 신약들이 임상 중이라 향후 더 나은 결과가 기대됩니다.$AAA$, array['분절형백반증', '백모', '치료한계', '엑시머레이저']::text[], 2023, 'U6JCjZHJ6a8-3', 'https://youtu.be/U6JCjZHJ6a8?t=2059s', null, '2023-07-17 00:00:00+00'::timestamptz, '2023-07-17 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$옵젤루라 가격은 얼마이고 직구해서 써야 할까요?$AAQ$, $AAA$옵젤루라 60g의 미국 판매가는 1,945달러로 한화 약 258만 원이 넘어 비싼 돈을 들여 직구나 불법 복제약을 구매할 필요까지는 없습니다. 현재 백반증에 널리 사용되는 프로토픽 연고도 6개월 도포 시 얼굴 백반증 75% 이상 소실 환자가 65%에 달해 효과적이기 때문입니다.

환자분들 중에는 미국 직구를 고려하거나 제3세계 복제약을 **개당 25만 원에 사서 써도 되냐고 묻는** 분들이 계십니다. 두 연고를 직접 비교한 임상 시험은 없지만 여러 데이터를 종합해 보면 프로토픽이 옵젤루라보다 크게 떨어진다는 생각은 들지 않습니다. **국내 도입 시에는 심평원과 제약회사 논의로 미국보다 훨씬 낮은 가격에 들어올 가능성이 많고** 보험 적용과 실비 보험 적용도 받을 수 있어 그때를 기다리는 것이 합리적입니다.$AAA$, array['옵젤루라가격', '프로토픽비교', '직구주의', '보험적용']::text[], 2023, 'U6JCjZHJ6a8-4', 'https://youtu.be/U6JCjZHJ6a8?t=487s', null, '2023-07-17 00:00:00+00'::timestamptz, '2023-07-17 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$피부과 전문의가 되려면 어떤 과정을 거치나요?$AAQ$, $AAA$피부과 전문의가 되려면 의과대학 졸업 후 의사 국가고시 합격으로 의사 자격증을 취득하고, 인턴 1년과 레지던트 4년의 수련을 마친 뒤 전문의 시험에 합격해야 합니다.

학교를 졸업하고 의사 국가고시만 합격해도 의료인이므로 의료 행위는 모두 할 수 있지만, **전문의와는 차이가 있습니다**. 학생 때는 이론과 교과서 강의 자료 위주로 공부하고 본 3, 4학년 때 실습을 돌지만 의료 면허가 없어 참관 위주로 배웁니다. 레지던트가 되면 직접 환자를 보고 처치와 술기를 하며 외래 진료도 열어보는 등 능동적으로 배웁니다. **레지던트 1, 2년 차에는 환자 병변과 피부 속 세포를 매칭하는 훈련을 무한 반복하고**, 3년 차쯤 외래 환자를 보기 시작하는 체계적인 수련 과정을 거칩니다.$AAA$, array['피부과전문의', '레지던트수련', '의사국가고시', '전문의시험']::text[], 2023, 'pf8nJWV_qhg-1', 'https://youtu.be/pf8nJWV_qhg', null, '2023-07-19 00:00:00+00'::timestamptz, '2023-07-19 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$피부과 전문의와 일반 의원은 어떻게 구분하나요?$AAQ$, $AAA$피부과 전문의 병원은 'OOO피부과 의원'으로 간판이 표기되며, 다른 과를 전공했거나 일반의가 진료하는 곳은 'OO의원' 또는 진료과목에 '피부과'라고 표시되도록 법으로 정해져 있습니다.

피부과 전문의는 **4년 전공의 생활을 거치고 시험도 통과해 학회의 인정을 받은 분들**이라는 점에서 일반의와 구분됩니다. 전문의는 가장 기초적인 병리부터 피부의 구조, 다양한 질환들을 공부하고 케이스를 경험하기 때문에 피부 질환 진단을 더 잘할 수 있어요. 또한 치료 시 **당장 효과를 보이는 강한 치료보다 장기적인 피부 건강과 부작용을 고려해** 권유하는 경향이 있습니다. 시술 후 부작용이 생기더라도 적절한 후처치로 후유증을 최소화할 수 있는 측면에서 전문의의 역할이 중요합니다.$AAA$, array['피부과간판', '전문의구분', '일반의', '병원선택']::text[], 2023, 'pf8nJWV_qhg-2', 'https://youtu.be/pf8nJWV_qhg', null, '2023-07-19 00:00:00+00'::timestamptz, '2023-07-19 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$피부과 전문의는 미용 시술 경험이 부족하지 않나요?$AAQ$, $AAA$피부과 전문의는 미용 시술 경험이 부족하지 않습니다. 대학병원에서도 레이저 장비를 다루고 있고 학회나 워크숍에서 직접 술기 교육도 진행하기 때문입니다.

기본적으로 피부과적인 지식을 갖추고 있어 **장비의 원리부터 배우고 적절히 활용하고 응용할 수 있다는 강점**이 있습니다. 병원마다 개개인의 피부 상태를 측정할 수 있는 장비가 갖춰져 있어 홍조, 모공, 색소 등을 파악한 뒤 맞춤형 커스터마이즈 치료가 가능합니다. 또한 시술 후 부작용이 생기더라도 **적절한 후처치로 후유증을 최소화할 수 있어** 전문의의 역할이 중요합니다. 피부에 문제가 생겼을 때 피부과 전문의가 아닌 곳을 찾기보다 전문의를 선택하시는 것이 확률적으로 더 안전한 선택입니다.$AAA$, array['대학병원미용시술', '맞춤형치료', '후처치', '장비활용']::text[], 2023, 'pf8nJWV_qhg-3', 'https://youtu.be/pf8nJWV_qhg', null, '2023-07-19 00:00:00+00'::timestamptz, '2023-07-19 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$스티바A가 단종됐는데 대체할 수 있는 연고가 있나요?$AAQ$, $AAA$스티바A가 2023년 8월 단종 예정이지만, 트레티노인 단일성분으로 이뤄진 프로좀A 크림과 투앤티 크림 등이 대체 가능한 제품입니다. 식약처 의약품 동등성 시험을 통해 1차 평가에서 14개 연고가 탈락하거나 취하되고 남은 3가지 중 시장에서 구할 수 있는 두 제품입니다.

대체품 선택 시 두 가지를 고려해야 합니다. 첫째 **트레티노인 단일성분으로 이뤄진 제품인가**, 둘째 우리가 원하는 효과가 무엇인가입니다. 단일 성분이란 연고의 유효성분이 오직 트레티노인으로만 이뤄졌다는 뜻입니다. 이 외에도 태극제약의 아지나크림이나 갈더마코리아의 레타크닐 크림 등이 있어요. 다만 **제약사마다 조제 방법이 다르므로 트레티노인 함유량이 같다고 같은 효과·안전성을 가진다고 단정 짓기는 어렵습니다**.$AAA$, array['스티바A단종', '트레티노인', '프로좀A', '투앤티크림']::text[], 2023, '0ee5NC6YrUE-1', 'https://youtu.be/0ee5NC6YrUE?t=128s', null, '2023-07-21 00:00:00+00'::timestamptz, '2023-07-21 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$프로좀A와 투앤티 크림은 어떤 차이가 있나요?$AAQ$, $AAA$프로좀A 크림은 15g, 투앤티 크림은 20g, 스티바A는 25g으로 용량 차이가 있고, 발림성과 입구 모양에도 차이가 있습니다. 얼굴을 반반으로 나눠 한 달간 사용한 결과 투앤티 크림 부위에서 각질이 조금 더 많이 일어났습니다.

프로좀A 크림은 **입구 부분이 샤프한 편이어서 용량 조절이 편했고**, 투앤티 크림은 그보다 덜 샤프했지만 스티바A보다는 편했습니다. 투앤티 크림은 프로좀A보다 약간 더 노란빛을 띠고 묽어서 발림성이 가벼운 느낌이었어요. **각질이 일어나는 것을 보면 트레티노인 성분이 제 역할을 한다는 신호**로, 각질 턴오버 증가 효과가 있다고 볼 수 있습니다. 한 달 사용 경험만으로는 둘 중 무엇이 더 좋다 단정하기 어렵고, 스티바A처럼 3~6개월 꾸준히 사용해야 효과를 어느 정도 느낄 수 있습니다.$AAA$, array['프로좀A', '투앤티', '용량비교', '발림성']::text[], 2023, '0ee5NC6YrUE-2', 'https://youtu.be/0ee5NC6YrUE?t=300s', null, '2023-07-21 00:00:00+00'::timestamptz, '2023-07-21 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$트레티노인 연고를 처음 사용할 때 주의사항은요?$AAQ$, $AAA$트레티노인 연고는 기본적으로 자극을 유발할 수 있어 처음에는 쌀 한 톨 크기로 소량부터 시작해 피부를 적응시킨 뒤 천천히 용량을 증량하는 것이 좋습니다.

특히 자외선이 강한 여름철에는 외출 전 자외선 차단제를 꼼꼼히 발라 주시고, **해가 지고 난 후 취침 전에 사용하시는 것이 중요합니다**. 또 장기간 야외활동이 있는 날 전날에는 연고 사용을 하루쯤 쉬는 것도 부작용을 줄일 수 있는 방법입니다. 스티바A는 광노화를 예방한다고 여러 논문에 알려져 있고, 자외선에 계속 노출되면 광노화가 진행되어 노화가 빨라질 수밖에 없는 상황을 막아주는 효과가 있어요. **약간의 각질이 보이는 정도라면 트레티노인 성분이 제 역할을 하고 있다는 신호**로 받아들이시면 됩니다.$AAA$, array['트레티노인사용법', '쌀한톨', '자외선차단', '광노화예방']::text[], 2023, '0ee5NC6YrUE-3', 'https://youtu.be/0ee5NC6YrUE?t=424s', null, '2023-07-21 00:00:00+00'::timestamptz, '2023-07-21 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$팔자주름은 왜 깊어지고 어떤 종류가 있나요?$AAQ$, $AAA$팔자주름은 원래 얼굴에 있는 구조이지만, 피부 노화로 근육·지방·뼈의 부피가 줄거나 탄력이 떨어지면서 여러 패턴으로 두드러지게 보입니다. 윗입술을 위로 올리는 근육이 움직일 때 피부가 밀려 올라가며 자연스럽게 형성되는 주름이에요.

팔자주름이 심해지는 원인은 크게 다섯 가지입니다. 첫째 노화로 **팔자 부위 자체가 깊어지는 경우**, 둘째 볼 지방이 처지면서 골이 깊어지는 경우, 셋째 표정 지을 때 주름이 잘 안 펴져 점점 길게 연결되는 경우, 넷째 실제 팔자가 아닌 입 옆 마리오네트 라인 부위 주름, 다섯째 옆에 피부가 오글오글 접혀서 생기는 주름이 있어요. **원인이 다르면 치료도 다르기 때문에 본인의 팔자가 어떤 원인인지 제대로 알아야** 그에 맞는 치료를 할 수 있습니다.$AAA$, array['팔자주름', '노화', '마리오네트라인', '볼처짐']::text[], 2023, 'Xfr9ixIGt9U-1', 'https://youtu.be/Xfr9ixIGt9U?t=82s', null, '2023-07-26 00:00:00+00'::timestamptz, '2023-07-26 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$팔자주름 필러는 어떻게 해야 어색하지 않나요?$AAQ$, $AAA$팔자주름 필러는 쏙 패어있는 깊은 곳에 잘 주입하고 과량을 넣지 않아야 어색하지 않게 유지됩니다. 팔자 부위는 움직임이 많아 필러가 위로 밀려 올라가면 오히려 두둑해 보일 수 있기 때문입니다.

예전에 필러를 맞고 빵빵한데 안 예뻐졌다는 분들의 경우 **필러가 이동해 위쪽으로 밀려 올라간** 경우가 많습니다. 너무 많은 양을 넣으면 이동하기 쉬워 적정량을 지키는 것이 중요합니다. 또 팔자가 깊어 보이지만 정작 그 부위는 쑥 꺼지지 않은 경우도 있는데, 이때는 **앞 볼에 볼륨이 꺼져서 상대적으로 팔자가 들어가 보이는 것**이라 앞 볼을 채워줘야 어려 보이고 어색하지 않은 모양이 됩니다. 환자가 팔자가 깊다고 호소해도 구조를 봐서 다른 부위에 필러를 넣는 경우도 많습니다.$AAA$, array['팔자필러', '필러이동', '앞볼필러', '주입깊이']::text[], 2023, 'Xfr9ixIGt9U-2', 'https://youtu.be/Xfr9ixIGt9U?t=320s', null, '2023-07-26 00:00:00+00'::timestamptz, '2023-07-26 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$처진 살로 깊어진 팔자주름은 어떻게 치료하나요?$AAQ$, $AAA$볼 살이 처지면서 깊어진 팔자주름은 처진 살을 위로 올려주는 리프팅 시술이 필요합니다. 울쎄라, 슈링크 같은 초음파 리프팅으로 처진 살 위쪽을 붙여주고, 실리프팅으로 위쪽으로 당겨줄 수 있습니다.

주름 위쪽에 **뭉친 지방이 너무 많은 경우에는 리프팅 레이저로도 드라마틱한 변화가 어려워** 지방 흡입 시술을 고려할 수 있어요. 팔자가 아래로 길어진 경우에는 길어진 부위 아래쪽을 채워줘야 이전 모습이 되고, 필러, 쥬베룩, 스컬트라 같은 채우는 시술이 적합합니다. 마리오네트 라인은 신경이 지나가 **울쎄라·슈링크 같은 초음파를 직접 적용하기 어렵고**, 티타늄이나 고주파리프팅 등 다른 레이저를 사용합니다. 탄력 저하로 피부가 우글우글 우는 주름은 실리프팅이나 얕은 필러로 피부를 단단하게 만드는 치료가 필요합니다.$AAA$, array['리프팅레이저', '울쎄라', '실리프팅', '마리오네트치료']::text[], 2023, 'Xfr9ixIGt9U-3', 'https://youtu.be/Xfr9ixIGt9U?t=438s', null, '2023-07-26 00:00:00+00'::timestamptz, '2023-07-26 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$팔자주름을 예방하려면 평소 어떻게 해야 하나요?$AAQ$, $AAA$팔자주름은 피부 노화로 인한 탄력 저하가 주요 원인이므로 노화를 막는 노력이 가장 중요합니다. 자외선 차단을 위해 선크림을 잘 발라주시고, 피부가 푸석해지지 않게 보습을 항상 잘해주세요.

주름 개선 화장품이나 노화를 막아줄 수 있는 연고를 **꾸준히 발라 주시는 게 도움이 됩니다**. 또 팔자주름은 반복적으로 피부가 접히면서 생기는 것이 맞으므로 평소 입을 풍선처럼 부풀려주는 페이스 동작이 도움이 될 수 있어요. 정기적으로 못 해도 가끔 쉴 때 이렇게 해주면 주름이 펴지는 데 좋습니다. 앞볼이 밑으로 꺼지는 것도 팔자 원인이기 때문에 **앞볼 쪽 근육을 위쪽으로 올려줄 수 있는 페이스 운동들**도 어느 정도 도움이 됩니다. 어쨌든 가장 드라마틱한 결과를 주는 것은 주사 시술임을 기억하세요.$AAA$, array['팔자예방', '자외선차단', '페이스운동', '보습']::text[], 2023, 'Xfr9ixIGt9U-4', 'https://youtu.be/Xfr9ixIGt9U?t=534s', null, '2023-07-26 00:00:00+00'::timestamptz, '2023-07-26 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$바세린은 정말 피부에 좋은 성분인가요?$AAQ$, $AAA$바세린은 피부에 좋은 성분이 맞지만, 모든 사람에게 다 좋은 것은 아닙니다. 바세린은 페트롤라툼 100%로 이뤄진 대표적인 밀폐제로, 피부가 가진 수분이 날아가지 못하게 강력하게 밀폐시켜주는 역할을 합니다.

피부에 바르는 화장품에는 보통 **습윤제와 밀폐제 성분**이 있는데, 습윤제는 주변에서 습기를 끌어와 피부에 보충하고, 밀폐제는 수분 증발을 막아줍니다. 바세린은 피부 건조와 잔주름 생성을 막아주고 보습감을 주는 좋은 성분이며 화장품·연고 제품에도 페트롤라툼이 기본 성분으로 많이 들어 있어요. 다만 **별로 건조하지 않고 살짝 기름진 타입이라면 모공을 막아 여드름·피지 트러블이나 비립종 생성** 같은 부작용이 생길 수 있어 사용에 주의가 필요합니다.$AAA$, array['바세린', '페트롤라툼', '밀폐제', '습윤제']::text[], 2023, 'Y_KEFviziw4-1', 'https://youtu.be/Y_KEFviziw4?t=83s', null, '2023-07-28 00:00:00+00'::timestamptz, '2023-07-28 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$지성 피부인데 바세린을 쓰면 안 되나요?$AAQ$, $AAA$대부분 사람들의 피부는 지성이냐 건성이냐로 딱 잘라 나눌 수 없으므로, 부위별로 다르게 사용하면 지성 피부도 바세린을 활용할 수 있습니다. T존(코·입·이마 주변)은 기름지고 볼은 건조한 식으로 사람마다 부위별 차이가 큽니다.

건조하고 피부가 얇은 부위에는 바세린을 같이 써주고, **기름지고 두꺼우며 모공이 많은 부위에는 가벼운 로션만 바르는 식**으로 내 피부에 맞게 사용하는 것이 중요합니다. 좁쌀이나 모낭염, 여드름이 났던 분들이나 민감성·아토피 피부염이 있는 분들에게는 바세린 대신 아쿠아퍼(유세린) 같은 제품을 권합니다. 아쿠아퍼는 페트롤라툼 베이스에 오일과 글리세린이 추가돼 **발림성이 좋고 밀폐력과 보습력도 충분합니다**. 손 습진이나 아기 아토피 발진 부위에도 살살 발라주기 유용한 제품입니다.$AAA$, array['지성피부바세린', '부위별사용', '아쿠아퍼', '민감성피부']::text[], 2023, 'Y_KEFviziw4-2', 'https://youtu.be/Y_KEFviziw4?t=187s', null, '2023-07-28 00:00:00+00'::timestamptz, '2023-07-28 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$바세린을 가장 효과적으로 바르는 방법은 무엇인가요?$AAQ$, $AAA$바세린은 부위별로 다른 비율로 로션·크림과 섞어 발라야 가장 효과적입니다. 건조한 부위에는 크림 20%·바세린 80%, 기름진 부위에는 로션 반·바세린 반 정도로 섞는 식으로 나만의 레시피를 만드는 것이 핵심입니다.

계절에 따라서도 바꿔 쓰는데, 여름에는 가벼운 로션 타입을 많이 쓰고 **겨울에는 꾸덕한 크림에 바세린을 섞어 바르는 식**으로 조절합니다. 너무 귀찮다면 잘 쓰는 로션이나 크림을 전체에 바른 뒤 건조한 부위에만 바세린을 살짝 덧바르는 방식도 좋아요. 꾸덕하고 가려운 분들은 페트롤라툼 대신 호호바 오일이나 올리브 오일을 몇 방울 떨어뜨려 섞어 발라도 됩니다. **밤사이 먼지가 피부에 묻기 때문에 바세린 사용자는 아침 클렌징을 꼼꼼히** 하셔야 합니다. 선크림은 가장 마지막에 바르는 것이 좋습니다.$AAA$, array['바세린레시피', '부위별비율', '오일혼합', '아침클렌징']::text[], 2023, 'Y_KEFviziw4-3', 'https://youtu.be/Y_KEFviziw4?t=378s', null, '2023-07-28 00:00:00+00'::timestamptz, '2023-07-28 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$햇빛 알러지라고 하는 발진은 정확히 무엇인가요?$AAQ$, $AAA$흔히 햇빛 알러지라고 부르는 발진은 엄밀히 말하면 광민감 반응인 다형광발진에 해당합니다. 광 피부질환 중에서는 가장 흔하고, 주로 젊은 여성, 평소 해를 잘 안 보던 분들에게 봄·초여름에 잘 생깁니다.

실내 생활을 주로 하시던 분이 봄·초여름 해가 강해질 때 활동하다 보면 **노출 부위에 우툴두툴한 가려운 좁쌀이나 두드러기, 물집** 같은 발진이 올라옵니다. 일반인이 자외선을 쪼이면 면역 반응이 억제되는데 이런 분들은 그런 억제가 일어나지 않고 햇빛에 의해 새로 만들어진 항원에 과민 반응이 뒤늦게 일어나는 것이에요. 진짜 햇빛 알러지인 일광 두드러기는 따로 있는데, 태양 광선 노출 **몇 초~몇 분 이내에 두드러기가 올라오는 아주 드문 경우**이며 일상생활이 어려울 정도입니다.$AAA$, array['다형광발진', '일광두드러기', '광민감반응', '햇빛알러지']::text[], 2023, '57OMkNtcmUo-1', 'https://youtu.be/57OMkNtcmUo?t=21s', null, '2023-08-01 00:00:00+00'::timestamptz, '2023-08-01 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$다형광발진은 어떻게 대처하고 예방하나요?$AAQ$, $AAA$다형광발진은 일반적으로 노출이 안 되면 1~2주 이내 좋아지기 때문에 증상 조절 위주로 치료합니다. 항히스타민제와 스테로이드 크림을 챙겨가 조금씩 올라올 때 바르거나 복용하면 증상이 나아집니다.

예방으로는 본격적으로 해가 강해지기 전 봄철에 **피부과에서 일주일에 두 번씩 몇 주 동안 광선치료**를 하면 발진을 예방할 수 있어요. 또 가리는 의복이 중요한데, **폴리에스테르 소재가 자외선 차단 기능이 가장 우수하고** 밝은 색보다 어두운 옷이 차단을 잘합니다. 기능성 의류의 UPF 수치는 선크림의 SPF와 같은 자외선 차단 능력 지표로, 40~50 이상의 의류를 골라 착용하는 것을 권고드립니다. 한여름이 되면 피부가 적응해 일종의 내성이 생겨 괜찮아지지만 겨울 후 계절이 바뀌면 다시 생길 수 있습니다.$AAA$, array['광선치료', 'UPF의류', '항히스타민제', '다형광발진예방']::text[], 2023, '57OMkNtcmUo-2', 'https://youtu.be/57OMkNtcmUo?t=121s', null, '2023-08-01 00:00:00+00'::timestamptz, '2023-08-01 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$사람마다 햇빛에 타는 정도가 다른 이유는 무엇인가요?$AAQ$, $AAA$햇빛에 대한 반응은 사람마다 타고난 피부 타입에 따라 다르며 유전적인 요인이 있습니다. 피부과에서는 자외선 노출 후 반응에 따라 피츠패트릭 스킨 포토 타입을 1형부터 6형까지 분류합니다.

1형일수록 피부가 하얗고 화상을 입기 쉬운 백인이고, **6형은 피부색이 어두워 화상은 잘 안 입지만 색소 침착이 잘 남는 타입**입니다. 한국인 같은 동양인은 주로 3형, 4형에 해당해요. 타고난 피부 타입에 따라 자외선 취약도가 다르고, 복용 중인 약물이나 바르는 제품이 햇빛 민감도를 변형시키기도 합니다. 일광화상은 햇빛의 **UVB 파장대가 일으키며**, 피부 손상 정도에 따라 붉어지는 1도, 수포가 생기는 2도로 분류되고 햇빛 에너지로는 3도 깊이까지는 불가능합니다. 광범위한 화상은 으슬으슬한 전신증상이 나타날 수 있습니다.$AAA$, array['피츠패트릭', '스킨포토타입', 'UVB', '일광화상']::text[], 2023, '57OMkNtcmUo-3', 'https://youtu.be/57OMkNtcmUo?t=298s', null, '2023-08-01 00:00:00+00'::timestamptz, '2023-08-01 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$일광화상을 입었을 때 절대 하면 안 되는 행동은요?$AAQ$, $AAA$일광화상을 입었을 때 절대 하지 말아야 할 세 가지 행동이 있습니다. 첫째 얼음을 피부에 직접 대는 것, 둘째 물집을 터뜨리는 것, 셋째 각질을 때수건으로 밀어내는 것입니다.

얼음을 직접 대면 **지나치게 차가워 화상으로 손상된 피부 조직을 더 악화**시킬 수 있어요. 물집은 피부를 보호해주는 필름 같은 역할을 하기 때문에 터뜨리면 2차 감염 위험이 있고, 너무 땡땡해서 불편하면 집에서 혼자 처리하지 말고 병원에 오시는 게 좋습니다. 화상이 나을 때쯤 빨갛다 어두워지며 실비듬 같은 각질이 일어나는데, 지저분하다고 빼내거나 때수건으로 밀어내면 **피부에 다시 손상을 줄 수 있어 보습제를 덧바르며 자연스럽게 탈락**시켜야 합니다. 대신 시원한 물에 10분 이내로 샤워하고 보습제를 바르고, 피부가 따끔거리면 스테로이드 크림이나 이부프로펜이 도움이 됩니다.$AAA$, array['일광화상대처', '물집관리', '쿨링주의', '각질탈락']::text[], 2023, '57OMkNtcmUo-4', 'https://youtu.be/57OMkNtcmUo?t=397s', null, '2023-08-01 00:00:00+00'::timestamptz, '2023-08-01 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$얼굴에 살이 없는데 울쎄라나 슈링크 받아도 되나요?$AAQ$, $AAA$얼굴에 살이 없는 분이 울쎄라·슈링크를 볼 부위에 받으면 부작용이 생길 수 있어 권하지 않습니다. 이 기기들은 **고강도 집속 초음파**를 작은 점에 집중시켜 조직을 응고·수축시키는 HIFU 방식의 리프팅 레이저들이에요.

주 타깃은 피부의 근막층인데, **근막층 바로 옆에 인접한 피하지방층으로 에너지가 과하게 들어가면 지방이 녹게 됩니다.** 그래서 가뜩이나 얼굴에 살이 없는 분은 볼살이 더 없어지는 부작용이 생길 수 있어요. 시술을 정말 잘하면 어느 정도 피할 수 있지만, 조금이라도 부작용이 싫으신 분이라면 원래도 들어간 볼 부위에는 초음파 리프팅을 받지 않는 것이 좋습니다.$AAA$, array['울쎄라', '슈링크', 'HIFU', '볼살꺼짐', '부작용']::text[], 2023, 'kFcKWDavblo-1', 'https://youtu.be/kFcKWDavblo?t=88s', '{"pmid": "25399626", "doi": "10.1111/jocd.12111", "title": "Review of the safety profile for microfocused ultrasound with visualization.", "journal": "J Cosmet Dermatol", "year": "2014", "authors_short": "Hitchcock TM, Dobke MK", "pubmed_url": "https://pubmed.ncbi.nlm.nih.gov/25399626/", "doi_url": "https://doi.org/10.1111/jocd.12111"}'::jsonb, '2023-08-08 00:00:00+00'::timestamptz, '2023-08-08 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$볼살 없는 사람한테 추천하는 리프팅 레이저는 뭔가요?$AAQ$, $AAA$볼살이 없는 분께는 단극성 고주파를 쓰는 써마지를 가장 먼저 권해 드립니다. 써마지는 피부 표면은 냉각시켜 손상을 주지 않고 진피층에 열을 발생시켜 콜라겐 재생을 도와주는 원리예요.

그래서 시술 후 피부가 쫀쫀해지고 **타이트닝 되는 효과**를 보실 수 있어요. 비슷한 원리의 제품으로 텐써마, 올리지오, 쓰리딥, 인모드, 튠페이스 등이 있습니다. **고주파 에너지를 사용하는 경우 시술을 적절하게 잘 받으면 부작용이 거의 없다고** 보시면 됩니다. 초음파 리프팅처럼 피하지방을 녹이는 메커니즘과는 결이 달라, 살 없는 분에게 더 안전한 선택지로 권해 드려요.$AAA$, array['써마지', '고주파리프팅', '콜라겐재생', '볼살없음', '타이트닝']::text[], 2023, 'kFcKWDavblo-2', 'https://youtu.be/kFcKWDavblo?t=162s', '{"pmid": "39957006", "doi": "10.1002/lsm.70002", "title": "Long-Term Efficacy and Safety of a Novel Monopolar Radiofrequency Device for Skin Tightening: A Prospective Randomized Controlled Study.", "journal": "Lasers Surg Med", "year": "2025", "authors_short": "Wang Z, Li L, Zhang X et al.", "pubmed_url": "https://pubmed.ncbi.nlm.nih.gov/39957006/", "doi_url": "https://doi.org/10.1002/lsm.70002"}'::jsonb, '2023-08-08 00:00:00+00'::timestamptz, '2023-08-08 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$살 없고 잔주름 많은 피부에 스킨 보톡스 효과 있나요?$AAQ$, $AAA$살 없으면서 잔주름이 많은 피부에는 **스킨 보톡스 하나만으로도** 드라마틱하게 좋아질 수 있어요. 살이 적고 얇은 피부는 주름이 비교적 잘 잡히는데, 이런 주름을 잡는 데 보톡스만큼 가성비 좋은 시술이 없습니다.

표정을 지을 때 잡히는 이마·미간·눈가 주름에는 주름 보톡스가 좋은 효과를 보이고, **얼굴 전반적인 잔주름이나 탄력 개선에는 스킨 보톡스가 비용 대비 효과가 좋습니다.** 특히 살 많고 축 처진 분보다는, 살이 없으면서 쪼글쪼글한 잔주름이 많은 분들에서 스킨 보톡스 단독으로도 만족도가 큰 편이에요.$AAA$, array['스킨보톡스', '잔주름', '주름보톡스', '탄력개선', '가성비시술']::text[], 2023, 'kFcKWDavblo-3', 'https://youtu.be/kFcKWDavblo?t=218s', '{"pmid": "35965899", "doi": "10.4103/JCAS.JCAS_162_21", "title": "Microdroplet Botulinum Toxin: A Review.", "journal": "J Cutan Aesthet Surg", "year": "2022", "authors_short": "Kandhari R, Kaur I, Gupta J et al.", "pubmed_url": "https://pubmed.ncbi.nlm.nih.gov/35965899/", "doi_url": "https://doi.org/10.4103/JCAS.JCAS_162_21"}'::jsonb, '2023-08-08 00:00:00+00'::timestamptz, '2023-08-08 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$필러와 쥬베룩 볼륨은 살 없는 얼굴에 어떻게 다른가요?$AAQ$, $AAA$필러는 즉각적인 볼륨을, 쥬베룩 볼륨은 시간이 지나면서 자연스러운 볼륨을 만든다는 점이 본질적 차이입니다. 필러는 히알루론산을 결합시켜 안정적 형태로 피부 속에 머무르게 함으로써 주입 부위에 **즉각적으로 볼륨**을 만들어 줍니다.

반면 쥬베룩 볼륨은 PDLA(Poly D-lactic acid)에 히알루론산이 결합된 시술로, 주입 후 분해되면서 콜라겐 생성을 유도해 점점 탄력과 볼륨이 올라옵니다. **처음 주입했을 때보다 시간이 지나면 볼륨감이 필러보다는 떨어진 느낌이 확실히 있어요.** 부자연스러운 빵빵함이 싫어 주사 시술이 두려운 분께는 자연스럽게 차오르는 쥬베룩 볼륨이 더 잘 맞고, 즉각적인 앞볼·옆볼·관자·눈 밑 꺼짐 보정은 필러가 강점이에요.$AAA$, array['필러', '쥬베룩볼륨', 'PDLA', '히알루론산', '볼륨비교']::text[], 2023, 'kFcKWDavblo-4', 'https://youtu.be/kFcKWDavblo?t=275s', '{"pmid": "39496962", "doi": "10.1007/s00266-024-04487-z", "title": "The Differences Between Sculptra and AestheFill Reconstitution Processes.", "journal": "Aesthetic Plast Surg", "year": "2024", "authors_short": "Lin JY, Peng X, Lin CY", "pubmed_url": "https://pubmed.ncbi.nlm.nih.gov/39496962/", "doi_url": "https://doi.org/10.1007/s00266-024-04487-z"}'::jsonb, '2023-08-08 00:00:00+00'::timestamptz, '2023-08-08 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$주사도 무섭고 초음파도 아픈데 받을 수 있는 시술 있나요?$AAQ$, $AAA$써마지·울세라처럼 아픈 게 싫고 필러·쥬베룩 같은 주사도 무서운 분께는 미라젯 리쥬비네이션을 권해 드려요. 자연스럽게 한 듯 안 한 듯 탄력이 올라오는 것을 선호하는 분에게 잘 맞는 시술입니다.

주로 **쥬베룩 성분을 주입**하는데, 쥬베룩 볼륨보다 입자 크기가 작아 잔주름 완화·피부결 개선·모공 축소 효과가 있어요. 이전에는 수기로 일일이 주입해 통증이 컸지만 미라젯 도입 이후 **통증 때문에 망설이시는 분들이 많이 줄어들었고 약물도 피부 전체에 고르게 주입됩니다.** 다만 쥬베룩은 분해되며 자가 콜라겐을 만드는 방식이라 효과가 바로 나타나기보다 시간이 좀 걸리는 단점이 있어, 즉각적 볼륨보다는 점차 탄력이 좋아지길 원하는 분께 적합해요.$AAA$, array['미라젯', '쥬베룩', '통증개선', '모공축소', '자연스러운탄력']::text[], 2023, 'kFcKWDavblo-5', 'https://youtu.be/kFcKWDavblo?t=395s', '{"pmid": "42098500", "doi": "10.1007/s00266-026-05817-z", "title": "Hybrid Biostimulator and Hyaluronic Acid Injectable for Tear Trough Rejuvenation.", "journal": "Aesthetic Plast Surg", "year": "2026", "authors_short": "Young SM, Lau EKH", "pubmed_url": "https://pubmed.ncbi.nlm.nih.gov/42098500/", "doi_url": "https://doi.org/10.1007/s00266-026-05817-z"}'::jsonb, '2023-08-08 00:00:00+00'::timestamptz, '2023-08-08 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$선크림 어느 정도 양을 발라야 SPF 그대로 효과 나요?$AAQ$, $AAA$선크림 권장량은 **1cm²당 2mg**으로, 우리가 평소 바르는 양은 권장량의 4분의 1 수준이라 차단 효과가 8분의 1까지 떨어집니다. 자외선차단지수는 이 권장량을 발랐을 때 측정된 수치예요.

연구에서는 피츠패트릭 3·4 피부색을 대상으로 한국에서 유통되는 SPF30·SPF35 선크림을 다양한 양으로 발라 비교했는데, **권장량(1cm²당 2mg)을 다 발랐을 때는 SPF가 24.6으로 30에 가깝게 차단**되었지만 1cm²당 0.5mg만 발랐을 때는 SPF3 수준에 그쳤어요. 거의 8배 차이가 나는 셈입니다. 얼굴에 바를 양은 큰 동전 하나 정도, 또는 검지 한 마디를 가득 채우는 정도이고, 목에는 큰 스푼으로 두 스푼(앞·뒤 따로)을 발라 주셔야 합니다.$AAA$, array['선크림권장량', 'SPF', '도포량', '자외선차단', '8배차이']::text[], 2023, 'voaT-43Y1Lc-1', 'https://youtu.be/voaT-43Y1Lc?t=121s', null, '2023-08-18 00:00:00+00'::timestamptz, '2023-08-18 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$SPF 화장품만 발라도 자외선 차단 되나요?$AAQ$, $AAA$선크림 성분이 포함된 화장품만 바르면 자외선 차단 기능이 많이 떨어집니다. 화장품에 포함된 선크림 양은 원래도 적은데, 실제 도포량은 권장량의 반의 반의 반도 안 되는 경우가 많기 때문이에요.

양이 줄어들면 **차단 효과도 8분의 1로 줄어듭니다.** 1cm²당 2mg을 발라야 SPF 표기 수치만큼 차단되는데, 화장품에 들어 있는 선크림 양과 실제 사용량을 곱하면 보호 효과가 크게 떨어지는 거예요. 그래서 **화장하시기 전에 선크림을 먼저 바르고 그 다음에 화장을 해 주시는 것이 중요합니다.** 큰 트러블이 없고 민감하지 않은 피부라면 SPF50+ 제품을 권해 드리고, 일반적인 도포량으로 자외선을 최대한 차단하고 싶다면 SPF70 이상을 쓰는 것이 좋아요.$AAA$, array['선크림화장품', 'SPF50', '도포순서', '자외선차단', '올인원']::text[], 2023, 'voaT-43Y1Lc-2', 'https://youtu.be/voaT-43Y1Lc?t=356s', null, '2023-08-18 00:00:00+00'::timestamptz, '2023-08-18 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$선크림 안 바르면 피부에 어떤 문제가 생기나요?$AAQ$, $AAA$선크림을 안 바르면 잡티뿐 아니라 **노화·잔주름·난치성 기미·피부암까지** 야기될 수 있습니다. 많은 분이 선크림을 잡티 예방용으로만 알고 계시지만, 가장 중요한 이유는 노화와 잔주름 예방이에요.

자외선을 오래 쬐면 노화와 잔주름이 진행되고, 면적이 넓은 난치성 기미나 피부암까지도 생길 수 있습니다. 실제로 설문에서는 거의 바르지 않거나 야외활동 시에만 바른다고 답한 분이 45%로 절반에 가까웠고, 이유는 귀찮아서·발림성이 싫어서·바를 이유를 못 느껴서가 많았어요. **목에 선크림을 안 바른 사례 사진처럼** 노출 부위와 비노출 부위 차이가 육안으로도 분명하게 드러납니다. 그래서 귀찮더라도 자외선 차단제는 꼭 발라 주시는 게 중요해요.$AAA$, array['광노화', '잔주름예방', '기미', '피부암', '목선크림']::text[], 2023, 'voaT-43Y1Lc-3', 'https://youtu.be/voaT-43Y1Lc?t=242s', null, '2023-08-18 00:00:00+00'::timestamptz, '2023-08-18 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$왁싱과 레이저 제모는 어떻게 다른가요?$AAQ$, $AAA$왁싱은 끈적한 물질로 털을 한 번에 뽑아내는 방식이고, 레이저 제모는 모낭의 멜라닌 색소를 타깃으로 줄기세포를 파괴하는 반영구적 방식이라는 점에서 본질적으로 다릅니다.

왁싱은 한 번에 뽑아내기 때문에 **지금 당장 털이 없어져야 하는 상황**에서 좋지만, 뽑아낸다고 다시 안 나는 건 아니라 주기적으로 받아야 한다는 단점이 있어요. 레이저 제모는 멜라닌 색소를 인식한 **레이저 열이 주변까지 전달되어 털의 줄기세포까지 파괴할 수 있어 반영구 제모가 가능합니다.** 한 번 받는다고 전부 제거되지 않지만 횟수를 거듭할수록 모의 양이 점점 감소해 나중에 편하게 생활할 수 있어요. 통증은 마취 안 하고도 레이저가 3~4, 왁싱이 6~7 수준이라 보면 됩니다.$AAA$, array['왁싱', '레이저제모', '멜라닌', '반영구제모', '통증비교']::text[], 2023, 'xjToCn_0VTA-1', 'https://youtu.be/xjToCn_0VTA?t=134s', null, '2023-08-23 00:00:00+00'::timestamptz, '2023-08-23 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$레이저 제모 받기 전에 주의할 점이 있나요?$AAQ$, $AAA$레이저 제모 최소 하루 전에는 털을 절대 뽑지 말고 깎고 오셔야 합니다. 그것이 시술 전 가장 중요한 핵심이에요.

털을 뽑고 가면 **레이저 빔이 인식할 게 없기** 때문입니다. 멜라닌 색소를 타깃으로 빔이 작동하는 원리라 모낭에 털이 있어야 효과가 나타나요. 그래서 최소 시술 한 달 이내에는 **왁싱처럼 털을 뽑는 행위는 자제하시는 게 좋습니다.** 또 하나는 태닝처럼 피부를 태우는 행위도 안 좋으니 피해서 와 주세요. 왁싱 전 주의사항으로는 너무 깎고 가면 접착제가 붙을 게 없으니 어느 정도 길이는 있어야 합니다. 가시면 왁서분들이 길이에 맞게 잘라 주시는 경우가 많아요.$AAA$, array['레이저제모전', '주의사항', '태닝금지', '털뽑기금지', '시술전관리']::text[], 2023, 'xjToCn_0VTA-2', 'https://youtu.be/xjToCn_0VTA?t=200s', null, '2023-08-23 00:00:00+00'::timestamptz, '2023-08-23 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$레이저 제모 몇 번 받으면 영구적으로 안 나나요?$AAQ$, $AAA$레이저 제모를 5~10회 받으면 깨끗한 상태가 수 개월에서 1년 이상 유지되지만, 그 후 다시 자라나는 털도 있어 한 번에 영구는 아닙니다.

일정 시술 후 깨끗해지는 기간이 수 개월에서 1년 이상 가는데, **그 후 데미지를 받은 세포 중 다시 재생이 일어나는 것들이 있어요.** 그런 경우 다시 자라난 털에 대해 추가 레이저 제모를 시행받다 보면 **원리적으로는 영구 제모가 가능합니다.** 시술 주기는 털의 생장기간을 고려해 4~6주 사이가 좋고, 모의 양이나 피부색에 따라 추가가 더 필요한 경우도 많아요. 왁싱은 한 4주 정도 간격을 두고 꾸준히 받으면 됩니다. 영구라는 표현보다는 횟수를 거듭할수록 모의 양이 점점 줄어든다고 이해하시는 편이 정확합니다.$AAA$, array['영구제모', '제모횟수', '시술주기', '재생', '모량감소']::text[], 2023, 'xjToCn_0VTA-3', 'https://youtu.be/xjToCn_0VTA?t=303s', null, '2023-08-23 00:00:00+00'::timestamptz, '2023-08-23 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$레이저 제모 받은 후에 어떻게 관리해야 하나요?$AAQ$, $AAA$당일은 쿨링이 가장 중요하고, 일주일 내에는 사우나·수영장·성관계 등을 삼가해 주셔야 합니다. 레이저 자체에도 쿨링 시스템이 있고 시술 후에도 쿨링을 해 드리지만 집에서도 시원하게 유지해 주는 게 좋아요.

또 **꽉 끼는 속옷이나 옷은 삼가**해 주시고, 자극을 줄여 주시는 게 좋습니다. 부작용으로는 모낭염이 생길 수 있는데 대부분 후시딘이나 스테로이드 연고로 치료하거나 자연스럽게 좋아지지만, **화상·물집·지속적인 통증 같은 경우엔 주저 말고 병원에 방문**해야 합니다. 인그로운 헤어 예방을 위해서는 시술 후 일주일쯤 뒤 증상이 없으면 일주일에 2~3회 스크럽을 가볍게 하고, 각질층을 부드럽게 하기 위해 매일 보습제를 발라 주시는 게 중요해요.$AAA$, array['레이저제모후관리', '쿨링', '모낭염', '인그로운헤어', '보습제']::text[], 2023, 'xjToCn_0VTA-4', 'https://youtu.be/xjToCn_0VTA?t=505s', null, '2023-08-23 00:00:00+00'::timestamptz, '2023-08-23 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$레이저 제모 어떤 종류의 레이저가 좋은가요?$AAQ$, $AAA$레이저 빔의 조사 시간이 조금 긴 레이저, 열을 충분히 줄 수 있는 레이저를 사용해야 합니다. 크게 두 가지로 나누면 알렉산드라이트와 다이오드 계열이 있어요.

**알렉산드라이트 계열에 포함되는 게 젠틀맥스·아포지·클라리티·악센토** 같은 기기들로, 이 레이저들은 명품기계라고 해도 과언이 아닙니다. 좋은 레이저를 가지고 **시술자가 얼마나 효과적이게 치료하는지가 제일 중요하다고** 볼 수 있어요. 기기 자체의 종류 못지않게 적절한 출력과 조사 시간으로 모낭 깊이까지 열을 전달할 수 있게 운용하는 시술자의 숙련도가 결과를 좌우합니다. 그래서 기기 이름만 보고 결정하시기보다 시술자의 경험을 함께 고려해 주세요.$AAA$, array['알렉산드라이트', '다이오드', '젠틀맥스', '레이저종류', '시술자숙련']::text[], 2023, 'xjToCn_0VTA-5', 'https://youtu.be/xjToCn_0VTA?t=648s', null, '2023-08-23 00:00:00+00'::timestamptz, '2023-08-23 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$선크림 한 번 바르면 얼마나 유지되나요?$AAQ$, $AAA$건성 피부는 약 4~5시간 후에도 어느 정도 유지되지만, 지성 피부는 더 잘 지워지기 때문에 자주 덧발라 주셔야 합니다. 직접 진료시간 내내 발라 비교한 결과 시간이 지나며 지워졌지만 선크림 부분이 화장품보다 훨씬 지속력이 우수했어요.

건성 피부는 4~5시간 후에도 유지력이 꽤 있었지만 지성 피부는 잘 지워졌습니다. **야외 활동을 할 때는 2~3시간에 한 번씩** 덧발라 주시는 게 좋아요. 화장품에만 있는 선크림은 양이 충분하지 않으니 **선크림을 먼저 바르고 그 다음에 화장**을 해 주시는 것이 핵심이에요. 일반 화장품에만 의존하면 햇빛 차단이 전혀 안 된다는 것이 비교 결과로 확인되었습니다.$AAA$, array['선크림지속시간', '덧바르기', '건성지성', '도포순서', '야외활동']::text[], 2023, 'TXLzUVOGI6g-1', 'https://youtu.be/TXLzUVOGI6g?t=95s', null, '2023-08-29 00:00:00+00'::timestamptz, '2023-08-29 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$실내에서도 선크림 발라야 하나요?$AAQ$, $AAA$**자외선 A는 창을 통과해 피부에 깊숙이 침투**하므로 실내라도 자외선 차단제를 발라 주셔야 합니다. 자외선에는 A·B·C가 있는데 에너지가 높은 C는 하늘의 자연 차단막에서 거의 다 걸러지지만 A는 다르거든요.

자외선 B는 휴가 가서 한여름에 햇빛을 받았을 때 화상·검게 그을림 같은 즉각적 변화를 일으키고, 자외선 A는 **창을 통과해 피부 깊숙이 침투해 피부 노화·피부암·깊은 주름·잔주름까지 야기할 수 있어요.** 69세 버스 기사님 사진에서 창문 쪽 얼굴은 노화가 굉장히 많이 진행된 반면 반대쪽은 상대적으로 괜찮은 모습이 그 대표 사례입니다. 그래서 실내에서도 자외선 차단제를 잘 발라 주셔야 해요.$AAA$, array['자외선A', '실내선크림', 'UVA', '광노화', '창문자외선']::text[], 2023, 'TXLzUVOGI6g-2', 'https://youtu.be/TXLzUVOGI6g?t=121s', null, '2023-08-29 00:00:00+00'::timestamptz, '2023-08-29 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$SPF와 PA 수치는 어떻게 보고 골라야 하나요?$AAQ$, $AAA$**SPF는 UVB 차단 정도, PA는 UVA 차단 정도**를 의미하며 SPF 30 이상·PA는 +의 개수로 강도를 확인하시면 됩니다. UVB는 SPF, UVA는 PA로 각각 표시되어 있어요.

SPF 30 정도를 바르면 **97% 이상은 차단**해 주기 때문에 웬만하면 SPF 30 이상은 발라 주셔야 합니다. PA는 +의 개수로 표시되는데, +가 1개면 2~4배, ++는 4~8배, +++는 8~16배, ++++는 16배 이상 차단해 줍니다. 입술도 노화가 빨리 일어나는 부위 중 하나라 SPF가 있는 립밤을 수시로 발라 노화를 방지할 수 있어요. SPF와 PA 수치를 함께 보면서 본인의 야외 활동 강도에 맞춰 골라 주시면 됩니다.$AAA$, array['SPF', 'PA', 'UVA', 'UVB', '선크림선택']::text[], 2023, 'TXLzUVOGI6g-3', 'https://youtu.be/TXLzUVOGI6g?t=193s', null, '2023-08-29 00:00:00+00'::timestamptz, '2023-08-29 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$민감성 피부·지성 피부엔 어떤 선크림이 좋나요?$AAQ$, $AAA$민감한 피부는 무기자차, 지성·여드름 피부는 SPF가 낮은 오일프리 제품이 더 잘 맞습니다. 외우기 쉽게 무민(무기자차=민감피부)으로 기억하시면 돼요.

무기자차 성분은 **티타늄디옥사이드·징크옥사이드 같은 무기질 성분**이고, 민감한 피부에 자극이 덜합니다. 지성이나 여드름이 많이 나는 피부에서는 SPF 수치가 너무 높으면 피부에 남는 시간이 많아지므로 **평소엔 SPF가 조금 낮은 오일프리 제품**을 쓰는 게 좋아요. 무기자차는 하얗게 뜨고 발림성이 좋지 않으니 무기자차·유기자차가 섞인 제품을 쓰면 발림성도 좋고 자극도 낮습니다. 그리고 선크림은 일반 폼클렌징으로 잘 안 지워지므로 클렌징 크림·밀크로 1차 마사지 후 폼으로 2차 세안하는 이중 세안을 권해 드려요.$AAA$, array['무기자차', '유기자차', '민감성피부', '지성피부', '이중세안']::text[], 2023, 'TXLzUVOGI6g-4', 'https://youtu.be/TXLzUVOGI6g?t=313s', null, '2023-08-29 00:00:00+00'::timestamptz, '2023-08-29 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$형광등 불빛으로도 기미가 짙어질 수 있나요?$AAQ$, $AAA$형광등에서 자외선이 나오긴 하지만 양이 아주 적어 일상 생활 정도로는 피부에 미치는 영향이 미미합니다. 햇빛이 1,000~10,000 정도라면 실내 조명은 1 정도 수준이에요.

형광등의 유리 안쪽에는 형광물질이 발라져 있는데, 전기가 통하면 안에서 자외선이 만들어졌다가 **형광물질에 닿으며 가시광선으로 바뀌어 나오는 양이 적어요.** 다만 0%는 아니므로 전구가 가까이 있는 스탠드 밑에서 오랜 시간 작업·공부를 한다거나 조명이 강한 작업 환경이라면 자외선 차단을 해 주시는 게 좋습니다. **형광등이 신경 쓰이면 LED등으로 바꿔 주시면 자외선이 거의 나오지 않아요.** 일반 가정 형광등은 크게 걱정하지 않으셔도 됩니다.$AAA$, array['형광등', '실내자외선', '기미', 'LED등', '실내조명']::text[], 2023, 'OBJ6HDdfUE4-1', 'https://youtu.be/OBJ6HDdfUE4?t=84s', null, '2023-09-05 00:00:00+00'::timestamptz, '2023-09-05 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$블루라이트가 피부 노화를 일으키나요?$AAQ$, $AAA$블루라이트는 가시광선 중 에너지가 가장 강하고 자외선보다 깊게 피부에 침투해 피부 노화를 촉진할 수 있습니다. 우리 몸이 블루라이트에 가장 민감하게 반응한다고 알려져 있어요.

블루라이트는 가시광선 중 파란빛(청색광) 영역으로, **세포 속 DNA를 손상시키고 활성산소를 생성**하며 피부 속 콜라겐을 분해해 피부 노화를 촉진합니다. 또 잘 시간에 블루라이트를 눈에 많이 쬐면 **뇌가 밤이 아니라고 착각해 멜라토닌 분비가 줄어 피부 재생이 덜 되는 영향**도 있어요. 다만 낮에는 블루라이트를 어느 정도 봐야 생체리듬이 유지되니, 하루 종일 차단하기보다 밤에 적절히 줄여 주시는 게 좋습니다. 잘 사용하면 좋고 과도하면 안 좋은 양날의 검이에요.$AAA$, array['블루라이트', '청색광', '광노화', '활성산소', '멜라토닌']::text[], 2023, 'OBJ6HDdfUE4-2', 'https://youtu.be/OBJ6HDdfUE4?t=240s', null, '2023-09-05 00:00:00+00'::timestamptz, '2023-09-05 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$핸드폰 모니터 불빛으로 기미가 진짜 진해지나요?$AAQ$, $AAA$일상에서 쓰는 모니터·핸드폰 불빛 정도로 **기미가 짙어질 가능성은 아주 미미**합니다. 프랑스 피부과 교수님의 실험 결과로도 확인되었어요.

프랑스 피부과 교수님이 진행한 실험에서는 **피부에서 20cm 정도 거리를 두고 하루 8시간씩 5일 동안 쬐어 비교했을 때 기미가 진해지지 않았다고** 보고했습니다. 다만 잠 잘 때처럼 정말 가까이 두고 보는 경우 또는 이보다 많은 양을 오랜 기간 쬐는 경우의 영향은 아직 모릅니다. 블루라이트가 가장 많이 나오는 기기는 측정 결과 핸드폰이 가장 적고 노트북·모니터·TV 순으로 많아지고, **블루라이트가 가장 많이 나오는 건 사실 햇빛으로 핸드폰·TV의 100~1,000배에 달합니다.** 그래서 밖에 나갈 때 선크림 바르는 것이 가장 중요해요.$AAA$, array['핸드폰블루라이트', '기미악화', '모니터', '햇빛블루라이트', '거리']::text[], 2023, 'OBJ6HDdfUE4-3', 'https://youtu.be/OBJ6HDdfUE4?t=388s', null, '2023-09-05 00:00:00+00'::timestamptz, '2023-09-05 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$블루라이트 차단은 어떻게 해야 하나요?$AAQ$, $AAA$모니터용 블루라이트 차단 필름을 붙이거나 핸드폰의 블루라이트 차단 기능을 활용하시면 됩니다. 아예 차단하기보다는 시간대별로 조절하는 것이 좋아요.

모니터에는 **블루라이트를 차단하는 필름 형태** 제품이 있고, 핸드폰에도 블루라이트 차단 기능이 들어 있어요. 아이폰의 경우 설정→디스플레이 및 밝기→Night Shift에서 **시간을 지정해 언제부터 언제까지 블루라이트를 줄일지** 정할 수 있습니다. 다만 낮에는 블루라이트를 어느 정도 봐야 뇌가 낮이라 인식하고 깨어나기 때문에, 하루 종일 차단하면 생체리듬이 깨질 수 있어요. 그래서 밤 시간대 중심으로 차단을 활용하고, 외출 시 햇빛에 가장 많은 블루라이트가 있으므로 선크림을 바르는 게 가장 효과적입니다.$AAA$, array['블루라이트차단', 'NightShift', '차단필름', '생체리듬', '선크림']::text[], 2023, 'OBJ6HDdfUE4-4', 'https://youtu.be/OBJ6HDdfUE4?t=476s', null, '2023-09-05 00:00:00+00'::timestamptz, '2023-09-05 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$상처가 났을 때 흉터 안 남게 하려면 어떻게 해야 하나요?$AAQ$, $AAA$흉터를 덜 남기려면 상처를 빨리 낫게 해야 하며, 그러기 위해 **깨끗하게 하기와 습하게 하기** 두 가지를 지켜 주셔야 합니다. 흰 옷에 얼룩처럼 상처도 빨리 회복될수록 흉터가 덜 남아요.

첫 번째는 균이 들어가지 않게 깨끗이 하는 것인데, 일상 상처는 깊지 않으므로 과산화수소수 같은 강한 소독 성분은 오히려 **피부 속 정상 세포까지 파괴해 새 살이 돋는 것을 방해할 수 있어요.** 그래서 생리식염수로 씻거나 거즈에 적셔 닦거나, 없으면 흐르는 수돗물에 씻어 주세요. 두 번째는 습한 환경 유지인데, **상처를 말리면 빨리 낫는 것 같지만 사실은 흉터가 더 많이 남고** 진물에 들어 있는 재생 성분이 마르면서 함께 사라지기 때문이에요. 그래서 습윤 밴드로 습한 환경을 유지하는 것이 좋습니다.$AAA$, array['흉터예방', '상처관리', '습윤환경', '생리식염수', '과산화수소수']::text[], 2023, '2AgnQ2Z6HRU-1', 'https://youtu.be/2AgnQ2Z6HRU?t=110s', null, '2023-09-08 00:00:00+00'::timestamptz, '2023-09-08 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$습윤 밴드와 메디폼 어떤 걸 언제 써야 하나요?$AAQ$, $AAA$처음 진물이 많을 때는 메디폼 같은 스펀지형이, 진물이 적어지면 일반 습윤 밴드가 적합합니다. 흡수성에 따라 단계별로 바꿔 주시면 돼요.

다쳐서 **진물이 많이 나는 시기**에는 스펀지 형태의 메디폼이 진물을 잘 흡수해 줍니다. 보통 하루에 한 번 갈아 주는데, **진물이 흘러넘치면 그 전에라도 한 번 더 갈아** 주셔야 하고요. 습윤 밴드는 흡수성이 떨어져 진물이 하얗게 새면 갈아 주시고, 상처가 많이 나아 하얗게 불어 있는 게 없으면 이틀에 한 번 갈아도 됩니다. 너무 자주 갈면 재생이 될 만하면 뜯어내는 격이 되므로 좋지 않아요. 또 너무 오래 붙이면 접착성분으로 알러지가 생길 수 있으니, 하루 동안 진물이 안 나면 그때부터는 떼셔도 됩니다.$AAA$, array['습윤밴드', '메디폼', '교체주기', '진물', '흡수성']::text[], 2023, '2AgnQ2Z6HRU-2', 'https://youtu.be/2AgnQ2Z6HRU?t=305s', null, '2023-09-08 00:00:00+00'::timestamptz, '2023-09-08 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$상처에 어떤 연고를 발라야 하나요?$AAQ$, $AAA$초기에는 항생제 연고나 마데카솔을 바르고, 습윤 밴드를 떼고 난 다음에는 흉터 연고를 발라 주시면 됩니다. 단계에 따라 발라야 할 연고가 달라요.

초기에는 **후시딘·에스로반·박테로신 같은 항생제 연고**를 발라 주시고, 항생제 연고가 없으면 집에 있는 마데카솔을 발라 주셔도 됩니다. 습윤 밴드를 떼고 난 다음부터는 콘트라투벡스·스카겔 같은 흉터 연고를 바르는데, 이 연고들은 살이 재생될 때 튀어나오는 흉터를 예방해 줍니다. 원칙적으로 **24시간 계속 흉터를 덮고 있는 게 좋아 보통 아침·저녁 한 번씩** 바르고, 점심에 보고 약이 다 지워졌으면 덧발라도 돼요. 빨간 부위가 가라앉으면서 까매지는 색소침착엔 미백 기능성 화장품과 외출 시 선크림을 챙겨 주세요.$AAA$, array['항생제연고', '마데카솔', '흉터연고', '콘트라투벡스', '미백크림']::text[], 2023, '2AgnQ2Z6HRU-3', 'https://youtu.be/2AgnQ2Z6HRU?t=200s', null, '2023-09-08 00:00:00+00'::timestamptz, '2023-09-08 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$상처 관리하다 병원에 가야 하는 신호는 뭔가요?$AAQ$, $AAA$**노란 딱지·이상한 냄새·튀어오르는 빨간 융기**가 보이면 병원에 가셔야 합니다. 이런 사인은 흉터가 심해지거나 감염이 진행 중일 가능성을 의미해요.

첫째는 상처에 **노란 딱지가 생기는 것**, 둘째는 상처 냄새가 이상해지는 것, 셋째는 상처가 많이 빨가면서 위로 튀어 오르는 것입니다. 특히 팔꿈치·무릎처럼 자꾸 움직이는 부위는 피부가 당겨지면서 **튀어 오르는 흉터가 더 잘 생기므로** 주의가 필요해요. 괜찮겠지 하고 내버려 두다가 오히려 염증이나 흉터가 심해져서 오시는 분이 많습니다. 이런 신호가 보이면 자가 관리에서 멈추고 병원을 방문해 적절한 처치를 받으시는 것이 결과를 좋게 만드는 길이에요.$AAA$, array['노란딱지', '감염사인', '비후성흉터', '팔꿈치무릎', '병원방문']::text[], 2023, '2AgnQ2Z6HRU-4', 'https://youtu.be/2AgnQ2Z6HRU?t=486s', null, '2023-09-08 00:00:00+00'::timestamptz, '2023-09-08 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$글루타치온이 진짜 피부에 효과가 있나요?$AAQ$, $AAA$글루타치온은 효과가 입증된 천연 항산화제로 보충 시 피부 미백·해독·면역 조절 등에 효과가 있습니다. 효과를 입증한 논문이 정말 많이 있다고 알려져 있어요.

글루타치온은 우리 몸 속에 있는 천연 항산화제로, **활성산소가 신체를 손상시키는 것을 막아 주는 히어로 같은 역할**을 합니다. 활성산소는 전자가 하나 빠져 불안정한 상태로 다른 곳에서 전자를 뺏는 반응을 연쇄적으로 일으키는데, 글루타치온이 자기 전자를 내줘 안정적인 상태로 만들어 줘요. 구체적으로는 **나쁜 화학물질·약물·중금속 같은 것을 해독, 면역세포 도움·염증 조절, DNA·단백질 손상 차단** 역할을 합니다. 다만 글루타치온 종류·용량·기간이나 개인 체질에 따라 반응이 다양할 수 있어요.$AAA$, array['글루타치온', '항산화제', '활성산소', '해독', '면역조절']::text[], 2023, '73luF_ymkKc-1', 'https://youtu.be/73luF_ymkKc?t=43s', null, '2023-09-14 00:00:00+00'::timestamptz, '2023-09-14 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$글루타치온은 어떻게 피부를 하얗게 만드나요?$AAQ$, $AAA$글루타치온은 두 가지 기전으로 멜라닌을 적게 만들어 피부를 밝게 합니다. **티로시나아제 차단과 페오멜라닌 유도**가 그것이에요.

첫 번째 기전은 멜라닌 합성에 관여하는 티로시나아제라는 효소를 차단하는 것입니다. 글루타치온이 티로시나아제를 차단해 **멜라닌이 아예 안 만들어지게 하기 때문에** 피부가 밝아지고 톤이 균일해져요. 두 번째 기전은 멜라닌 종류 조절입니다. 멜라닌에는 갈색·검정색을 띠는 유멜라닌과 붉은색·노란색의 페오멜라닌이 있는데, **글루타치온은 유멜라닌보다 페오멜라닌이 더 많이 생성되게 만들어** 피부를 덜 까매지게 합니다. 단, 나이가 들면서 몸 안의 글루타치온 생성 능력이 떨어지고 스트레스·식단으로 필요량이 늘기 때문에 보충제가 다양하게 출시되어 있어요.$AAA$, array['미백기전', '티로시나아제', '유멜라닌', '페오멜라닌', '피부톤']::text[], 2023, '73luF_ymkKc-2', 'https://youtu.be/73luF_ymkKc?t=221s', null, '2023-09-14 00:00:00+00'::timestamptz, '2023-09-14 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$환원형 아세틸 리포조말 글루타치온 뭐가 다른가요?$AAQ$, $AAA$환원형은 가장 저렴하지만 흡수 전 산화되기 쉽고, **아세틸은 흡수율이 가장 좋지만 비싸고, 리포조말은 적절한 가성비**를 가집니다. 흡수율과 가격이 단계별로 달라요.

환원형 글루타치온은 우리가 이용하기 전에 이미 **산화되어 버리는 양이 많아 실제로 이용할 수 있는 양이 적다**는 단점이 있어요. 아세틸 글루타치온은 아세틸기를 붙여 분해 대상으로 인식되지 않게 만들어 흡수가 늘어나고, 리포조말 글루타치온은 글루타치온을 리포좀(기름막)으로 싸서 위장에서 그대로 흡수되도록 만든 형태입니다. 가격은 환원형이 가장 저렴, 리포조말이 그 다음, 아세틸이 제일 비싸요. **나는 비싸도 좋은 걸 원하면 아세틸, 저렴한 걸 원하면 환원형, 가성비를 원하면 리포조말**을 선택하시면 됩니다.$AAA$, array['환원형글루타치온', '아세틸글루타치온', '리포조말', '흡수율', '가성비']::text[], 2023, '73luF_ymkKc-3', 'https://youtu.be/73luF_ymkKc?t=479s', null, '2023-09-14 00:00:00+00'::timestamptz, '2023-09-14 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$필름형 글루타치온은 먹는 것과 어떻게 다른가요?$AAQ$, $AAA$필름형은 입 점막에서 바로 흡수되어 위장에서 분해되는 과정을 거치지 않는다는 점이 먹는 형태와의 본질적 차이입니다. 입 위쪽이나 혀 밑에 붙이는 얇은 필름 형태예요.

먹는 형태는 위장에서 분해되어 아미노산으로 쪼개진 후 흡수되는데, 필름형은 **점막에 붙이면 그런 과정을 거치지 않고 바로 우리 몸으로 흡수**됩니다. 다만 필름 **한 장당 보통 50mg 내외 용량**이고, 글루타치온 저하 시 권장량이 하루 300~500mg, 많게는 1,000mg이라 용량은 적은 편이에요. 그래도 경구용보다 흡수도가 훨씬 높아 단순 용량 비교는 어렵습니다. 빠른 흡수와 적은 부담을 원하는 분께 적합한 제형이라 보시면 돼요.$AAA$, array['필름형글루타치온', '점막흡수', '설하필름', '용량비교', '흡수경로']::text[], 2023, '73luF_ymkKc-4', 'https://youtu.be/73luF_ymkKc?t=625s', null, '2023-09-14 00:00:00+00'::timestamptz, '2023-09-14 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$백옥주사 글루타치온 주사는 어떻게 맞나요?$AAQ$, $AAA$글루타치온 주사는 정맥으로 바로 들어가 효과가 가장 확실하며, **표준 용량은 600~1,200mg, 주기는 일주일에 1~2회**가 권장됩니다. 환원형 글루타치온을 용제에 타서 맞아요.

주사는 정맥으로 직접 들어가기 때문에 흡수 과정이 없어 가장 확실한 효과를 보입니다. 한 병 안에 **하얀 가루 형태로 600~1,200mg**이 들어 있고, 생리식염수나 포도당에 타서 정맥주사로 맞아요. 시간이 부족하면 적은 용량을 타서 엉덩이에 근육주사로도 맞을 수 있습니다. 표준 용량은 600~1,200mg이고 **주기는 일주일에 한 번에서 두 번 정도가 권장**됩니다. 백옥주사·아이유주사로 알려진 이 주사를 실제 맞으면 피부가 밝아지는지, 몇 번 정도부터 효과가 보이는지는 일주일에 한 번씩 3개월간 총 12번을 직접 체험해 다음 편에서 공유할 예정이에요.$AAA$, array['백옥주사', '글루타치온주사', '정맥주사', '용량주기', '근육주사']::text[], 2023, '73luF_ymkKc-5', 'https://youtu.be/73luF_ymkKc?t=688s', null, '2023-09-14 00:00:00+00'::timestamptz, '2023-09-14 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$레티날과 레티놀은 어떻게 다른가요?$AAQ$, $AAA$레티날은 레티노산 바로 전 단계에 있는 비타민 A 유도체로, 레티놀보다 효과가 한 단계 더 좋다고 볼 수 있습니다. 레티노이드 계열은 레티닐에스터부터 레티놀, 레티날, 레티노산으로 갈수록 효과가 좋아지지만 자극도 함께 올라가는데, 레티노산은 가장 효과가 좋지만 자극이 많아 병원 처방약으로만 사용되고 화장품에는 나머지 세 성분이 주로 쓰입니다.

레티놀의 경우 **레티노산으로 바뀌려면 레티날 단계를 거쳐야 해서** 그만큼 효과가 떨어질 수 있는 구조입니다. 반면 레티날은 알데하이드 형태로 빛·열·산소에 불안정해 원래는 화장품화가 어려웠지만, 최근 안정화 기술이 발전하며 사용이 가능해졌어요. 40~60대 여성을 대상으로 0.05%와 0.1% 크림을 각 4주씩 비교한 연구에서는 주름·탄력·보습 모두 레티날이 더 우수했다는 결과가 있었습니다.$AAA$, array['레티날', '레티놀', '레티노이드', '주름개선', '성분비교']::text[], 2023, 'FOx9z7TFv9Y-1', 'https://youtu.be/FOx9z7TFv9Y?t=308s', null, '2023-09-20 00:00:00+00'::timestamptz, '2023-09-20 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$레티놀은 어떤 효과가 있나요?$AAQ$, $AAA$레티놀은 피부에 흡수된 후 레티노산으로 전환되며 턴오버 촉진, 콜라겐 합성, 모공 개선의 세 가지 효과를 만들어냅니다. 레티노이드 성분들 중에서도 안정화가 잘 되어 있고 효과가 좋아 대중적으로 가장 많이 쓰이는 주름 개선·항노화 성분입니다.

첫째로 묵은 각질세포가 건강한 세포로 교체되는 **턴오버 주기를 빠르게 만들어 피부결을 매끈하게** 정돈해 줍니다. 둘째로 콜라겐 합성을 유도해 주름 개선 효과를 볼 수 있고, 셋째로 과각화로 인해 모공이 막혀 생기는 여드름을 개선하는 효과도 있습니다. 다만 레티놀이 레티노산으로 바뀌려면 레티날 단계를 한 번 더 거쳐야 하기 때문에, 같은 농도에서는 레티날에 비해 효과가 다소 떨어질 수 있는 구조입니다.$AAA$, array['레티놀', '콜라겐합성', '턴오버', '주름개선', '여드름']::text[], 2023, 'FOx9z7TFv9Y-2', 'https://youtu.be/FOx9z7TFv9Y?t=348s', null, '2023-09-20 00:00:00+00'::timestamptz, '2023-09-20 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$민감성 피부도 레티놀을 사용할 수 있나요?$AAQ$, $AAA$민감성 피부도 사용 가능하지만, 피부가 안정된 상태에서 샌드위치 방법으로 발라야 합니다. 피부가 너무 민감해서 뒤집어진 상태라면 레티놀이나 레티날 사용을 완전히 중단하고, 어느 정도 안정화된 뒤에 다시 시작하는 것이 안전합니다.

샌드위치 방법은 앰플과 로션, 크림을 먼저 바르고 그 위에 **레티놀을 얇게 펴 바른 뒤 마지막에 크림을 한 번 더** 덧바르는 방식입니다. 보습제로 레이어링을 해 주면 피부 자극은 줄고 보습 효과는 올라가서 민감한 분들에게 안전하게 활용됩니다. 함께 쓰면 좋은 보습제로는 세라마이드·콜레스테롤·지방산으로 구성된 세콜지 제품과, 센텔라아시아티카·이지에프·판테놀 같은 재생크림 성분이 있습니다.$AAA$, array['레티놀', '민감성피부', '샌드위치방법', '세콜지', '재생크림']::text[], 2023, 'FOx9z7TFv9Y-3', 'https://youtu.be/FOx9z7TFv9Y?t=553s', null, '2023-09-20 00:00:00+00'::timestamptz, '2023-09-20 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$레티놀과 함께 쓰면 안 되는 성분이 있나요?$AAQ$, $AAA$레티놀과 함께 쓰면 자극이 커지는 대표 성분은 순수 비타민 C와 다른 레티노이드 계열 제품입니다. 또한 필링이나 스크럽처럼 각질을 벗겨내는 행위도 함께 피하는 것이 좋습니다.

순수 비타민 C는 그 자체로 자극이 있어 레티놀과 동시에 바르면 **자극이 배가 될 수 있습니다.** 민감성 피부나 입문자는 격일로 따로 쓰거나 아침엔 비타민 C, 저녁엔 레티놀처럼 시간 간격을 두고 사용하는 게 안전해요. 또한 스티바A·디페린·아크리프 같은 같은 계열 레티노이드는 함께 바르면 자극을 유발할 수 있어 굳이 같이 쓰지 않는 편이 좋고, 꼭 병행하고 싶다면 **주름 부위에는 레티놀·레티날, 여드름 부위에는 디페린·아크리프**처럼 부위를 나누어 도포하면 됩니다.$AAA$, array['레티놀', '비타민C', '주의사항', '각질제거', '병용금기']::text[], 2023, 'FOx9z7TFv9Y-4', 'https://youtu.be/FOx9z7TFv9Y?t=676s', null, '2023-09-20 00:00:00+00'::timestamptz, '2023-09-20 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$생리식염수팩이 피부에 효과가 있나요?$AAQ$, $AAA$생리식염수팩은 피부 상태에 따라 효과가 달라지는 팩으로, 건강한 피부에는 큰 효과가 없습니다. 생리식염수는 물에 염화나트륨을 특정 농도로 희석한 소금물이며, 피부와 삼투압이 같은 등장성이라 멀쩡한 피부에 올려두면 별다른 변화가 일어나지 않기 때문입니다.

다만 진물이 나거나 염증이 있는 피부에는 도움이 될 수 있습니다. 피부과에서 거즈에 적셔 **10분에서 15분 올려두는 'Wet dressing' 기법으로 활용되며,** 상처 부위를 습윤한 상태로 유지해 회복을 돕고 진물을 빨아들이는 역할을 합니다. 그래서 아토피 피부염이나 지루성 피부염처럼 염증·진물이 있는 분들에게는 유용할 수 있지만, **수분을 피부에 그대로 먹여 주는 역할은 하지 않습니다.**$AAA$, array['생리식염수팩', '삼투압', 'wet dressing', '염증피부', '팩효과']::text[], 2023, '1l57HsTCDZ8-1', 'https://youtu.be/1l57HsTCDZ8?t=83s', null, '2023-09-22 00:00:00+00'::timestamptz, '2023-09-22 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$생리식염수팩은 누구에게 좋고 누구는 피해야 하나요?$AAQ$, $AAA$생리식염수팩은 염증이나 진물이 있는 피부에는 도움이 될 수 있지만, 피부가 얇고 건조한 분들에게는 권하지 않습니다. 아토피 피부염이나 지루성 피부염처럼 피부 자체에 염증·진물이 있을 때는 진물을 빨아들이고 피부를 진정시키는 효과를 기대할 수 있습니다.

반면 피부에 수분을 채워야 하는 건조한 분들에게는 큰 도움이 되지 않습니다. 축축한 것을 적시니 보습이 될 거라 생각하기 쉽지만, 실제로는 **떼어낸 뒤 마르면서 오히려 수분만 뺏어가는 경우가 흔합니다.** 이런 분들은 차라리 보습에 좋은 에센스가 많이 들어 있는 마스크팩을 쓰는 편이 훨씬 효과적입니다. **유행한다고 모두에게 맞는 건 아니라서** 작은 용량을 먼저 사서 피부에 맞는지 확인한 뒤 본격적으로 사용하는 것이 안전합니다.$AAA$, array['생리식염수팩', '건성피부', '적응증', '마스크팩', '피부타입']::text[], 2023, '1l57HsTCDZ8-2', 'https://youtu.be/1l57HsTCDZ8?t=327s', null, '2023-09-22 00:00:00+00'::timestamptz, '2023-09-22 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$생리식염수팩을 안전하게 하는 방법은 무엇인가요?$AAQ$, $AAA$생리식염수팩 후에는 반드시 물로 세안해 소금을 닦아내고 기초 제품을 발라야 합니다. 팩을 떼고 나면 얼굴에 소금물이 잔뜩 묻어 있는 상태가 되는데, 이대로 자면 피부에 좋을 게 없기 때문입니다.

또한 멸균 상태 유지가 중요합니다. **한번 뚜껑을 열면 보통 일주일 이내로 사용하는 것이 좋고,** 미리 냉장고에 만들어 둔 팩도 빨리 써야 합니다. 너무 오래되면 균이 증식해 트러블의 원인이 될 수 있어요. 약국에 있는 렌즈 세척액은 방부제·살균제·단백질 제거제가 들어 있어 생리식염수와 혼동해 팩에 쓰지 않도록 주의해야 합니다. **작은 용량으로 먼저 피부에 맞는지 확인한 뒤 큰 용량을 구매하는 것이** 안전한 방법입니다.$AAA$, array['생리식염수팩', '사용법', '멸균보관', '렌즈세척액', '주의사항']::text[], 2023, '1l57HsTCDZ8-3', 'https://youtu.be/1l57HsTCDZ8?t=251s', null, '2023-09-22 00:00:00+00'::timestamptz, '2023-09-22 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$지성피부의 스킨케어 루틴은 어떻게 해야 하나요?$AAQ$, $AAA$지성피부의 스킨케어는 닦토·레티날크림·산뜻한 수분크림·자외선차단제의 단순한 구성으로 유지하는 것이 좋습니다. 스킨케어만으로 모공이 좁아지거나 피지 분비량이 크게 줄지는 않지만, 관리하지 않으면 다른 피부보다 모공이 쉽게 넓어지고 여드름이 잘 생기기 때문에 악화 방지를 위해 꾸준한 케어가 필요합니다.

저녁에는 약산성 성분과 BHA가 든 닦는 토너로 피부결을 정돈하고, 그 위에 **여드름 전용 레티날 크림을 발라** 잔주름 개선과 각질·피지 제거 효과를 함께 봅니다. 이어 젤 타입처럼 가벼운 수분크림을 바르고, **세라마이드·콜레스테롤·지방산이 든 수분크림은 인중·턱처럼 건조한 부위에만** 덧발라 유수분 밸런스를 맞춥니다. 수분 부족형 지성(수부지)도 같은 루틴을 응용할 수 있습니다.$AAA$, array['지성피부', '스킨케어루틴', '닦토', '레티날크림', '유수분밸런스']::text[], 2023, 'N-TSezzqJgY-1', 'https://youtu.be/N-TSezzqJgY?t=224s', null, '2023-09-27 00:00:00+00'::timestamptz, '2023-09-27 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$지성피부의 세안법은 어떻게 해야 하나요?$AAQ$, $AAA$지성피부 세안은 클렌징 밀크로 1차 세안 후 여드름용 포밍 클렌저로 2차 세안하는 이중세안이 가장 적당합니다. 클렌징 오일은 너무 오일리하고 클렌징 워터는 너무 가벼워서, **피지까지 깨끗하게 세정하기에는 클렌징 밀크가 제일 적합합니다.**

2차 세안 시 거품이 자체 생성되는 포밍 클렌저를 쓰면 따로 거품을 만들지 않아도 돼서 편리합니다. 물 온도도 중요한데, **미지근한 물로 모공을 열어 청소를 한 뒤 마지막에는 시원한 물로 모공을 닫아 주는** 방식이 좋습니다. 뜨거운 물은 피지 분비량을 오히려 더 늘릴 수 있으니 피해야 합니다. 아침에는 자는 동안 쌓인 피지가 있어 그냥 물 세안만으로는 부족하고, 폼클렌저로 1차 세안을 해 피지와 노폐물을 씻어내는 것이 필요합니다.$AAA$, array['지성피부', '세안법', '클렌징밀크', '이중세안', '물온도']::text[], 2023, 'N-TSezzqJgY-2', 'https://youtu.be/N-TSezzqJgY?t=464s', null, '2023-09-27 00:00:00+00'::timestamptz, '2023-09-27 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$지성피부도 화장이 잘 먹게 하려면 어떻게 해야 하나요?$AAQ$, $AAA$지성피부는 산뜻한 수분크림 하나만 바르고 오일프리 자외선차단제, 매트 파우더로 마무리하는 것이 좋습니다. 이것저것 많이 바르면 화장이 밀리고 잘 안 먹기 때문에, 아침에는 닦토와 레티날 크림을 생략하고 꼭 필요한 보습만 채우는 게 핵심입니다.

자외선차단제는 오일프리 제품을 고르고 **SPF 30 이상을 평소에 바르는 것을 추천하며,** 가시광선까지 막아 잡티를 줄여 주는 틴티드 선크림도 좋은 선택입니다. 모공 프라이머는 정말 중요한 날에만 쓰고, 파운데이션은 얇게 여러 겹 바르는 편이 자연스러워요. 마지막에 **번들거림을 잡아주는 매트 파우더로 마무리하면 모공과 요철이 덜 보이며,** 너무 번들거릴 땐 2~3시간 간격으로 파우더가 묻은 종이 타입 기름종이를 사용하는 것이 좋습니다.$AAA$, array['지성피부', '메이크업', '오일프리선크림', '파우더', '기름종이']::text[], 2023, 'N-TSezzqJgY-3', 'https://youtu.be/N-TSezzqJgY?t=578s', null, '2023-09-27 00:00:00+00'::timestamptz, '2023-09-27 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$지성피부와 여드름은 스킨케어만으로 해결되나요?$AAQ$, $AAA$지성피부의 여드름·트러블은 홈케어로 어느 정도 막을 수 있지만, 피지 분비량 자체를 조절하려면 경구약 복용이 필요합니다. 홈케어는 모공 노폐물 정돈과 염증 완화에는 도움이 되지만, 뿜어져 나오는 피지 자체를 줄이기는 어렵기 때문입니다.

그래서 피지 분비가 심하다면 의사 상담을 받아보는 것이 좋습니다. 또한 지성피부와 여드름 피부는 **먹는 음식, 스트레스, 환경의 영향을 굉장히 많이 받기 때문에** 생활 관리도 병행해야 합니다. 보조적으로는 여름이나 잠을 잘 못 잔 날, 스트레스가 심한 날 등 피지가 많이 나올 때 **주 1회나 2회 정도 필링 젤로 묵은 각질과 피지 노폐물을 정리하는** 방법도 활용할 수 있으며, 이때는 닦토와 레티날 크림을 생략하고 수분·재생 크림 위주로 진정시키는 것이 안전합니다.$AAA$, array['지성피부', '여드름', '경구약', '필링젤', '생활관리']::text[], 2023, 'N-TSezzqJgY-4', 'https://youtu.be/N-TSezzqJgY?t=534s', null, '2023-09-27 00:00:00+00'::timestamptz, '2023-09-27 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$점은 다른 색소와 어떻게 다른가요?$AAQ$, $AAA$점은 점 세포 덩어리가 뭉쳐 둥지를 만든 것이라 둥지 자체를 파괴해야 제거되는, 기미·주근깨와 본질적으로 다른 색소입니다. 기미나 다른 색소는 자외선과 노화로 색소가 진해진 것이라 흉터가 생기게 세게 부수는 방식이 아니라 레이저 토닝처럼 색소를 흐리게 만드는 식으로 치료합니다.

반면 점은 완전히 부수지 않으면 안에 멜라닌 세포가 그대로 남아 **재발하거나 그대로 남는 경우가 생기는** 구조입니다. 그래서 점은 결국 흉터가 생기더라도 완전히 파괴하는 식으로 치료하는 경우가 많아요. 진단도 중요한데, 점이 맞는지 사마귀·비립종·피부암인지를 먼저 구분해야 적절한 치료가 가능합니다. 어린아이의 김처럼 묻어 있는 판판한 점은 시간이 지나며 **두꺼워지거나 밑으로 깊어지거나 튀어나올 수 있어** 미리 제거하는 것도 좋은 선택일 수 있습니다.$AAA$, array['점', '기미', '색소차이', '점세포', '진단']::text[], 2023, '7QQKAkvY0IA-1', 'https://youtu.be/7QQKAkvY0IA?t=85s', null, '2023-10-05 00:00:00+00'::timestamptz, '2023-10-05 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$팔자주름이나 입가 점은 빼도 되나요?$AAQ$, $AAA$팔자주름·인중·턱 주변 점은 움직임이 많아 일반적인 점 제거를 하면 흉터가 튀어나올 위험이 큰 부위입니다. 밥을 먹고 말을 많이 하는 위치이기 때문에, 열로 구멍을 내듯 파내면 흉터 조직에 신호가 과하게 가서 튀어나오는 비후성 흉터가 흔하게 생깁니다.

그래서 이런 부위는 일반적인 제거보다 **피코레이저로 색깔을 살짝 흐리게만 만드는 방식**을 권합니다. 피코레이저는 굉장히 짧은 시간 동안만 열을 주기 때문에 점이 완전히 없어지지는 않지만 회색이나 옅은 갈색으로 변해 흉터 없이 충분히 흐려집니다. 화장으로 가려지고 주변 잡티와 비슷한 수준이 되도록만 정리하고, 시간이 지나 남은 색이 거슬리면 **몇 달 뒤 다시 시술하는 방식이** 안전합니다.$AAA$, array['점제거', '팔자주름', '흉터예방', '피코레이저', '비후성흉터']::text[], 2023, '7QQKAkvY0IA-2', 'https://youtu.be/7QQKAkvY0IA?t=163s', null, '2023-10-05 00:00:00+00'::timestamptz, '2023-10-05 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$점 제거 후 듀오덤은 언제까지 붙여야 하나요?$AAQ$, $AAA$점 제거 후 듀오덤은 진물이 안 나올 때까지 붙이는 것이 기준이며, 보통 1~2주 정도 걸립니다. 진물이 차서 볼록해지면 지저분해 보이지만, 사실 피부 재생을 도와주는 좋은 진물이라 피부가 잘 재생되고 있다는 신호로 보면 됩니다.

그래서 듀오덤을 붙인 상태에서 볼록하게 진물이 나오면 **재생이 잘 되고 있다고 생각하시면 되고,** 진물이 멈출 때까지 붙이는 것이 좋은 기준이 됩니다. 다만 **6개월씩 너무 오래 붙이면 접촉 피부염이 생기고 없던 병도 생길 수 있어** 오래 붙인다고 더 좋아지는 건 아닙니다. 떼고 난 뒤에는 재생크림과 수분크림을 잘 바르고, 자외선차단제도 꼼꼼히 사용해야 합니다. 회복 중인 피부에 자외선이 닿으면 색소침착이 더 잘 생기기 때문에 자극을 줄이고 차단제를 챙기는 것이 색소 예방에 중요합니다.$AAA$, array['점제거', '듀오덤', '진물', '재생관리', '자외선차단']::text[], 2023, '7QQKAkvY0IA-3', 'https://youtu.be/7QQKAkvY0IA?t=311s', null, '2023-10-05 00:00:00+00'::timestamptz, '2023-10-05 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$점은 빼도 또 자라나는 경우가 있나요?$AAQ$, $AAA$점 제거 후 재발은 흔한 편이며, 점 세포 모두가 눈에 보이지 않기 때문에 발생합니다. 작게 다시 자라거나, 흉터와 점이 섞여 나오거나, 가장자리부터 동그랗게 점 색이 다시 자라나는 형태로 나타날 수 있습니다.

아무리 제거해도 **눈에 보이지 않는 점 세포가 남아 재발하는 일은 너무 흔하기 때문에,** 최근에는 점을 완전히 없애려 하기보다 **흐리게 만들어 안 보이는 정도로 정리하는 치료가** 더 권장됩니다. 점 제거는 깨끗하게 빼면 흉터가 생기고 약하게 하면 재발 불만이 생기는 양면성이 있어, 피부과 전문의 입장에서도 은근히 까다로운 시술입니다. 그래서 의료진은 환자의 점 위치·크기·살성을 보고 흉터 위험과 미용 효과 사이에서 균형 잡힌 접근을 권하게 됩니다.$AAA$, array['점제거', '재발', '잔존세포', '흐리게치료', '흉터위험']::text[], 2023, '7QQKAkvY0IA-4', 'https://youtu.be/7QQKAkvY0IA?t=415s', null, '2023-10-05 00:00:00+00'::timestamptz, '2023-10-05 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$피부가 예민해졌을 때는 어떻게 관리해야 하나요?$AAQ$, $AAA$피부가 예민해졌을 때는 뭘 더 바르기보다 뭘 안 하는 게 우선입니다. 매일 쓰던 제품도 따갑게 느껴지고 피부가 뒤집어지는 분들은 보통 피부 장벽이 약해진 상태인데, 이때는 기존 제품 중 자극이 될 만한 것을 빼는 것이 회복에 더 효과적이기 때문입니다.

진료실에서는 기초·클렌저를 차트에 하나하나 적어 보고 장벽이 안 좋은 분들에게 안 좋을 수 있는 것을 모두 빼는 방식으로 정리합니다. 만약 쓰는 제품이 너무 많아 어떤 게 자극을 주는지 모를 때는 **아무것도 쓰지 마시고 딱 두 개만 처방**하기도 합니다. 그 두 가지는 **약산성 클렌저와 피부에 좋은 보습제이며,** 다른 제품을 끊고 이 둘만 제대로 지키면 피부가 진짜 많이 좋아진다고 설명합니다. 필요할 때는 약 처방을 함께 병행하기도 합니다.$AAA$, array['예민피부', '피부장벽', '약산성클렌저', '보습제', '기초제품정리']::text[], 2023, 'YuOTZRiB2ds-1', 'https://youtu.be/YuOTZRiB2ds?t=28s', null, '2023-10-16 00:00:00+00'::timestamptz, '2023-10-16 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$토너는 정말 피부에 수분을 공급해주나요?$AAQ$, $AAA$토너는 피부에 수분을 직접 공급하는 제품이 아닙니다. 토너의 95% 이상이 정제수로 구성되어 있어 발라도 피부 속에 수분이 머무르는 게 아니라 증발하면서 피부 속 물까지 함께 뺏어갈 수 있기 때문입니다.

토너의 진짜 기능은 두 가지입니다. 첫째는 노폐물과 각질 제거 기능으로, **화장솜에 적셔 피부결을 따라 닦으면 3차 클렌징 역할을** 합니다. 둘째는 피부의 약산성화 기능인데, 예전 비누가 알칼리성이라 씻고 나면 피부가 중성·약알칼리성으로 변하기 때문에 토너로 다시 약산성을 맞춰 주려는 목적이었습니다. 따라서 **요즘처럼 약산성 클렌저로 세안한다면 굳이 약산성 토너를 다시 바를 필요는 없습니다.** 두꺼운 메이크업 후 닦토를 잔여물 제거 목적으로 가끔 활용하는 것은 도움이 될 수 있습니다.$AAA$, array['토너', '정제수', '약산성', '닦토', '3차클렌징']::text[], 2023, 'YuOTZRiB2ds-2', 'https://youtu.be/YuOTZRiB2ds?t=98s', null, '2023-10-16 00:00:00+00'::timestamptz, '2023-10-16 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$닦토는 모든 피부 타입에 좋은가요?$AAQ$, $AAA$닦토는 건성·민감성 피부에는 권하지 않으며 안 하는 게 좋습니다. 화장솜은 실로 엮인 결이 있어 토너를 묻혀 닦는 행동 자체가 피부를 문지르는 자극이 되기 때문입니다. 어쩌다 한 번은 괜찮지만, 매일 하루 두 번씩 얼굴 전체를 꼼꼼히 닦으면 부담이 됩니다.

반면 **지성이라 유분이 많고 닦아낼 게 많은 피부**에는 닦토가 도움이 될 수 있어요. 가장 중요한 이유는 **닦아내는 토너가 피부 장벽을 무너뜨릴 수 있다는 점**입니다. 피부 장벽이 깨져 있는 질환이 피부병의 대부분이며, 아토피 피부염은 선천적으로 장벽이 약하고, 안면홍조·주사 피부염은 혈관 염증과 함께 장벽이 깨져 따가움을 호소하며, 기미 환자도 장벽이 튼튼하지 않은 경우가 많아 장벽을 튼튼히 하면 안색이 같이 맑아질 수 있습니다.$AAA$, array['닦토', '건성피부', '민감성', '피부장벽', '화장솜자극']::text[], 2023, 'YuOTZRiB2ds-3', 'https://youtu.be/YuOTZRiB2ds?t=250s', null, '2023-10-16 00:00:00+00'::timestamptz, '2023-10-16 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$피부 장벽은 어떻게 생겼고 왜 중요한가요?$AAQ$, $AAA$피부 장벽은 벽돌과 시멘트 구조로 된 피부 가장 겉의 각질층으로, 안팎으로 무언가 들고 나는 것을 막는 핵심 보호막입니다. 목욕탕에서 밀면 나오는 때가 바로 각질층이며, 이게 아무 기능이 없는 게 아니라 두 가지 중요한 역할을 합니다.

첫째는 세균·바이러스·자외선처럼 **밖에서 몸 속으로 들어오는 것을 막아 주고,** 둘째는 신체 60~70%를 차지하는 수분이 증발해 나가는 것도 막아 줍니다. 구조를 보면 **각질세포가 벽돌, 세콜지(세라마이드·콜레스테롤·지방산) 지질이 시멘트** 역할로 층층이 쌓여 있어요. 시멘트가 기름 성분이라 건조할 때 물을 발라도 잘 흡수되지 않는 이유가 바로 여기에 있습니다. 이렇게 중요한 장벽을 화장솜으로 빡빡 닦아내면 피부가 좋아지기 어렵습니다.$AAA$, array['피부장벽', '각질층', '세콜지', '세라마이드', '보호기능']::text[], 2023, 'YuOTZRiB2ds-4', 'https://youtu.be/YuOTZRiB2ds?t=423s', null, '2023-10-16 00:00:00+00'::timestamptz, '2023-10-16 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$판테놀은 피부에서 어떤 역할을 하나요?$AAQ$, $AAA$판테놀은 프로 비타민 B5로, 피부에 흡수된 뒤 비타민 B5로 바뀌어 보습·재생·항염·컨디셔닝 효과를 만들어 냅니다. 비타민 B5는 피부·머리카락·손톱이 자라는 데 중요한 영양소이며, 발랐을 때 피부가 촉촉하고 쫀쫀해지는 변화로 효과를 체감할 수 있습니다.

첫 번째는 피부에 수분을 공급해 **촉촉하고 부드러우며 쫀쫀해지는 효과**가 있고, 두 번째는 손상된 피부를 빠르게 복구하는 재생 효과가 있습니다. 세 번째는 **피부 세균이 막을 형성하는 것을 막아 염증을 억제하는** 항염 효과이고, 네 번째는 손·발톱·머리카락에 수분을 공급하는 컨디셔닝 효과로 속눈썹 영양제와 샴푸에도 많이 쓰입니다. 판테놀에는 D-판테놀과 D,L-판테놀 두 가지 형태가 있는데, 효과 면에서 D-판테놀(덱스판테놀)이 훨씬 뛰어납니다.$AAA$, array['판테놀', '비타민B5', '보습효과', '재생효과', '덱스판테놀']::text[], 2023, 'Bzlq2Zy_7m4-1', 'https://youtu.be/Bzlq2Zy_7m4?t=167s', null, '2023-10-20 00:00:00+00'::timestamptz, '2023-10-20 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$비판텐 연고를 얼굴에 발라도 되나요?$AAQ$, $AAA$비판텐 연고는 효과가 좋은 D-판테놀 5% 제품이지만 얼굴에 그대로 바르기에는 적절하지 않습니다. 연고 제형은 크림·겔보다 가장 되직하고 기름기가 많아 끈적거리며, 라놀린 성분이 들어 있어 얼굴에 바르면 트러블·여드름을 유발할 수 있기 때문입니다.

그래서 비판텐을 굳이 얼굴에 바르거나 **다른 크림에 섞어 쓸 필요는 없습니다.** 시중에 판테놀로 만들어진 화장품이 정말 많이 나와 있어, 그 중 본인 피부에 맞는 제품을 선택해 바르는 것이 더 합리적이에요. 판테놀 화장품의 농도는 적게는 1%, 많게는 10%까지 함유되어 있으며, **피부가 건조하고 예민하거나 레이저 시술 후 부쩍 예민해진 분들**에게 권할 만합니다. 알러지처럼 안 맞는 경우도 있으니 걱정되면 2.5% 제품부터 시작해 보는 것이 안전합니다.$AAA$, array['비판텐', '연고제형', '라놀린', '여드름유발', '판테놀화장품']::text[], 2023, 'Bzlq2Zy_7m4-2', 'https://youtu.be/Bzlq2Zy_7m4?t=72s', null, '2023-10-20 00:00:00+00'::timestamptz, '2023-10-20 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$판테놀 화장품의 재생 효과는 정말 입증되었나요?$AAQ$, $AAA$판테놀의 보습과 재생 효과는 여러 논문에서 입증된 결과가 있습니다. 덱스판테놀 2.5%와 5%를 바른 쪽과 안 바른 쪽을 비교한 연구에서는 피부 속 수분도가 증가하는 결과가 확인되었습니다.

또 다른 연구들에서는 **덱스판테놀 5%(비판텐과 동일 농도)와 유효성분 없는 일반 크림을 비교했을 때 비판텐 쪽의 재생 효과가 더 좋았다는** 결과가 나왔습니다. 이렇게 판테놀이 피부를 촉촉·부드럽게 만들고 재생에 도움이 된다는 점을 보여주는 논문은 이 외에도 많이 있어요. 판테놀이 잘 맞는 분들이 사용하면 좋은 상황은 항상 속당김이 있을 때, 뭘 발라도 계속 건조할 때, **건조해진 날씨에 메이크업이 금방 뜨고 갈라질 때, 피부가 얇은 느낌일 때, 레이저 시술 후 피부가 예민해졌을 때**입니다.$AAA$, array['판테놀', '임상연구', '덱스판테놀', '보습효과', '재생효과']::text[], 2023, 'Bzlq2Zy_7m4-3', 'https://youtu.be/Bzlq2Zy_7m4?t=372s', null, '2023-10-20 00:00:00+00'::timestamptz, '2023-10-20 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$판테놀 화장품은 농도가 높을수록 좋은가요?$AAQ$, $AAA$판테놀만 놓고 보면 함량이 높을수록 효과가 크지만, 실제 화장품은 다른 성분 조합도 중요합니다. 시중 판테놀 화장품은 1%부터 10%까지 다양하게 나와 있어, 자신의 피부에 맞는 제품을 고르는 것이 함량보다 우선될 수 있습니다.

바이엘사의 비판톨은 **D-판테놀 2.5%에 카프릴릭/카프릭트라이글리세라이드 같은 지방산과 글리세린·시어버터**가 함께 들어가 건조하고 예민한 피부에 도움이 됩니다. 라로슈포제의 시카플라스트B5는 덱스판테놀 5%에 마데카소사이드와 히알루론산이 더해져 발림성이 좋아 데일리로 쓰기 편하고, 피부과 시술 후 재생크림으로도 처방됩니다. 바이오힐보 판테셀은 병풀추출물 75.5%와 판테놀 5%, 화상연고 성분인 베타시토스테롤이 든 시카크림이고, **아토팜의 판테놀 크림은 판테놀이 10% 함유된 가장 고함량 제품**입니다.$AAA$, array['판테놀화장품', '농도별', '비판톨', '시카플라스트', '제품비교']::text[], 2023, 'Bzlq2Zy_7m4-4', 'https://youtu.be/Bzlq2Zy_7m4?t=405s', null, '2023-10-20 00:00:00+00'::timestamptz, '2023-10-20 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$적금형 피부 시술이 뭔가요?$AAQ$, $AAA$적금형 시술은 처음에는 차이가 1~2%밖에 나지 않지만 10년, 20년 꾸준히 받으면 큰 효과를 누적시키는 관리 방식입니다. 진피를 차오르게 해야 광채와 우아함이 살아나는데, 진피 관리는 당장 티가 나지 않는다는 단점이 있어 적금처럼 길게 보는 관점이 필요합니다.

진피는 콜라겐과 엘라스틴이라는 밧줄 같은 조직으로 이루어져 있고, **이 조직이 단단하게 당기고 있어야 피부가 치밀하고 탄력 있어요**. 노화가 시작되면 콜라겐을 분해하는 효소가 나오면서 지지대가 무너지고, 표피 아래의 진피가 점점 얇아집니다. 그래서 표피 장벽은 그대로 보존하면서 진피를 차오르게 하는 시술을 꾸준히 적립하듯 받는 것이 핵심이에요. 5년, 10년 지나면 광채와 아우라가 있는 피부로 누적 효과가 드러납니다.$AAA$, array['적금형시술', '진피관리', '콜라겐', '엘라스틴', '광채피부', '누적효과']::text[], 2023, 'WQ1YUlPtER0-1', 'https://youtu.be/WQ1YUlPtER0?t=168s', null, '2023-10-31 00:00:00+00'::timestamptz, '2023-10-31 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$써마지는 얼마 간격으로 받아야 하나요?$AAQ$, $AAA$써마지 같은 고주파 시술은 보통 1년에 한 번 받으면 된다고 알려져 있지만, 비용·통증 부담이 없다면 6개월에 한 번 받는 것도 권할 만합니다. 고주파가 콜라겐을 재생시킨다는 점은 이미 수많은 연구를 통해 입증되어 있어요.

시술 후 **3개월, 6개월이 지나도 콜라겐이 증가된 채로 오랫동안 유지되는 것**을 확인할 수 있습니다. 써마지, 올리지오, 텐써마, 쓰리딥 등 다양한 고주파 시술이 있고, 시술 후 바로 일상생활이 가능하다는 점이 사람을 많이 만나는 직업군에게 큰 장점이에요. 레이저 토닝처럼 자주 받아야 하는 시술과 달리 자주 할 필요가 없어 꾸준히 이어가기 쉬운 편이며, 효과·결과에는 개인차가 있습니다.$AAA$, array['써마지', '고주파시술', '콜라겐재생', '시술간격', '올리지오', '다운타임']::text[], 2023, 'WQ1YUlPtER0-2', 'https://youtu.be/WQ1YUlPtER0?t=322s', '{"pmid": "39957006", "doi": "10.1002/lsm.70002", "title": "Long-Term Efficacy and Safety of a Novel Monopolar Radiofrequency Device for Skin Tightening: A Prospective Randomized Controlled Study.", "journal": "Lasers Surg Med", "year": "2025", "authors_short": "Wang Z, Li L, Zhang X et al.", "pubmed_url": "https://pubmed.ncbi.nlm.nih.gov/39957006/", "doi_url": "https://doi.org/10.1002/lsm.70002"}'::jsonb, '2023-10-31 00:00:00+00'::timestamptz, '2023-10-31 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$고주파 시술과 스킨부스터는 어떻게 다른가요?$AAQ$, $AAA$고주파는 효과가 시간을 두고 나타나는 시술이고, 스킨부스터는 콜라겐 부스팅 재료를 주사로 직접 피부에 넣어 즉각적인 효과를 내는 시술이라는 점이 가장 큰 차이입니다. 두 시술은 효과가 나타나는 시점이 정반대예요.

써마지나 올리지오 같은 고주파는 즉각적인 효과가 없지만 시간이 지나며 콜라겐이 증가합니다. 반면 **리쥬란이나 쥬베룩 같은 스킨부스터는 주사로 바로 집어넣기 때문에 당장 효과가 나는** 대신 주사 바늘 자국이 생긴다는 단점이 있어요. 그래서 두 시술의 단점을 서로 보완하기 위해 스킨부스터로 즉각 효과를 내고, 이후 고주파로 장기 효과를 더하는 식의 병합 시술이 많이 이뤄집니다.$AAA$, array['고주파시술', '스킨부스터', '리쥬란', '쥬베룩', '병합시술', '콜라겐부스팅']::text[], 2023, 'WQ1YUlPtER0-3', 'https://youtu.be/WQ1YUlPtER0?t=428s', '{"pmid": "38093498", "doi": "10.1111/jocd.16125", "title": "A survey on the cosmetic use of injectable polynucleotide: The pattern of practice among Korean Dermatologists.", "journal": "J Cosmet Dermatol", "year": "2023", "authors_short": "Rho NK, Han KH, Cho M et al.", "pubmed_url": "https://pubmed.ncbi.nlm.nih.gov/38093498/", "doi_url": "https://doi.org/10.1111/jocd.16125"}'::jsonb, '2023-10-31 00:00:00+00'::timestamptz, '2023-10-31 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$비타민C 비타민E 세럼은 어떻게 발라야 하나요?$AAQ$, $AAA$비타민C·비타민E와 페룰릭 애시드가 결합된 세럼은 매일 사용하되 자극이 있는 날엔 빈도를 줄여 바르는 것이 권장됩니다. 비타민C와 비타민E는 강력한 항산화 기능으로 광노화 예방에 효과가 있다고 이미 알려져 있어요.

각각의 항산화 물질은 본래 불안정해 공기 노출 시 환원되거나 갈변이 일어나지만, **특정 비율로 합쳤을 때 안정적으로 효과를 낸다는 점이 밝혀졌습니다**. 자외선을 많이 받았거나 자극이 있는 날은 약간 따가울 수 있어 그런 날엔 바르지 않고, 자극이 지속되면 매일 바르던 것을 2일에 한 번, 3일에 한 번으로 줄이는 방식이 좋아요. 적금형 홈케어의 일환으로 꾸준히 발라야 효과가 누적됩니다.$AAA$, array['비타민C세럼', '페룰릭애시드', '항산화', '광노화예방', '홈케어', '사용빈도']::text[], 2023, 'WQ1YUlPtER0-4', 'https://youtu.be/WQ1YUlPtER0?t=85s', '{"pmid": "16185284", "doi": "10.1111/j.0022-202X.2005.23768.x", "title": "Ferulic acid stabilizes a solution of vitamins C and E and doubles its photoprotection of skin.", "journal": "J Invest Dermatol", "year": "2005", "authors_short": "Lin FH, Lin JY, Gupta RD et al.", "pubmed_url": "https://pubmed.ncbi.nlm.nih.gov/16185284/", "doi_url": "https://doi.org/10.1111/j.0022-202X.2005.23768.x"}'::jsonb, '2023-10-31 00:00:00+00'::timestamptz, '2023-10-31 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$노안을 만드는 가장 중요한 구조물은 뭔가요?$AAQ$, $AAA$노안으로 보이게 하는 데 가장 중요한 구조물은 피부가 아니라 뼈, 즉 골격 구조입니다. 골격만 봐도 어느 쪽이 어린이고 어느 쪽이 노인인지 구별할 수 있을 정도예요.

얼굴은 나이가 들면 골격 구조 자체가 변화하도록 되어 있습니다. 눈 밑이 꺼지고 팔자주름 옆이 꺼지면서 전체적으로 함몰이 생기고, **그 위에 지방층이 재배치되면서 늘어진 인상**으로 보이게 돼요. 여기에 잦은 표정 사용으로 생기는 근육 주름이 더해지는 세 가지 요인이 노안의 핵심 원인입니다. 노화는 표면이 아니라 더 깊은 층에서 시작된다는 점을 이해해야 적절한 시술 방향을 잡을 수 있어요.$AAA$, array['노안원인', '골격변화', '지방재배치', '표정주름', '얼굴노화', '구조적변화']::text[], 2023, 'uMaWxFLCpc4-1', 'https://youtu.be/uMaWxFLCpc4?t=72s', null, '2023-11-02 00:00:00+00'::timestamptz, '2023-11-02 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$팔자주름 시술이 꼭 필요한가요?$AAQ$, $AAA$팔자주름이 신경 쓰이는 진짜 이유는 팔자주름 자체가 아니라 그 주변의 잔주름과 입가로 이어지는 주름인 경우가 많습니다. 팔자주름이 전혀 없는 얼굴이 오히려 부자연스러울 수 있어요.

물론 골격이나 구조적으로 푹 꺼져 팔자주름이 깊은 분들은 교정이 필요합니다. 하지만 **더 많은 분들은 사실 입가에 있는 주름이나 마리오네트 주름이 나이 들어 보이게 만드는 요인**이에요. 돌출 입처럼 골격 자체로 입가 주름이 생기는 분도 있지만, 입을 꽉 다무는 습관, 핸드폰·책 보면서 무의식적으로 입을 다무는 습관이 더 흔한 원인이에요. 필러나 실 리프팅 같은 시술도 가능하지만, 집에서 스마일 운동이나 입가 힘 빼기 연습만으로도 개선할 수 있습니다.$AAA$, array['팔자주름', '입가주름', '마리오네트주름', '스마일운동', '입다무는습관', '필러시술']::text[], 2023, 'uMaWxFLCpc4-2', 'https://youtu.be/uMaWxFLCpc4?t=190s', null, '2023-11-02 00:00:00+00'::timestamptz, '2023-11-02 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$관자(태양혈) 꺼짐엔 어떤 시술이 좋나요?$AAQ$, $AAA$관자 부위가 꺼졌을 때 볼륨을 채우는 가장 대표적이고 사실상 유일한 치료 방법은 필러입니다. 관자가 깊어 보이는 위치라 필러 시술 후에도 자연스럽게 교정되는 부위 중 하나예요.

나이가 들수록 관자 부위 뼈가 꺼져 푹 들어가게 되는데, 이렇게 되면 광대가 도드라져 보이고 눈썹 주변이 처지며 수척한 인상을 줍니다. 동안의 기준이 되는 계란형 얼굴이 무너지는 거예요. **이 부위는 굉장히 깊숙이 필러를 집어넣기 때문에** 필러가 이동하거나 문제가 생길 가능성도 거의 없고, 교정 결과도 자연스럽게 나오는 편입니다. 효과·결과에는 개인차가 있지만 노안 인상 개선에 효과적인 부위로 꼽힙니다.$AAA$, array['관자필러', '관자꺼짐', '볼륨필러', '수척한인상', '노안교정', '계란형얼굴']::text[], 2023, 'uMaWxFLCpc4-3', 'https://youtu.be/uMaWxFLCpc4?t=405s', null, '2023-11-02 00:00:00+00'::timestamptz, '2023-11-02 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$눈가 노화는 수술이 가장 좋은 방법인가요?$AAQ$, $AAA$눈가 노화 교정에 가장 드라마틱한 효과를 내는 방법은 수술이지만, 일생에 한두 번 정도로 최대한 미루는 것이 좋다는 입장입니다. 수술 흉터 자체도 시간이 지나면 다시 노화하기 때문이에요.

안구를 보호하는 눈 주변 뼈가 변화하면 가장자리가 쳐지고, 눈꺼풀 위쪽이 푹 꺼져 더 노안으로 보입니다. 눈 밑은 뼈가 흡수되면서 **안와격막이 늘어져 피하지방이 아래로 흘러내려 울퉁불퉁한 모양을 만들어요**. 쳐진 눈꺼풀을 잘라 위로 올려 꼬매는 방식이 대표적인 수술이지만, 수술 자국 부위도 다시 노화가 진행돼 주름지고 처집니다. 그래서 리프팅 레이저, 필러, 스킨부스터 같은 피부과적 치료로 어느 정도 늙어 보이지 않게 관리하는 방법도 함께 고려됩니다.$AAA$, array['눈가노화', '안와격막', '눈밑지방', '눈꺼풀수술', '리프팅레이저', '수술시기']::text[], 2023, 'uMaWxFLCpc4-4', 'https://youtu.be/uMaWxFLCpc4?t=119s', null, '2023-11-02 00:00:00+00'::timestamptz, '2023-11-02 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$여드름을 악화시키는 음식이 진짜 있나요?$AAQ$, $AAA$음식과 여드름은 어느 정도 상관관계가 있다고 현재는 인정되고 있으며, 대표적으로 혈당지수가 높은 음식과 우유·유제품이 영향을 줍니다. 과거 교과서엔 언급이 없었지만 연구 결과가 누적되며 관점이 바뀌었어요.

2002년 미국 콜로라도 대학 연구팀이 발표한 결과를 보면, **파푸아뉴기니 원주민 1200명과 파라과이 원주민 115명 중 여드름을 가진 사람이 단 한 명도 없었습니다**. 일반 서구사회 청년층 여드름 유병률이 70~90%인 것과 대비됐어요. 도시로 이주해 서양화된 식습관을 갖게 된 사람들에서 여드름과 당뇨, 대사증후군이 증가한 것이 확인되며 음식과의 연관성이 주목받았습니다. 다만 식이조절만으로 여드름을 예방·치료할 수 있다고 생각하시면 안 됩니다.$AAA$, array['여드름음식', '혈당지수', '서양식식습관', '유병률', '원주민연구', '식이조절']::text[], 2023, 'C68QC5omUFg-1', 'https://youtu.be/C68QC5omUFg?t=21s', null, '2023-11-08 00:00:00+00'::timestamptz, '2023-11-08 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$혈당지수 높은 음식이 왜 여드름을 유발하나요?$AAQ$, $AAA$혈당지수가 70 이상인 음식을 먹으면 혈당이 빠르게 올라가 인슐린 분비가 증가하고, 이어지는 호르몬 반응이 결국 모공을 막아 여드름을 유발합니다. 도너츠, 떡, 감자, 사탕, 케이크 등 설탕이 많은 음식이 여기에 해당돼요.

혈당지수는 음식 섭취 후 혈당이 상승하는 속도를 0~100 값으로 나타낸 수치입니다. **55 이하가 낮은 혈당지수, 56~69가 보통, 70 이상이 높은 혈당지수**로 분류돼요. 혈당을 낮추기 위해 인슐린이 분비되면 IGF-1 증가를 자극하고, 안드로겐 호르몬 활성도가 올라 피지 분비가 증가하며, 각질형성세포를 자극해 모공을 막는 과정으로 이어집니다. 요즘 유행하는 탕후루도 과일을 설탕물에 코팅한 음식이라 여기에 포함됩니다.$AAA$, array['혈당지수', '인슐린', 'IGF-1', '안드로겐', '피지분비', '모공막힘']::text[], 2023, 'C68QC5omUFg-2', 'https://youtu.be/C68QC5omUFg?t=161s', null, '2023-11-08 00:00:00+00'::timestamptz, '2023-11-08 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$저지방 우유는 여드름에 더 안전한가요?$AAQ$, $AAA$저지방 우유나 무지방 우유가 여드름에 더 안전하지 않으며, 오히려 탈지 우유가 여드름 악화와 더 강한 연관을 보입니다. 우유가 여드름을 악화시키는 이유가 지방이 아니라 단백질과 호르몬이기 때문이에요.

무지방·저지방 우유를 만드는 과정에서 지방 함유량을 줄이는 대신 **다른 호르몬과 유청단백질이 더 많이 들어가게 되는데**, 여러 연구에서 일반 우유보다 탈지 우유가 여드름 악화와 연관이 있다고 보고되고 있어요. 하루 두 잔 이상 우유 섭취 시 그렇지 않은 사람보다 여드름이 잘 발생한다는 연구도 있습니다. 유청단백질은 단백질 보충제에도 많이 들어있어, 보충제 섭취 후 여드름이 갑자기 생긴다면 일단 끊어보시는 게 좋아요.$AAA$, array['저지방우유', '무지방우유', '유청단백질', '단백질보충제', '인슐린상승', '유제품여드름']::text[], 2023, 'C68QC5omUFg-3', 'https://youtu.be/C68QC5omUFg?t=253s', null, '2023-11-08 00:00:00+00'::timestamptz, '2023-11-08 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$여드름이 있으면 어떤 음식 위주로 먹어야 하나요?$AAQ$, $AAA$혈당지수가 낮은 음식과 가공되지 않은 곡류, 콩, 식이섬유가 풍부한 음식을 위주로 드시고 우유는 하루 한 잔 이내로 제한하는 것이 권장됩니다. 음식 조절은 보조적이지만 도움이 될 수 있어요.

흰쌀밥보다 잡곡밥, 흰 빵보다 통밀빵, 주스보다 생과일과 생채소가 좋고 탄산음료 대신 물을 드세요. 우유는 저지방·무지방 대신 일반 우유를 하루 한 잔 이내로 마시고, 커피는 라떼보다 아메리카노가 권장됩니다. **유청단백질 보충제를 드시는 분은 닭가슴살로 대체하는 등** 다른 단백질 섭취 방법을 추천해요. 추가로 오메가-3가 여드름에 도움이 된다는 연구가 있어 육류보다 오메가-3가 많은 생선을 섭취하시는 것도 도움이 됩니다.$AAA$, array['저혈당지수식단', '잡곡밥', '통밀빵', '오메가3', '닭가슴살', '여드름식단']::text[], 2023, 'C68QC5omUFg-4', 'https://youtu.be/C68QC5omUFg?t=336s', null, '2023-11-08 00:00:00+00'::timestamptz, '2023-11-08 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$MD보습제와 일반 보습제는 어떻게 다른가요?$AAQ$, $AAA$MD보습제는 화장품이 아닌 의료기기로 분류된 제품이라 일반 보습제보다 엄격한 출시 절차를 거친다는 점이 가장 큰 차이입니다. MD는 Medical Device의 약자예요.

일반 화장품 보습제와 다르게 **안전성, 안정성, 유효성을 입증하는 자료를 제출해야 하고** GMP 인증 업체에서 생산된 제품인지 확인 절차를 거칩니다. 피부질환이 있는 환자를 대상으로 만들어졌기 때문에 알레르기를 유발하는 성분을 최소화했고, 대부분 무색·무취의 저자극 제품이에요. 세라마이드, 콜레스테롤, 지방산이 함유돼 무너진 피부 장벽 회복에 도움을 줍니다. 한마디로 내 얼굴에 더 믿고 바를 수 있다는 점이 핵심 차이예요.$AAA$, array['MD보습제', '의료기기보습제', '세콜지', '피부장벽', 'GMP인증', '저자극제품']::text[], 2023, 'x2oYe9C-6nk-1', 'https://youtu.be/x2oYe9C-6nk?t=62s', null, '2023-11-15 00:00:00+00'::timestamptz, '2023-11-15 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$MD보습제는 무조건 일반 화장품보다 좋은 건가요?$AAQ$, $AAA$MD제품이 무조건 더 좋은 것은 아니며 피부 타입에 따라 선택이 달라져야 합니다. MD보습제는 건조한 피부에 맞춰 만들어져 끈적임이 더 있을 수 있고, 오히려 유분기가 모공을 막을 수도 있어요.

같은 아토베리어 라인이라도 가격은 비슷한 편으로, **아토베리어365는 80ml에 31,000원, 아토베리어MD는 100g에 35,000원**입니다. 성분상 많은 부분이 중복되고 일부 성분에서만 차이를 보여요. 발랐을 때 느낌은 큰 차이가 없을 수 있지만 MD제품이 의료기기로서 제조 품질관리와 안정성이 강화됐다는 점이 가장 중요한 차이입니다. 다만 끈적이는 느낌이 더 있는 경우가 있고, 트러블이 생겼다는 분들도 있으니 본인 피부 상태에 맞춰 선택하시는 게 좋습니다.$AAA$, array['MD제품선택', '아토베리어', '건조피부', '유분기', '모공막힘', '피부타입']::text[], 2023, 'x2oYe9C-6nk-2', 'https://youtu.be/x2oYe9C-6nk?t=395s', null, '2023-11-15 00:00:00+00'::timestamptz, '2023-11-15 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$MD크림은 오래 바르면 내성이 생기나요?$AAQ$, $AAA$MD크림은 약 성분이 아니라 보습제이기 때문에 오래 발라도 내성이 생기지 않습니다. 내성은 약을 계속 사용했을 때 효과가 떨어지는 현상인데, MD크림은 치료제가 아니라 피부 보호막을 만들어주는 보습제예요.

MD크림의 역할은 **피부 보호막을 만들어 피부 수분을 유지하고 피부 장벽 손상을 개선시키는 효과**입니다. 약 성분으로 피부질환을 직접 치료하는 치료제가 아니기 때문에, 항생제나 스테로이드처럼 내성을 걱정할 필요가 없어요. 내성 걱정 없이 전문의의 안내에 따라 꾸준히 사용해도 됩니다. 다만 심한 피부질환이라면 보습제만으로는 한계가 있기 때문에 약물치료와 병행하는 것이 권장됩니다.$AAA$, array['MD크림내성', '보습제내성', '피부장벽회복', '치료제구분', '장기사용', '수분유지']::text[], 2023, 'x2oYe9C-6nk-3', 'https://youtu.be/x2oYe9C-6nk?t=270s', null, '2023-11-15 00:00:00+00'::timestamptz, '2023-11-15 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$MD보습제는 실비보험이 무조건 적용되나요?$AAQ$, $AAA$MD보습제 구매만으로 실비보험이 무조건 적용되지는 않으며, 피부질환 진료와 처방이 동반되어야 합니다. 아토피 피부염 등으로 피부장벽 손상과 증상이 있어 진료를 받고 처방이 나간 경우 실비 적용 대상이 돼요.

실비보험은 보험 가입 시기, 보험회사, 개인의 보장 범위가 모두 달라 처방전을 보고 약관에 해당되면 적용됩니다. 일부 사람들이 **MD제품을 대량으로 구매하고 보험금을 받은 뒤 중고거래로 재판매하는** 몰상식한 행위가 늘면서, 보험사들이 지급을 중단하거나 기준을 까다롭게 바꿔버렸어요. 의사가 직접 발라줘야 한다거나 일주일에 한 개만 적용 가능 같은 식이라, 진짜 치료 목적으로 사용하는 환자분들이 피해를 보는 상황입니다.$AAA$, array['실비보험', 'MD보습제처방', '아토피피부염', '보험적용기준', '처방요건', '보험약관']::text[], 2023, 'x2oYe9C-6nk-4', 'https://youtu.be/x2oYe9C-6nk?t=300s', null, '2023-11-15 00:00:00+00'::timestamptz, '2023-11-15 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$겨울철 건조한 피부 집에서 어떻게 관리해야 하나요?$AAQ$, $AAA$겨울철 건조한 피부는 보습제를 하루 세 번 이상 발라야 잘 바르는 것에 해당합니다. 하루 한 번만 바르는 것으로는 부족하기 때문이에요.

부분적으로 건조한 부분만 소량 덜어 톡톡 두드리듯이 얼굴에 틈틈이 발라주고, 손등이나 팔, 다리처럼 건조한 부위는 낮에도 수시로 발라줍니다. 미스트를 뿌리는 경우라면 거리를 두고 뿌려 공기를 가습하는 정도로 활용하는 게 좋아요. **무리한 각질 제거는 피부 장벽을 손상시킬 수 있어** 오히려 피부를 더 건조하고 예민하게 만들 수 있습니다. 각질이 눈에 보일 때는 제거하지 말고 보습제를 한 번 더 바르는 편이 좋아요.$AAA$, array['겨울보습', '보습제횟수', '미스트사용', '각질제거', '건조피부', '수시도포']::text[], 2023, 'cbuzmb-AUwE-1', 'https://youtu.be/cbuzmb-AUwE?t=64s', null, '2023-11-24 00:00:00+00'::timestamptz, '2023-11-24 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$바세린 끈적임을 줄여서 바르는 방법이 있나요?$AAQ$, $AAA$바세린은 얇게 펴 바르거나, 보습제 위에 두껍게 바른 후 10분 밀폐했다 떼는 방법, 흐르는 물에 씻어내는 방법 세 가지로 끈적임을 줄일 수 있습니다. 바세린은 피부에 오일막을 형성해 수분 증발을 막는 게 핵심 효과이기 때문이에요.

첫째, 소량을 도포해 아주 얇게 펴 바르면 충분합니다. 둘째, 끈적임이 정말 싫다면 보습제를 먼저 바른 뒤 그 위에 바세린을 두껍게 바르고 장갑이나 마스크팩, 랩을 씌워 10분 두는 방법이 있어요. **메사추세츠 의과대학 하워드 박사가 2020년 '바세린 베스'라는 방법으로 발표한 논문**에 따르면, 바세린을 먼저 바른 뒤 흐르는 물에 씻어내고 수건으로 톡톡 두드린 다음 보습제를 바르면 효과적으로 촉촉함을 유지할 수 있습니다. 단, 지성 피부는 모공이 막혀 여드름이 생길 수 있으니 자제하는 게 좋아요.$AAA$, array['바세린', '끈적임감소', '밀폐요법', '바세린베스', '오일막', '지성피부주의']::text[], 2023, 'cbuzmb-AUwE-2', 'https://youtu.be/cbuzmb-AUwE?t=204s', null, '2023-11-24 00:00:00+00'::timestamptz, '2023-11-24 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$30대 가성비 최고 시술이 뭔가요?$AAQ$, $AAA$30대 가성비 시술로는 보톡스가 가장 추천됩니다. 보톡스만큼 주름에 효과적이고 저렴하고 간단한 시술은 없기 때문이에요. 30대가 되면 표정 근육 수축으로 주름이 생기기 시작하는데, 반복되면 무표정일 때도 고정 주름으로 남게 됩니다.

고정 주름은 한번 생기면 여러 시술로도 없애기 어려워, 생기기 전에 보톡스로 예방하는 것이 좋습니다. **주름 보톡스는 보통 4개월에서 6개월 간격으로 맞아** 1년에 2~3번 정도면 충분하고, 시술은 약 5분이면 끝나요. 내성은 보툴리눔 톡신 주변 복합단백질이 외부 물질로 인식되며 항체가 형성되어 생기는데, 실제로 내성이 생기는 경우는 굉장히 드뭅니다. 내성이 걱정되면 단백질을 줄인 제오민이나 국내산 코어톡스를 선택할 수 있습니다.$AAA$, array['보톡스', '가성비시술', '고정주름예방', '내성걱정', '제오민', '코어톡스']::text[], 2023, 'cbuzmb-AUwE-3', 'https://youtu.be/cbuzmb-AUwE?t=400s', null, '2023-11-24 00:00:00+00'::timestamptz, '2023-11-24 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$자외선 차단제 발라도 비타민D 부족하지 않나요?$AAQ$, $AAA$자외선 차단제를 발라도 비타민D 합성에 유의미한 영향을 주지 않는다는 연구 결과가 있습니다. 메이요 클리닉이 20대 이상 미국 성인을 대상으로 자외선 차단제를 열심히 바른 군과 그렇지 않은 군을 비교했을 때 두 군 간 비타민D 합성에 유의미한 차이가 없었어요.

자외선이 피부에 일으키는 문제는 매우 많아 잔주름, 기미·잡티·주근깨 같은 색소질환, **안 좋은 경우엔 피부암까지** 생길 수 있습니다. 자외선 차단제를 잘 바르는 것만으로도 충분히 예방할 수 있어 안 바를 이유가 없어요. 비타민D는 일주일에 두 번 이상 하루 20~30분 가벼운 산책, 생선 등 비타민D가 풍부한 음식 섭취, 영양제로 권장량을 채울 수 있습니다. 비타민D 주사도 있으니 얼굴 자외선 노출로 합성하려 하기보다 다른 방법을 활용하는 게 좋아요.$AAA$, array['자외선차단제', '비타민D합성', '메이요클리닉연구', '광노화예방', '비타민D보충', '피부암예방']::text[], 2023, 'cbuzmb-AUwE-4', 'https://youtu.be/cbuzmb-AUwE?t=534s', null, '2023-11-24 00:00:00+00'::timestamptz, '2023-11-24 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$좋은 바디로션의 핵심 성분은 뭔가요?$AAQ$, $AAA$좋은 바디로션은 습윤제, 밀폐제, 연화제, 피부장벽 보강 성분이 골고루 들어 있어야 합니다. 이 네 가지가 함께 작동해야 수분을 충분히 공급하고 유지할 수 있기 때문이에요.

습윤제는 마른 스펀지처럼 주변 수분을 끌어당겨 피부에 공급하는 역할로, **글리세린, 히알루론산, 판테놀이 대표적**입니다. 공기가 너무 건조하면 진피에서 수분을 끌어와 피부 겉으로 공급하기도 해요. 밀폐제는 공급된 수분이 증발하지 않도록 비닐막 같은 보호막을 형성하며 바세린, 미네랄 오일, 식물성 오일이 대표적입니다. 연화제는 각질 사이 틈을 메워 부드럽게 해주고, 피부장벽 보강 성분으로는 세라마이드, 콜레스테롤, 지방산이 핵심입니다.$AAA$, array['바디로션성분', '습윤제', '밀폐제', '연화제', '피부장벽', '세라마이드']::text[], 2023, 'TjDXXMrt6pA-1', 'https://youtu.be/TjDXXMrt6pA?t=58s', null, '2023-11-30 00:00:00+00'::timestamptz, '2023-11-30 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$비싼 백화점 바디로션이 더 좋은가요?$AAQ$, $AAA$비싼 백화점 바디로션이 무조건 좋은 것은 아니며, 가격과 보습 성능이 비례하지 않습니다. 백화점 제품은 보습보다 향을 위해 사용하는 경우가 많아요.

샤넬, 조말론, 불리1803, 산타마리아노벨라, 로라메르시 같은 백화점 브랜드 제품들은 **향료와 착향제가 성분 앞쪽에 위치하고**, 보습 성분 중심인 올리브영 제품과 구성 자체가 다릅니다. 더마비, 일리윤, 바이오더마, 세타필, 에스트라 같은 올리브영 제품들은 습윤제, 밀폐제, 연화제, 피부장벽 성분이 골고루 들어가 보습이 핵심이에요. 그래서 향을 즐기는 용도라면 백화점 제품, 실제 건조 부위 보습 목적이라면 올리브영 제품을 선택하는 식의 구분이 합리적입니다.$AAA$, array['백화점바디로션', '향료중심', '보습성분', '샤넬바디로션', '조말론로션', '가격대성능']::text[], 2023, 'TjDXXMrt6pA-2', 'https://youtu.be/TjDXXMrt6pA?t=360s', null, '2023-11-30 00:00:00+00'::timestamptz, '2023-11-30 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$바디로션은 부위마다 다르게 써야 하나요?$AAQ$, $AAA$바디로션은 정답 하나가 있는 게 아니라 피부 상태와 부위별로 다르게 사용하는 것이 좋습니다. 두 제품을 적당히 섞어 바르는 방법도 효과적이에요.

실제로 향을 위해 상체에는 향 중심 백화점 제품을 바르고, **팔꿈치, 종아리, 발등처럼 특히 건조한 부위엔 올리브영 제품을 따로 바르거나** 두 제품을 반반 섞어 보습과 향을 동시에 잡는 방법을 활용할 수 있습니다. 아이들이 아토피가 있고 건조하다면 로션보다는 크림 제형이 더 적합한데, 바이오더마 아토덤 크림 같은 제품을 여러 곳에 두고 긁고 있을 때 바로 발라주는 식으로 활용할 수 있어요. 내 피부 상황에 맞게 현명하게 골라 쓰는 것이 핵심입니다.$AAA$, array['바디로션사용법', '부위별보습', '혼합사용', '아토피관리', '크림제형', '건조부위']::text[], 2023, 'TjDXXMrt6pA-3', 'https://youtu.be/TjDXXMrt6pA?t=589s', null, '2023-11-30 00:00:00+00'::timestamptz, '2023-11-30 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$피부장벽 성분이 들어간 바디로션은 뭐가 있나요?$AAQ$, $AAA$피부장벽 보강 성분이 골고루 들어간 대표적인 바디로션은 에스트라 아토베리어365 바디로션입니다. 보습제가 갖춰야 할 다섯 가지 성분이 모두 들어 있는 구성이에요.

에스트라 제품에는 **세라마이드, 콜레스테롤, 지방산과 천연보습인자가 모두 포함**되어 있어 습윤제, 밀폐제, 연화제, 천연보습인자, 피부장벽 성분이 모두 갖춰져 있습니다. 알레르기를 일으킬 수 있는 성분도 최대한 배제되어 있어 아이들과 어른 누구나 쓸 수 있어요. 일리윤 세라마이드 아토로션도 세라마이드엔피 4ppm이 들어가 피부장벽을 보강해 줍니다. 다만 에스트라 제품은 굉장히 묽어 발목 등 노출되고 건조한 부위는 금방 다시 건조해질 수 있습니다.$AAA$, array['피부장벽바디로션', '아토베리어365', '세라마이드콜레스테롤지방산', '천연보습인자', '일리윤세라마이드', '저자극바디로션']::text[], 2023, 'TjDXXMrt6pA-4', 'https://youtu.be/TjDXXMrt6pA?t=315s', null, '2023-11-30 00:00:00+00'::timestamptz, '2023-11-30 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$여드름은 왜 생기나요?$AAQ$, $AAA$여드름은 모공 막힘, 피지 분비 증가, 여드름균 증식, 염증 반응이라는 네 가지 작용에 의해 생깁니다. 이 네 가지 원인을 개선하면 여드름 완화에 많은 효과를 볼 수 있어요.

첫째 모낭이 각질로 막히는 경우, 둘째 남성 호르몬에 의해 피지 분비량이 많아지는 경우, **셋째 '큐티박테리움 아크네스'라는 여드름균이 증가**하는 경우, 넷째 염증 반응이 일어나는 경우가 핵심 작용입니다. 여드름은 이외에도 많은 복합적인 요인에 의해 발생하는 염증성 질환이지만, 이 네 가지 작용을 잡아주는 것이 연고 선택의 기준이 돼요. 어떤 단계가 문제인지에 따라 항생제 연고, 살리실산 연고, 항염 연고 등 선택이 달라집니다.$AAA$, array['여드름원인', '큐티박테리움아크네스', '피지분비', '모낭각질', '염증반응', '여드름네가지작용']::text[], 2023, 'HbBObeUn5cw-1', 'https://youtu.be/HbBObeUn5cw?t=37s', null, '2023-12-07 00:00:00+00'::timestamptz, '2023-12-07 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$에스로반 연고는 여드름에 효과 있나요?$AAQ$, $AAA$에스로반은 여드름보다 모낭염에 더 효과적인 연고입니다. 무피로신이라는 항생제 성분이라 세균 감염성 질환인 모낭염에 잘 듣기 때문이에요. 박테로신, 베아로반도 같은 성분의 연고입니다.

모낭염은 털구멍에 균이 들어가 생기는 염증질환인데, 남성의 면도 후 트러블, 여성의 제모·왁싱 후 트러블, **물놀이나 필링·스크럽 후 자극이 일어나고 생긴 트러블**이 모낭염에 가깝습니다. 후시딘도 항생제 연고지만 에스로반이 커버하는 항생제 범위가 조금 더 넓어요. 항생제 연고이므로 내성이 생길 수 있어, 상처나 모낭염이 완전히 없어질 때까지 끝까지 발라야 내성을 줄일 수 있습니다. 애매하게 남은 상태에서 끊으면 세균이 항생제에 진화해 내성이 생기기 때문이에요.$AAA$, array['에스로반', '무피로신', '모낭염', '항생제연고', '내성예방', '후시딘비교']::text[], 2023, 'HbBObeUn5cw-2', 'https://youtu.be/HbBObeUn5cw?t=89s', null, '2023-12-07 00:00:00+00'::timestamptz, '2023-12-07 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$화이트헤드 블랙헤드엔 어떤 연고가 좋나요?$AAQ$, $AAA$면포성 여드름인 화이트헤드와 블랙헤드에는 아젤리아 크림이나 클리어틴 외용액 2%가 효과적입니다. 두 제품 모두 피지 분비물과 각질이 응겨 있는 면포를 녹여주는 작용을 해요.

아젤리아 크림은 아젤릭산이 포함된 자연유래 성분으로 **임산부나 수유부가 안전하게 사용할 수 있고**, 타이로시네이즈 효소를 억제해 미백 효과와 여드름 색소침착 개선에도 도움이 됩니다. 클리어틴 외용액 2%는 살리실산 성분으로 지방에 잘 녹는 성질이 있어 피지선에 잘 들어가 묵은 각질과 피지 덩어리를 녹여주고 피지 분비량도 줄여줘요. 자극이 있을 수 있어 하루 한 번부터 보습제와 섞어 시작해보시는 게 좋습니다.$AAA$, array['아젤리아크림', '클리어틴', '살리실산', '화이트헤드블랙헤드', '면포여드름', '임산부사용']::text[], 2023, 'HbBObeUn5cw-3', 'https://youtu.be/HbBObeUn5cw?t=222s', null, '2023-12-07 00:00:00+00'::timestamptz, '2023-12-07 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$붓고 아픈 화농성 여드름엔 어떤 연고를 발라야 하나요?$AAQ$, $AAA$붉게 부어오르고 만지면 아픈 화농성 여드름엔 애크논 크림이 효과적입니다. 해열 진통소염제인 이부프로펜 성분과 항균 작용을 하는 이소프로필메틸페놀 성분이 함께 들어 있기 때문이에요.

갑자기 붉게 올라오고 건드리면 아프거나 부어오른 여드름, **잘 짜지지 않는 그런 여드름에 효과적**이라 면봉으로 찍어서 발라줍니다. 그 상태로 자도 되지만, 더 좋은 효과를 위해서는 랩이나 듀오덤 같은 밀폐제를 약 위에 얹어주면 약이 더 잘 스며들어 염증이 빨리 가라앉아요. 큐아크네 크림도 비슷한 성분이지만 애크논 크림이 이소프로필메틸페놀 함량이 더 높습니다. 균 증식을 억제하는 성분이 있어 화농성 여드름에 효과적이에요.$AAA$, array['애크논크림', '화농성여드름', '이부프로펜', '이소프로필메틸페놀', '밀폐요법', '큐아크네비교']::text[], 2023, 'HbBObeUn5cw-4', 'https://youtu.be/HbBObeUn5cw?t=374s', null, '2023-12-07 00:00:00+00'::timestamptz, '2023-12-07 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$화장품 바르는 순서는 어떻게 정하나요?$AAQ$, $AAA$기초 화장품은 묽고 수분 함량이 많은 제형부터 꾸덕하고 유분기가 많은 제형 순서로 바르시면 됩니다. 유분기가 많은 제품을 먼저 바르면 피부에 일종의 기름막을 형성해서 그 위에 수분을 아무리 보충해도 흡수가 되지 않기 때문입니다. **묽고 수분 함량이 많은 제형부터** 바르는 것이 원칙이에요.

수분 함량이 많은 것을 세분화하면 토너가 제일 묽고, 일반적으로 에센스, 세럼, 앰플 순으로 농축이 점점 진해집니다. 다만 비타민A나 비타민C처럼 자극이 되는 성분은 예외인데, 제형이 묽다고 너무 먼저 바르다 보면 오히려 자극감이 더 심해질 수 있어요. 이럴 때는 **로션이나 크림과 같은 유분기가 많은 것들을 먼저 발라 보호막을 형성한 다음에** 바르거나, 두 가지를 섞어서 바르셔도 됩니다.$AAA$, array['화장품순서', '스킨케어순서', '토너세럼앰플', '유분기제형', '비타민A비타민C']::text[], 2023, 'P3z1jbU412o-1', 'https://youtu.be/P3z1jbU412o?t=22s', null, '2023-12-13 00:00:00+00'::timestamptz, '2023-12-13 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$마스크팩 전에 바르면 안 되는 게 있나요?$AAQ$, $AAA$마스크팩 전에 바르면 안 되는 세 가지는 유분기 많은 성분, 자극 성분, 피부과 처방약입니다. 마스크팩은 수분 함량이 많은 에센스 제형을 잘 흡수시키기 위해 하는 건데, 바세린이나 오일 같은 유분기 많은 것을 먼저 바르면 오일 성분이 얼굴에 기름막을 형성해 **에센스가 흡수되는 것을 막아버리게 되거든요**.

두 번째로 피해야 할 것은 비타민A, 비타민C 같은 자극 성분이에요. 팩을 하면서 밀폐 작용이 되어 흡수도가 높아지면 자극이 더 심해질 수 있습니다. 세 번째는 스테로이드 연고, 스티바 연고, 디페린, 멜라논 크림 같은 피부과 처방약인데, **약재에 의한 부작용 발생 위험이 더 커지기 때문에** 팩을 한 다음에 바르는 것이 맞는 순서입니다. 이런 꾸덕한 성분이나 자극 성분, 처방약은 팩 후 마무리 단계에 발라주세요.$AAA$, array['마스크팩', '팩전바르면안되는것', '바세린오일', '스테로이드연고', '디페린']::text[], 2023, 'P3z1jbU412o-2', 'https://youtu.be/P3z1jbU412o?t=147s', null, '2023-12-13 00:00:00+00'::timestamptz, '2023-12-13 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$건성, 민감성 피부도 닦토를 해도 되나요?$AAQ$, $AAA$건성, 민감성 피부라면 닦토는 하지 않는 것이 좋습니다. 적절한 세안만으로도 공기 중 먼지, 피지, 노폐물, 메이크업은 충분히 제거가 가능하고 굳이 추가적으로 닦토를 하실 필요까지는 없어요. 건성·민감성 피부가 닦토를 계속 하면 **반복적인 마찰로 인해서 오히려 피부장벽이 깨질 수가 있어요**.

다만 화장을 두껍게 한 날 세안만으로 눈화장이 충분히 지워지지 않거나, 지성피부가 너무 심해서 피지 분비량이 많은 경우에는 닦토를 가끔씩 해주는 것은 괜찮습니다. 수건에서 묻어나는 먼지가 고민이시라면 시중에 일회용 페이스타올 같은 것들도 있으니까 그런 제품으로 가볍게 물기를 닦아내시면 돼요. 세안 후에는 **물기가 약간 묻어 있는 상태에서 보습제를 발라 주는 게 보습면에서는 효과가 더 좋거든요**.$AAA$, array['닦토', '건성민감성피부', '피부장벽', '일회용페이스타올', '보습']::text[], 2023, 'P3z1jbU412o-3', 'https://youtu.be/P3z1jbU412o?t=246s', null, '2023-12-13 00:00:00+00'::timestamptz, '2023-12-13 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$복합성 피부도 따로 관리해야 하나요?$AAQ$, $AAA$복합성 피부는 굳이 피부 타입을 따로 나누지 않고 현재 피부상태에 맞춰서 관리해 주시는 게 좋습니다. 지성피부라 해도 겨울철에는 건조해질 수 있고, 건성피부라도 여름철에는 번들거리는 부분이 있기 때문이에요. **건성피부도 T존이라 불리는 이마와 코는 번들거릴 수가 있어요**.

전체적으로 건성피부인 사람도 피지 분비량이 많은 T존은 번들거릴 수 있고, 지성피부인 사람도 피부가 비교적 얇은 눈 주변이나 입 주변은 건조해질 수 있는데, 이러한 경우를 복합성이라고 부릅니다. 이럴 때에는 **건조한 부위는 보습에 신경을 써주시고 번들거리는 부분은 좀 더 산뜻한 제형의 보습제를 가볍게** 바르시는 등의 스킨 케어를 해 주시면 됩니다. 피부 타입 하나에 갇히지 말고 부위별·계절별로 유연하게 대응하는 것이 핵심이에요.$AAA$, array['복합성피부', 'T존U존', '피부타입', '부위별보습', '계절별스킨케어']::text[], 2023, 'P3z1jbU412o-4', 'https://youtu.be/P3z1jbU412o?t=393s', null, '2023-12-13 00:00:00+00'::timestamptz, '2023-12-13 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$모공이 넓어지는 원인은 무엇인가요?$AAQ$, $AAA$모공이 넓어지는 원인은 크게 피지샘, 잘못된 홈케어, 나이가 들어감에 따른 탄력 저하 세 가지로 함축할 수 있습니다. 모공은 말 그대로 털구멍으로 어렸을 때부터 타고나는 것이라 없앨 수는 없지만, 원인에 따라 치료해주면 줄일 수 있어요. **모공이 넓어지는 원인은 세 가지**입니다.

젊었을 때는 다른 요인들보다 많은 피지 분비량으로 인해서 모공이 넓어지는 경우가 거의 대부분이고, 한 논문 결과에서도 18세에서 80세까지 보면 **젊은 분들은 피지 양을 줄이는데 중점을 둬야 되고 나이가 드신 분들은 탄력에 조금 더 중점**을 두라고 합니다. 잘못된 홈케어 중에서는 코팩을 자주 해서 피부를 손상시키는 행위나 스크럽제를 자주 쓰는 것이 모공을 더 넓게 만들 수 있어요. 따라서 원인에 따라서 치료를 해주는 것이 가장 중요합니다.$AAA$, array['모공원인', '피지샘', '홈케어', '탄력저하', '모공넓어짐']::text[], 2023, 'vt9lDByCTC8-1', 'https://youtu.be/vt9lDByCTC8?t=96s', null, '2023-12-22 00:00:00+00'::timestamptz, '2023-12-22 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$이소트레티노인 먹으면 모공이 줄어드나요?$AAQ$, $AAA$이소트레티노인은 한 달 정도 지나면 피지 분비량이 많이 줄고 모공이 쫀쫀해지는 경험을 할 수 있는 피지 조절제입니다. 모공이 한 번 넓어지면 5~60대가 된다고 해서 갑자기 감소하지 않기 때문에 적극적인 피지 억제가 필요한데, **이소트레티노인이 가장 효과적이고 빨리 좋아질 수 있는 방법**이에요.

다만 이 약은 전문의약품이기 때문에 본인 피부상태에 대해서 전문의와 충분히 상의한 다음에 처방을 받아 복용해야 합니다. **너무 과량 복용하거나 잘못된 방법으로 복용하면 피지가 너무 말라버려서 얼굴이 건조해지고** 피부에 손상이 가서 탄력이 떨어질 수 있어요. 그로 인해 오히려 모공이 더 넓어질 수 있으니까 뭐든지 적당히 하는게 좋습니다. 효과는 좋지만 자가 판단으로 복용하면 안 되고 반드시 의료진과 상의해야 하는 약입니다.$AAA$, array['이소트레티노인', '피지조절제', '모공축소', '전문의약품', '부작용']::text[], 2023, 'vt9lDByCTC8-2', 'https://youtu.be/vt9lDByCTC8?t=293s', null, '2023-12-22 00:00:00+00'::timestamptz, '2023-12-22 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$모공 관리에 좋은 화장품 성분은 무엇인가요?$AAQ$, $AAA$모공 줄이는 데 검증된 화장품은 레티놀, 레티날 크림이며, 더 효과적인 것으로는 전문의약품인 디페린 겔이 있습니다. 모공을 한순간에 줄여준다는 화장품은 믿으시면 안 됩니다. 레티놀, 레티날 크림은 **모공 줄이기에 검증된 화장품**이에요.

레티노이드 계열의 크림은 안티에이징 효과뿐 아니라 묵은 각질을 제거해주고 여드름이 올라오고 피지 분비량이 많은 분들의 피부를 개선해주며, **피부 자체를 매끈하고 쫀쫀하게 해주는 역할이 있기 때문에** 모공에도 도움이 됩니다. 레티놀, 레티날, 레티노산으로 갈수록 효과는 더 좋지만 부작용도 더 크기 때문에 사용 시 주의해야 해요. 레티놀이나 레티날 크림이 약하게 느껴진다면 병원에서 디페린 겔을 처방받아 사용해 보시는 것을 권해 드립니다. 모공을 직접 줄인다기보다 각질의 턴오버 주기를 빨리 해서 피부를 매끄럽게 하는 효과가 더 큽니다.$AAA$, array['레티놀레티날', '디페린겔', '레티노이드', '각질턴오버', '모공크림']::text[], 2023, 'vt9lDByCTC8-3', 'https://youtu.be/vt9lDByCTC8?t=503s', null, '2023-12-22 00:00:00+00'::timestamptz, '2023-12-22 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$탄력 저하로 넓어진 모공은 어떤 시술이 좋나요?$AAQ$, $AAA$나이가 들어 탄력 저하로 넓어진 모공은 울쎄라나 써마지 같은 탄력 시술이 도움이 됩니다. 모공 주변에도 탄력 섬유들이 쫀쫀하게 메워주고 있다가 나이가 들면 점차 사라지면서 느슨하게 중력 방향으로 늘어지는데요, **이런 경우는 탄력에 신경을 써주시면** 모공을 줄이는 데 도움이 됩니다.

집에서 홈쎄라 같은 기계로 루틴으로 해주셔도 도움이 되고, 매일 관리가 귀찮다면 병원에 **6개월이나 1년에 한 번씩 오셔서 울쎄라나 써마지를 한 번씩 받아주시면** 탄력도가 떨어져서 모공이 넓어지는 것을 방지할 수 있어요. 모공 흉터에 특화된 스킨부스터 쥬베룩도 도움이 됩니다. 피지 분비량이 많아서 늘어난 모공은 피지선만 집중적으로 파괴하는 아그네스 시술이나 바늘 고주파 시술, 골드PTT가 도움이 될 수 있어요. 얼굴이 높은 온도에 지속 노출되면 모공이 넓어질 수 있어 열을 많이 받은 날엔 쿨링팩으로 진정시키는 것도 좋습니다.$AAA$, array['울쎄라써마지', '탄력모공', '아그네스', '쥬베룩', '바늘고주파']::text[], 2023, 'vt9lDByCTC8-4', 'https://youtu.be/vt9lDByCTC8?t=996s', null, '2023-12-22 00:00:00+00'::timestamptz, '2023-12-22 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$복합성 피부는 어떻게 세안해야 하나요?$AAQ$, $AAA$복합성 피부는 꼼꼼하게 씻되 피부 보호막을 날릴 만큼 세안 과정이 과해지면 안 됩니다. 복합성 피부는 트러블은 있지만 한편으로는 수분도 부족하고 굉장히 민감한 피부이기 때문이에요. **트러블이 있어도 과한 세안은 금물**입니다.

화장을 한 날엔 립앤아이 리무버로 눈과 입술 같은 포인트 부위를 먼저 지우고, 얼굴 나머지 부위는 클렌징 로션으로 부드럽게 씻어내시면 됩니다. 클렌징 오일은 오일 입자가 트러블성 피부에는 안 좋을 수 있고 클렌징 워터는 닦아내는 과정에서 자극이 될 수 있어 **로션 타입을 권고**해요. 손에 일정량 덜고 미온수를 섞은 후 부드럽게 마사지하듯 씻어내시고, 세안 시간은 화장 지우는 단계부터 씻어내는 것까지 2~3분 이내가 충분합니다. 세안 후 뽀드득보다는 부드럽다는 느낌이 드는 정도가 적절해요.$AAA$, array['복합성세안', '클렌징로션', '이중세안', '민감성피부', '세안시간']::text[], 2023, 'U3aPjtnco5k-1', 'https://youtu.be/U3aPjtnco5k?t=80s', null, '2023-12-29 00:00:00+00'::timestamptz, '2023-12-29 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$스크럽이나 필링겔은 얼마나 자주 해야 하나요?$AAQ$, $AAA$각질이 많이 일어나도 스크럽이나 필링겔은 주 1회 정도만 사용하시는 게 좋습니다. 너무 자주만 아니면 무조건 하지 말라는 것은 아니지만, 입자가 굵어서 거친 것보다는 부드럽게 문지를 수 있는 제형이 좋아요. **주 1회 정도만 각질을 정돈**해 주세요.

사용할 때는 얼굴에 물이 있는 상태에서 **30초 정도 가볍게 마사지하고 끝내시면 각질 정돈도 잘 되고 자극도 되지 않습니다**. 살짝 마사지만 해도 부드럽게 필링이 되는 제품이 좋고, 입자가 굵어 강하게 문지르는 제품은 피하시는 게 좋아요. 단, 지금 내 피부가 민감하고 따갑고 붉은 상태라면 이런 과정도 아예 안 하시는 게 좋습니다. 트러블이 심하게 진행되는 시점에는 각질 케어보다 피부 진정과 회복이 우선이에요.$AAA$, array['스크럽필링겔', '각질정돈', '주1회', '민감성피부', '각질관리']::text[], 2023, 'U3aPjtnco5k-2', 'https://youtu.be/U3aPjtnco5k?t=282s', null, '2023-12-29 00:00:00+00'::timestamptz, '2023-12-29 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$여드름 연고는 어떻게 발라야 자극이 덜한가요?$AAQ$, $AAA$민감성, 복합성 피부는 보습 크림을 얼굴 전체에 먼저 바르고 그 위에 여드름 연고를 트러블 부위에만 스팟으로 소량 바르는 것이 좋습니다. 대부분의 여드름 연고 설명서에는 맨 얼굴에 바르라고 되어 있지만, **레티노이드 같은 자극 성분**이 들어 있어 민감한 피부엔 각질이 일어나고 빨개질 수 있어요.

그래서 보습 크림을 얼굴 전체에 바른 후 트러블이 있는 부위에 **손가락 끝이나 면봉으로 콕콕콕 얹어주듯이 찍어서** 바르시는 게 좋습니다. 그래도 자극이 된다면 보습제와 연고를 반반 섞어서 희석해 바르는 방법도 있어요. 민감한 분들은 매일 연속으로 바르면 자극이 될 수 있으니 2~3일 정도만 바르고 피부 상태를 보면서 쉬엄쉬엄 바르셔도 됩니다. 트러블이 너무 심해 홈케어로 안 잡힐 땐 진료를 보고 의약품을 처방받는 게 가장 빠른 해결책이에요.$AAA$, array['여드름연고', '스팟도포', '민감성피부', '레티노이드', '희석사용']::text[], 2023, 'U3aPjtnco5k-3', 'https://youtu.be/U3aPjtnco5k?t=388s', null, '2023-12-29 00:00:00+00'::timestamptz, '2023-12-29 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$수분 부족형 지성 피부는 어떻게 관리하나요?$AAQ$, $AAA$T존은 기름지고 U존은 건조한 복합성 피부는 사실 '수분 부족형 지성 피부'라는 표현이 더 적합하며, 얼굴 전체에 보습제를 골고루 충분히 발라주는 것이 핵심입니다. 피부도 유수분 밸런스가 중요해서 너무 공급을 안 해주면 부족함을 보상하기 위해 **피지가 더 많이 분비**될 수 있어요.

세안 후 토너를 쓰고 얼굴 전체에 보습제를 골고루 바르는데, 여름에는 로션 제형, 나머지 계절에는 발림성이 좋고 꾸덕하지 않은 크림류를 사용해요. **전체적으로 충분히 유수분을 공급해주는 게 결과적으로 기름이 덜 올라오는 방법**입니다. 다만 라놀린, 스테아르산, 올레익산, 코코넛 오일 같은 모공을 막을 수 있는 성분은 트러블을 악화시킬 수 있어 주의하시고, 헷갈리면 '논코메도제닉'이 쓰여있는 제품이나 병원용 제품들을 사용하시는 것이 안전합니다.$AAA$, array['수분부족형지성피부', '유수분밸런스', '복합성보습', '논코메도제닉', 'T존U존']::text[], 2023, 'U3aPjtnco5k-4', 'https://youtu.be/U3aPjtnco5k?t=211s', null, '2023-12-29 00:00:00+00'::timestamptz, '2023-12-29 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$울쎄라 받을 때 가장 중요한 것은 무엇인가요?$AAQ$, $AAA$울쎄라는 내 피부층에 맞는 팁을 사용해서 시술해야 한다는 점이 가장 중요합니다. 사람마다 피부층이 얇은 사람도 두꺼운 사람도 있고, 같은 사람 얼굴 안에서도 부위마다 피부 두께가 달라서 **각각 어떤 팁을 써서 몇 샷을 시술할지 디자인**해서 받아야 해요.

울쎄라는 초음파 리프팅 중에 가장 오랜 역사를 가지고 가장 강력하고 효과가 좋은 시술이지만, 잘못 받으면 볼패임이 더 심해지거나 얼굴이 해골처럼 됐다는 사례도 있습니다. 통증 때문에 두려운 분이라면 **300샷 정도 작은 샷 수로 한 번 경험해 보시는 것을 권**해 드려요. 실제로 맞아보면 생각보다 안 아프다는 분도 많고, 울쎄라는 1년에 한 번 정도만 시술하면 되기 때문에 한 번 정도는 생각해 볼 만한 시술입니다. 수면마취도 가능하지만 무섭다면 작은 샷으로 체험해보는 접근이 부담을 줄여 줍니다.$AAA$, array['울쎄라', '초음파리프팅', '팁선택', '수면마취', '300샷']::text[], 2023, 'UbW6fYcvDLo-1', 'https://youtu.be/UbW6fYcvDLo?t=93s', null, '2023-12-30 00:00:00+00'::timestamptz, '2023-12-30 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$더모톡신과 일반 보톡스는 어떻게 다른가요?$AAQ$, $AAA$더모톡신은 일반 보톡스를 피부의 얕은 진피층에 전체적으로 주입하는 시술로 스킨보톡스, 메조보톡스로도 불리며, 일반 보톡스가 표정 주름이나 턱·종아리 근육을 타깃하는 것과는 본질적으로 다릅니다. 일반 보톡스는 이마, 미간, 눈가 주름이나 턱·종아리 근육 크기 감소에 쓰이지만, **더모톡신은 피부 얕은 층에 전체적으로 주입**해요.

보톡스를 진피층에 주사하면 피지샘이나 혈관, 얕은 모공 주변 근육들을 마비시켜서 **모공이 좀 덜 보이게 만들고 혈관도 작아지게 만들고 피지샘 분비를 줄여**줍니다. 다만 매우 희석한 보톡스를 많이 넣기 때문에 너무 자주 맞으면 내성 위험이 있어 중요한 일 있으실 때만 받는 것을 권하고, 자주 맞는다면 제오민이나 코어톡스처럼 내성 없는 보톡스가 더 권장됩니다. 입 주변 얕은 층에는 표정 근육들이 있어 잘못 주입되면 입이 안 움직이거나 웃지 못하는 부작용이 생길 수 있어 주의해야 해요.$AAA$, array['더모톡신', '스킨보톡스', '메조보톡스', '내성', '제오민코어톡스']::text[], 2023, 'UbW6fYcvDLo-2', 'https://youtu.be/UbW6fYcvDLo?t=158s', null, '2023-12-30 00:00:00+00'::timestamptz, '2023-12-30 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$리쥬란과 스킨보톡스 중 어떤 게 더 맞나요?$AAQ$, $AAA$리쥬란은 건조함·속당김이 심하거나 염증이 많은 피부에 효과가 좋고, 스킨보톡스는 모공이 고민이거나 홍조·지성 피부에 효과가 좋아 적응증이 다릅니다. **건조함과 속당김이 심한 분들이나 민감하거나 여드름이 있어 염증이 많은 분들에게 리쥬란**이 훨씬 효과가 좋아요.

반대로 **스킨보톡스는 모공이 고민이거나 전반적으로 홍조가 있거나 기름지고 지성 피부인 분들에게 효과**가 좋습니다. 둘 다 결혼식 같은 중요한 날 피부가 확 좋아지고 화장이 잘 먹게 하는 효과가 있어 그럴 땐 둘 다 추천하는 편이에요. 리쥬란은 시술이 아픈 걸로 유명한데 통증이 두려우면 무통 리쥬란을 적극 권해 드립니다. 리쥬란만큼의 효과는 충분히 노리면서 통증은 매우 적기 때문이에요. 보통 리쥬란은 한 달 간격으로 세 번 정도를 권장하지만 모든 사람에게 똑같이 적용되는 건 아닙니다.$AAA$, array['리쥬란', '스킨보톡스', '무통리쥬란', '속당김', '모공홍조']::text[], 2023, 'UbW6fYcvDLo-3', 'https://youtu.be/UbW6fYcvDLo?t=281s', null, '2023-12-30 00:00:00+00'::timestamptz, '2023-12-30 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$써마지는 왜 매년 받아야 효과가 좋나요?$AAQ$, $AAA$써마지는 저금처럼 피부에 적립하는 형태의 시술로 매년 꾸준히 받았을 때 빛을 발하기 때문입니다. 시술 후 바로 대단한 탄력이 생기는 것보다는 **떨어지는 콜라겐을 1년에 한 번 정도 살짝 붙잡아 놓는 시술**이라고 생각하시면 좋아요.

써마지는 피부 진피층 전체를 데워서 진피층을 탄탄하게 만들고, **콜라겐과 콜라겐 사이를 연결하는 엘라스틴이라는 밧줄 같은 조직을 다시 팽팽하게 당기고 재생**시키는 역할을 합니다. 콜라겐의 가장 큰 역할은 수분을 잡아주는 것이라 콜라겐이 풍부하면 건조하지 않고 피부가 밝고 맑아 보여요. 어린 아이들 피부가 로션 없이도 건조하지 않은 이유가 바로 탱탱하고 탄력 있는 콜라겐과 엘라스틴 덕분입니다. 한예슬님처럼 울쎄라로 깊은 근막층을 잡고 리쥬란이나 스킨보톡스로 겉을 좋아지게 하고 써마지로 전반적 탄력까지 같이 관리하는 것이 영리한 조합이에요.$AAA$, array['써마지', '콜라겐', '엘라스틴', '진피층', '안티에이징']::text[], 2023, 'UbW6fYcvDLo-4', 'https://youtu.be/UbW6fYcvDLo?t=440s', null, '2023-12-30 00:00:00+00'::timestamptz, '2023-12-30 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$홍조가 있을 때 하지 말아야 할 것은 무엇인가요?$AAQ$, $AAA$홍조가 있다면 뜨거운 물로 세안하고 찬물로 마무리하는 것, 스크럽, 토너 닦토, 의료진 처방 없는 스테로이드 연고 사용을 피하셔야 합니다. 모공을 열고 닫는다는 생각으로 온냉 세안을 하시는데, **급격한 온도 변화는 혈관을 자극**시킬 수 있어요.

미지근하다고 느껴지는 피부와 비슷한 온도로 1-2분 이내로 세수하시는 게 좋고, 스크럽은 각질층을 벗겨내는 행위인데 각질층이 유해 물질과 알레르겐으로부터 피부를 보호하는 역할을 하므로 없애면 더 민감해질 수 있어요. 토너의 닦토 행위 자체가 자극이 되어 **민감한 피부를 더 예민하게 만들 수가 있어요**. 스테로이드 연고는 적절한 강도·부위·기간에 사용해야 효과를 보고 부작용도 방지할 수 있는데, 자가 판단으로 오래 반복 사용하면 결과적으로 치료가 더 어려워집니다. 강한 햇빛, 뜨겁고 자극적인 음식, 음주도 홍조를 악화시킬 수 있어 피하시는 게 좋습니다.$AAA$, array['홍조주의사항', '온냉세안', '스크럽', '닦토', '스테로이드연고']::text[], 2024, 'oDaK588uBUI-1', 'https://youtu.be/oDaK588uBUI?t=107s', null, '2024-01-04 00:00:00+00'::timestamptz, '2024-01-04 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$홍조에 도움 되는 화장품 성분은 무엇인가요?$AAQ$, $AAA$홍조에 도움이 되는 대표 성분은 나이아신아마이드와 아젤라익산이며, 둘 다 항염증 효과로 혈관 주변 염증을 가라앉혀 줍니다. 나이아신아마이드는 니코틴아마이드라고 하는 비타민B3 일종으로 **염증을 가라앉히고 항산화, 미백 효과**도 있어요.

10%, 20% 고함량 제품은 자극이 될 수 있어 **5% 이내의 제품들도 충분히 효과를 보실 수가 있어서** 그 정도 농도가 적절합니다. 아젤라익산도 항염 성분으로 여드름 제품에 많이 들어가요. 이외에 피버퓨, 녹차, 감초 추출물, 카모마일, 알로에 같은 식물류 성분도 도움이 됩니다. 시중 제품 중 에스트라의 A-cica 365 블래미쉬 카밍 세럼(나이아신아마이드 2%), 스킨수티컬즈 피토 코렉티브 앰플(아젤라익산 3%), 라로슈포제 똘러리앙(나이아신아마이드 4-5%, SPF30) 등이 있어요. 처음 쓰는 제품은 얼굴 가장자리나 팔 안쪽에 먼저 테스트해 보시고, 너무 따갑고 민감한 상태라면 아예 사용을 안 하시는 게 좋습니다.$AAA$, array['나이아신아마이드', '아젤라익산', '항염성분', '프래그런스프리', '민감성피부세럼']::text[], 2024, 'oDaK588uBUI-2', 'https://youtu.be/oDaK588uBUI?t=386s', null, '2024-01-04 00:00:00+00'::timestamptz, '2024-01-04 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$홍조 병원 치료에는 어떤 게 있나요?$AAQ$, $AAA$홍조 병원 치료는 정확한 진단 후 먹는 항생제, 혈관 수축 연고, Vbeam 레이저 등 단계별로 진행됩니다. 먹는 약으로는 **미노사이클린이나 독시사이클린 같은 항생제 성분**을 주로 처방드리는데, 균을 억제하면서 항염증 작용이 굉장히 강한 약재여서 저용량으로 길게는 몇 달까지도 처방드려요.

바르는 연고 중에는 브리모니딘, 옥시메타졸린, 프로프라놀롤처럼 혈관을 수축시키는 연고가 있고 안약으로 나온 것을 피부에 바르도록 처방하기도 합니다. 수란트라, 로제스, 아젤라익산, 엘리델 같은 항염증 연고도 있어요. 약을 써도 남아있는 늘어난 실핏줄은 약으로 더 잡히지 않고 레이저로 치료해야 하는데, **대표적인 게 Vbeam 레이저로 혈색소를 타겟으로 해서 피부에 늘어나는 혈관들을 억제**해주는 시술입니다. 이외에도 피부 진정과 재생에 도움이 되는 LDM이나 LED 관리도 같이 하시면 도움이 돼요.$AAA$, array['미노사이클린독시사이클린', 'Vbeam레이저', '엘리델', '혈관수축연고', '홍조치료']::text[], 2024, 'oDaK588uBUI-3', 'https://youtu.be/oDaK588uBUI?t=610s', null, '2024-01-04 00:00:00+00'::timestamptz, '2024-01-04 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$민감한 피부도 메이크업해도 되나요?$AAQ$, $AAA$홍조 민감 피부는 메이크업을 가급적 안 하시는 게 좋지만, 한다면 1차 세안만으로 지울 수 있을 정도로 가볍게 하시는 게 좋습니다. 메이크업하면 닦아내야 할 게 많아지기 때문이에요. **자외선도 홍조를 악화**시킬 수 있어 자외선 차단제는 필수입니다.

홍조가 있는 민감한 분들은 화학적 차단제보다 **물리적 무기자차 성분의 자외선 차단제**가 더 낫고, 선크림을 바르는 순서는 세안→보습제→처방 연고→선크림→파운데이션 순입니다. 피부 화장이 필요하다면 매트한 질감에 살짝 그린톤이 홍조를 가리는 데 효과적이에요. 색조도 아이라이너는 워터프루프 리퀴드보다 펜슬이 낫고, 섀도우는 펄이 많은 것보다 가벼운 제품이 좋아요. 화장품 유통기한도 꼭 확인하시고, 새 화장품은 한 부위에 발라 테스트한 후 괜찮으면 나머지 부위에 쓰시는 게 좋습니다.$AAA$, array['홍조메이크업', '무기자차', '물리적자외선차단제', '매트파운데이션', '그린톤']::text[], 2024, 'oDaK588uBUI-4', 'https://youtu.be/oDaK588uBUI?t=525s', null, '2024-01-04 00:00:00+00'::timestamptz, '2024-01-04 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$MD 보습제는 일반 보습제와 어떻게 다른가요?$AAQ$, $AAA$MD 보습제는 메디컬 디바이스의 약자로 피부가 손상된 부위에 사용하여 피부 장벽을 개선시켜주는 의료기기입니다. **전체적인 성분이 적고 알러지 유발 물질이 적은 편**이라 일반 보습제와 본질적으로 다른 카테고리예요.

대부분의 화장품들이 40개에서 50개 이상의 성분으로 구성되는 데 비해 MD 보습제는 20개 정도로 매우 적은 편이라, **아토피나 피부 건조증, 예민한 피부를 가진 분들에게 안전하게 사용**할 수 있어요. 피부 장벽의 핵심 성분은 세라마이드, 콜레스테롤, 지방산 줄여서 '세콜지'인데, 아토피나 습진처럼 장벽이 손상됐을 때 세콜지가 포함된 보습제를 도포하면 회복에 도움이 됩니다. 피터 엘리아스 교수님 연구에 따르면 어느 한 성분의 비율을 3배로 높이면 회복이 더 가속화된다고 해요. 그래서 닥터 디퍼런트의 311 크림은 세라마이드 비율을, 131 크림은 노화 피부용으로 콜레스테롤 비율을 3배로 높였습니다.$AAA$, array['MD보습제', '세콜지', '세라마이드', '피부장벽', '메디컬디바이스']::text[], 2024, 'hk12NYwjnBk-1', 'https://youtu.be/hk12NYwjnBk?t=58s', null, '2024-01-10 00:00:00+00'::timestamptz, '2024-01-10 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$악건성 피부에 좋은 MD 크림은 어떤 게 있나요?$AAQ$, $AAA$악건성 피부에는 덱시안 MD 크림이 매우 효과적이며, 바세린을 바른 것 같은 꾸덕꾸덕한 질감에 수분 손실을 방지하는 밀폐제 성분이 많이 들어 있습니다. 다른 MD 크림들과 달리 **꾸덕꾸덕하고 끈적끈적한 느낌**이 들고 마치 바세린 같은 사용감이에요.

끈적이고 답답한 것을 싫어하는 분이나 여드름이 잦은 피부에는 사용이 어려울 수 있지만, **너무 건조한 악건성 피부, 손이나 무릎, 팔꿈치 같이 특정 부분이 많이 건조한 경우에는 매우 효과적**입니다. 전성분은 22가지로 예민한 피부에 안심하고 사용할 수 있어 손 습진이 심한 분들에게 핸드크림으로도 권해 드려요. 손 습진이 너무 심해 갈라지고 아플 때는 덱시안을 바르고 일회용 비닐장갑을 낀 다음 10~15분 정도 방치하고 장갑을 벗은 후 티슈로 한번 꾹 눌러 흡수시키고 자는 방법도 효과적입니다. 제로이드 MD크림은 가벼운 제형이라 끈적임을 싫어하는 분이나 여드름 있는 분에게 좋습니다.$AAA$, array['덱시안MD크림', '악건성', '손습진', '밀폐제', '핸드크림']::text[], 2024, 'hk12NYwjnBk-2', 'https://youtu.be/hk12NYwjnBk?t=400s', null, '2024-01-10 00:00:00+00'::timestamptz, '2024-01-10 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$MD 보습제는 어떻게 발라야 효과가 좋나요?$AAQ$, $AAA$MD 보습제는 세안이나 샤워 후 3분 이내, 물기가 날아가기 전에 바로 발라주고 하루에도 여러 번 자주 덧발라주는 것이 가장 중요합니다. 그냥 씻고 대충 바르는 분들은 계속 건조할 수밖에 없어요. **물기가 날아가기 전에 3분 이내에 보습제를 발라주는 것**이 첫 번째 핵심입니다.

두 번째는 하루에도 여러 번 자주 덧바르는 건데요, **피부 장벽이 손상된 경우에는 수분이 금방 날아가서 보습제를 발라도 금방 건조하게 되거든요**. 그래서 보습제를 바르고 한두 시간밖에 안 됐는데도 다시 하얗게 각질이 뜨고 당긴다고 느낄 때마다 자주 도포해주시는 것이 좋습니다. 세 번째로 언제 어디서나 눈앞에 잘 보이게 보습제를 두는 것인데, 가렵고 건조해서 바르려고 해도 막상 눈앞에 없으면 찾다가 귀찮아서 안 바르는 경우가 많기 때문이에요. 사소해 보이지만 꾸준히 해보면 분명 달라진 피부를 느낄 수 있습니다.$AAA$, array['보습제도포법', '3분이내', '덧바르기', '피부장벽손상', '보습루틴']::text[], 2024, 'hk12NYwjnBk-3', 'https://youtu.be/hk12NYwjnBk?t=657s', null, '2024-01-10 00:00:00+00'::timestamptz, '2024-01-10 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$아토베리어와 에스트라 MD 크림은 어떻게 다른가요?$AAQ$, $AAA$아토베리어 MD 크림은 더마온 공법의 소프트 캡슐로 보습력이 뛰어난 대신 전성분이 50개로 많고, 에스트라 MD 크림은 그 단점을 개선해 전성분을 20개로 줄이고 세라마이드 함량을 높여 보습력을 유지한 제품입니다. 아토베리어는 **발림성이 좋고 알갱이가 느껴지는 더마온 공법의 소프트 캡슐**을 통해 보습력을 높였어요.

보습력이 뛰어난 대신 유분감이 있어 지성보다는 건성피부에 더 권해 드리는데, 단점이 전성분이 50개로 많아 **예민한 피부에 사용하기엔 조금 부담스러울 수가 있죠**. 이를 개선한 에스트라 MD 크림은 전성분을 20개로 줄이고 대신 세라마이드 함량을 높여 보습력은 그대로 유지했고, 세라마이드 함량이 높아 조금 꾸덕하다는 느낌이 듭니다. 최근에는 36개월 미만 아이들이 마음 놓고 사용할 수 있는 더마 베이비 프로 크림도 개발됐는데, 소아사용 의료기기 인증을 받았고 혹시 아이 입에 들어가더라도 안전한 성분으로 만들어졌어요.$AAA$, array['아토베리어', '에스트라MD크림', '더마온공법', '세라마이드함량', '더마베이비프로']::text[], 2024, 'hk12NYwjnBk-4', 'https://youtu.be/hk12NYwjnBk?t=343s', null, '2024-01-10 00:00:00+00'::timestamptz, '2024-01-10 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$피부 마이크로바이옴이란 무엇인가요?$AAQ$, $AAA$피부 마이크로바이옴은 눈에 보이지 않지만 피부 속에서 같이 살아가는 균, 바이러스 등 미생물들이 모여서 만들어내는 생태계를 말합니다. **마이크로는 미생물, 바이옴은 생태계라는 뜻**이에요.

유산균이 우리 장 속에 살면서 장을 튼튼하게 해 면역력에 도움을 준다는 건 널리 알려져 있는데, 피부도 마찬가지로 미생물 환경의 영향을 받아 좋아지기도 나빠지기도 합니다. 미세먼지가 심할 때 기관지가 안 좋아지거나 발이 자꾸 물에 젖어 있으면 무좀이 잘 생기는 것처럼, **피부도 눈에 보이지 않는 미생물들의 환경인 마이크로바이옴의 영향**을 받아요. 마이크로소프트 창립자 빌게이츠가 앞으로 세상을 바꿀 성분 3가지 중 하나로 마이크로바이옴을 꼽았을 정도로 핫한 분야이고, 논문 검색 사이트에서 스킨과 마이크로바이옴을 함께 검색하면 5천 개가 넘는 논문들이 검색됩니다.$AAA$, array['피부마이크로바이옴', '피부유산균', '미생물생태계', '장피부축', '마이크로바이옴논문']::text[], 2024, '0w0uYpMJriU-1', 'https://youtu.be/0w0uYpMJriU?t=222s', null, '2024-01-15 00:00:00+00'::timestamptz, '2024-01-15 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$프로바이오틱스와 프리바이오틱스는 어떻게 다른가요?$AAQ$, $AAA$프로바이오틱스는 우리가 먹는 유산균 자체이고, 프리바이오틱스는 그 유산균의 먹이가 되는 성분입니다. 유산균을 먹어서 장 속에 들어갔을 때 먹이가 없으면 죽어버릴 수 있기 때문에 **프로바이오틱스들의 먹이인 프리바이오틱스가 필요**해요.

프리바이오틱스는 주로 식이섬유 같은 성분들이고, 신바이오틱스는 프리바이오틱스와 프로바이오틱스 두 개를 합쳐 놓은 것입니다. **포스트바이오틱스는 우리 몸속에서 어떤 활동을 하고 나서 생긴 부산물들을 얘기**하는데요, 부산물이지만 우리 장내 환경에 좋은 영향을 미친다는 사실이 알려지면서 요즘 각광받고 있어요. 그래서 화자 본인은 프리바이오틱스와 프로바이오틱스가 합쳐진 신바이오틱스 제품을 먹고 있다고 합니다. 유산균 구입 시 상세 페이지에서 이런 용어들이 헷갈렸다면 차이를 알고 자신에게 맞는 형태를 고르시면 됩니다.$AAA$, array['프로바이오틱스', '프리바이오틱스', '신바이오틱스', '포스트바이오틱스', '유산균']::text[], 2024, '0w0uYpMJriU-2', 'https://youtu.be/0w0uYpMJriU?t=347s', null, '2024-01-15 00:00:00+00'::timestamptz, '2024-01-15 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$유산균이 들어 있는 화장품은 어떤 게 있나요?$AAQ$, $AAA$유산균을 직접 화장품에 넣을 수는 없어서 부산물 형태나 프리바이오틱스 형태로 들어간 제품들이 시중에 나와 있습니다. 실제로는 부패 등의 문제 때문에 **화장품에 직접 균을 넣을 수는 없기 때문**에 가공된 형태로 들어가요.

SK-II 피테라 에센스의 첫 번째 성분은 갈락토미세스 발효 여과물로, 갈락토미세스 효모를 발효시킨 다음 정제해서 얻은 물질이라 바를 때 누룩 냄새가 살짝 나죠. 랑콤 어드밴스드 제니피끄 세럼에는 **비피다 발효용해물, 락토바실러스, 효모 추출물** 같은 성분이 들어 있고, 에스티로더 어드밴스드 나이트리페어에도 비피다 발효용해물, 락토바실러스 발효물이 들어 있어요. 라로슈포제 시카플라스트 크림이나 밤에는 프리바이오틱스 복합체가 들어 있어 마찬가지로 살아있는 균은 아니지만 유산균의 먹이가 들어 있는 형태입니다. 마이크로바이옴을 이용한 화장품은 점점 늘고 있는 추세예요.$AAA$, array['갈락토미세스', '비피다발효용해물', '락토바실러스', '프리바이오틱스화장품', '마이크로바이옴화장품']::text[], 2024, '0w0uYpMJriU-3', 'https://youtu.be/0w0uYpMJriU?t=412s', null, '2024-01-15 00:00:00+00'::timestamptz, '2024-01-15 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$피부과 의사의 아침 저녁 루틴은 어떻게 다른가요?$AAQ$, $AAA$아침에는 비타민 앰플과 시카 플라스트 크림 두 가지만 바르고 선크림으로 마무리하며, 저녁에는 레티날 크림이 추가되는 점이 다릅니다. 아침 세안은 약산성 클렌저를 사용하고 **딱 두 가지 정도만 기초로** 바르는데, 비타민 앰플과 라로슈포제 시카 플라스트 크림이에요.

비타민 앰플은 1년 내내 쓰지 않고 여름에 태닝이 많이 됐을 때 피부 항산화 능력을 키우기 위해 사용하는데, CE페룰릭이나 동일하게 비타민C·비타민E·페룰릭 애씨드가 들어간 저렴한 제품을 쓰고 있어요. 영양제로는 유산균(프리바이오틱스 합쳐진 신바이오틱스), 트루바이타민초이스 종합비타민, 코엔자임Q10을 챙겨 먹습니다. **저녁에는 레티날 크림이 추가되고, 잠자기 전 락티움이라는 우유 추출 성분을 먹어 수면의 질을 높이고** 스트레스 완화에 도움을 받아요. 화장품과 영양제 성분이 비타민과 유산균에서 겹치도록 안팎으로 챙기는 것이 핵심입니다.$AAA$, array['피부과의사루틴', '비타민앰플', '레티날크림', '코엔자임Q10', '락티움']::text[], 2024, '0w0uYpMJriU-4', 'https://youtu.be/0w0uYpMJriU?t=55s', null, '2024-01-15 00:00:00+00'::timestamptz, '2024-01-15 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$비타민C 앰플은 피부에 어떤 효과가 있나요?$AAQ$, $AAA$비타민C 앰플은 미백·항산화 효과뿐 아니라 **콜라겐 합성을 유도하는 효과**까지 있는 성분입니다. 기미와 주근깨가 있는 피부에 비타민C를 발랐을 때 색소가 현저히 옅어지고, 꾸준히 바르면 노화된 피부가 매끄러워지면서 주름이 줄어든다는 논문 결과가 있어요.

특히 1987년 듀크대학교 Sheldon Pinnell 교수님이 '아스코르빅 애씨드가 콜라겐의 합성을 유도한다'는 논문을 세계 최초로 발표한 이후로 비타민C 연구가 이어졌습니다. **피부에 콜라겐이 많아지면 탱탱해지고 부드러워지며 주름도 줄어드는 효과**가 나타나죠. 항산화 효과도 함께 있어 손상받은 피부 세포에 발랐을 때 염증과 피부 손상이 줄어든다는 연구 결과도 있어요.$AAA$, array['비타민C앰플', '콜라겐합성', '항산화효과', '미백효과', '주름개선']::text[], 2024, '1sZoEppv0Z8-1', 'https://youtu.be/1sZoEppv0Z8?t=98s', null, '2024-01-18 00:00:00+00'::timestamptz, '2024-01-18 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$CE페룰릭과 CEQ 앰플은 어떻게 다른가요?$AAQ$, $AAA$CE페룰릭과 CEQ는 비타민C 15%·비타민E·페룰릭 애씨드라는 동일한 3가지 성분 조합을 가진 앰플로, 차이는 가격과 부가 성분에 있습니다. CE페룰릭은 30ml에 20만원 중반대인데, **CEQ는 30ml 패키지가 8만원대로 약 3분의 1 가격**이에요.

CEQ에는 이름 그대로 코엔자임Q10이 추가되어 있고 풀러렌, 글루코노락톤이라는 항산화 성분이 함께 들어 있어, **세 가지 핵심 조합이 변하지 않도록 유지시켜 주는 역할**을 합니다. 바나나에 두 제품을 발라 항산화 효과를 비교한 실험에서도 두 제품 모두 비슷하게 색깔이 변하지 않고 잘 유지되는 결과를 보였어요. CEQ는 15ml 용기여서 한 병을 짧은 기간에 사용하게 되니 제품 색상 변화도 더 적은 편이라 가성비를 중시한다면 CEQ가 합리적인 선택입니다.$AAA$, array['CE페룰릭', 'CEQ', '가성비비타민C', '닥터디퍼런트', '스킨수티컬즈']::text[], 2024, '1sZoEppv0Z8-2', 'https://youtu.be/1sZoEppv0Z8?t=450s', null, '2024-01-18 00:00:00+00'::timestamptz, '2024-01-18 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$비타민C 앰플을 바를 때 따가운 이유는 무엇인가요?$AAQ$, $AAA$비타민C 앰플이 따가운 이유는 **pH가 3.0 정도로 산성이기 때문**입니다. 비타민C 성분은 pH 3.5 이하일 때 피부 속으로 침투가 잘 되기 때문에, CE페룰릭과 CEQ도 pH가 3.0 정도로 맞춰져 있어요. 우리 피부의 pH는 4.5에서 5.5 정도이기 때문에 차이가 커서 자극이 느껴질 수 있죠.

특히 피부 컨디션이 좋지 않을 때 바르면 따갑고 오히려 피부가 뒤집어지는 느낌이 날 수 있어요. 그래서 **피부 컨디션이 좋지 않거나 아토피가 있는 분들은 수분크림이나 재생크림으로 피부를 회복시킨 다음에** 사용하시는 게 좋습니다. 바르는 순서는 세럼 제형이라 세안 후 다른 기초를 하기 전 가장 먼저 6-7방울 정도 떨어뜨려 두드려서 흡수시킨 뒤 수분크림을 발라주세요.$AAA$, array['비타민C자극', '산성pH', '민감성피부', '앰플사용법', '아토피']::text[], 2024, '1sZoEppv0Z8-3', 'https://youtu.be/1sZoEppv0Z8?t=586s', null, '2024-01-18 00:00:00+00'::timestamptz, '2024-01-18 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$비타민C 앰플은 아침과 저녁 중 언제 발라야 효과가 좋나요?$AAQ$, $AAA$비타민C 앰플은 **아침과 저녁 모두 사용하는 것이 좋습니다**. 아침에 바르면 자외선이나 유해물질로부터 피부가 손상되는 것을 항산화 작용으로 막아주기 때문에 보호 효과를 누릴 수 있어요.

실제로 바나나 실험을 보면 아무것도 바르지 않은 바나나는 시간이 지날수록 까맣게 변하지만, **비타민C 앰플을 바른 바나나는 색깔이 비교적 그대로 유지되는 모습**을 볼 수 있어요. 이는 비타민C가 피부 주변의 여러 가지 유해물질로부터 손상되는 것을 막아주는 역할과 비슷합니다. 비타민C가 불안정해서 공기와 빛을 만나면 변해버려 기능을 잃는다는 단점이 있지만, 비타민E와 페룰릭 애씨드를 함께 배합하면 안정화가 되어 효과가 잘 유지된다고 알려져 있어요.$AAA$, array['비타민C바르는시점', '아침저녁사용', '자외선보호', '항산화', '안정화']::text[], 2024, '1sZoEppv0Z8-4', 'https://youtu.be/1sZoEppv0Z8?t=748s', null, '2024-01-18 00:00:00+00'::timestamptz, '2024-01-18 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$마데카솔과 병풀추출물 화장품은 어떤 관계인가요?$AAQ$, $AAA$마데카솔의 핵심 성분은 **병풀추출물(센텔라 아시아티카)**이며, 같은 성분이 들어간 화장품을 통해서도 비슷한 재생 효과를 누릴 수 있습니다. 마데카솔 성분표를 보면 센텔라정량추출물과 아시아티코사이드가 표기되어 있는데, 이것이 바로 우리가 흔히 듣는 병풀추출물입니다.

병풀은 피부 상처를 치유하고 재생시키는 효과가 뛰어나 오래전부터 상처 치료에 사용되어 왔어요. 논문에 따르면 병풀추출물은 **상처 부위에 콜라겐 합성, 염증 감소, 항산화, 세균 감소의 4가지 효과**가 있다고 정리되어 있습니다. 마데카솔에는 항생제나 스테로이드가 들어간 종류도 있어 잘 모르고 바르면 피부를 망가뜨릴 수 있어요. 화장품으로 대체하면 편하고 안전하게 마데카솔의 재생 효과를 누릴 수 있습니다.$AAA$, array['마데카솔', '병풀추출물', '센텔라아시아티카', '피부재생', '콜라겐합성']::text[], 2024, 'ka-QoKJHsYY-1', 'https://youtu.be/ka-QoKJHsYY?t=116s', null, '2024-01-26 00:00:00+00'::timestamptz, '2024-01-26 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$마데카소사이드가 들어간 시카크림은 어떤 제품인가요?$AAQ$, $AAA$**마데카소사이드는 병풀추출물의 4가지 유효성분 중 가장 강력한 재생 효과**를 나타내는 성분으로, 라로슈포제 시카플라스트 밤과 닥터디퍼런트 시카메탈 크림에 들어 있습니다. 병풀추출물 안에는 마데카소사이드, 아시아티코사이드, 마데카식애시드, 아시아틱애시드 네 가지 유효성분이 있어요.

네 가지 모두 피부 재생에 효과가 있지만 논문에 따르면 **마데카소사이드가 가장 강력한 효과를 나타낸다고 보고**되어 있어요. 라로슈포제 시카플라스트 밤은 판테놀과 마데카소사이드가 함께 들어가 건조한 시기 밤에 바르면 좋은 제품이고, 닥터디퍼런트 시카메탈 크림은 50ml 49,000원으로 마데카소사이드에 카퍼·징크 같은 금속 이온까지 더해져 피부 회복을 돕습니다. 동국제약 더 마데카 크림과 바이오더마 시카비오, 닥터자르트 시카페어에는 마데카소사이드가 빠져 있어요.$AAA$, array['마데카소사이드', '시카크림', '라로슈포제', '닥터디퍼런트', '피부재생']::text[], 2024, 'ka-QoKJHsYY-2', 'https://youtu.be/ka-QoKJHsYY?t=257s', null, '2024-01-26 00:00:00+00'::timestamptz, '2024-01-26 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$닥터디퍼런트 시카메탈 크림의 금속 이온은 어떤 역할을 하나요?$AAQ$, $AAA$닥터디퍼런트 시카메탈 크림에 들어 있는 **카퍼(구리)와 징크(아연) 이온은 피부 회복 과정에 필요한 금속 이온**으로 작용합니다. 제품 이름의 '메탈'은 바로 이 구리 이온과 아연 이온을 의미해요.

실제 피부과에서 대상포진 환자의 물집이 까져 쓰라리고 아플 때, **구리·아연 이온이 들어간 화장품 크림을 처방하면 발랐을 때 굉장히 빨리 낫는 모습**을 확인할 수 있다고 합니다. 마데카소사이드와 함께 금속 이온이 더해져 피부 회복을 돕는 구조죠. 사용감은 일반 수분크림 정도의 점도여서 데일리로 쓰기 좋았고, 추운 곳에서 손이 텄을 때 핸드크림보다 빠르게 좋아지는 재생력을 보였습니다. 단점은 50ml에 49,000원으로 비교 5종 중 두 번째로 비싼 가격이에요.$AAA$, array['시카메탈크림', '구리아연', '금속이온', '피부회복', '닥터디퍼런트']::text[], 2024, 'ka-QoKJHsYY-3', 'https://youtu.be/ka-QoKJHsYY?t=537s', null, '2024-01-26 00:00:00+00'::timestamptz, '2024-01-26 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$시카크림은 데일리와 나이트 중 어떻게 골라야 하나요?$AAQ$, $AAA$**데일리용은 가벼운 점도의 동국제약 더 마데카 크림과 닥터디퍼런트 시카메탈**, 나이트용은 라로슈포제 시카플라스트 밤과 닥터자르트 시카페어가 적합합니다. 본인의 피부 상태와 시간대에 따라 골라 사용하면 좋아요.

동국제약 더 마데카 크림은 키엘 수분크림과 비슷한 점도여서 아침 메이크업 후에도 피부가 편안하게 유지됩니다. 닥터디퍼런트 시카메탈도 일반 수분크림 정도라 데일리로 부담이 없어요. 반면 **라로슈포제 시카플라스트 밤은 밤에 듬뿍 바르면 다음날 광나는 느낌**이 있고, 바이오더마 시카비오 포마드 크림은 100ml 37,000원으로 가장 저렴하지만 굉장히 끈적해서 레이저 후나 장벽이 깨졌을 때 쓰기 좋습니다. 닥터자르트 시카페어는 50ml 5만원으로 가장 비싼데 매트한 사용감이 있어 저녁용으로 적합해요.$AAA$, array['시카크림선택', '데일리크림', '나이트크림', '수분크림', '피부타입']::text[], 2024, 'ka-QoKJHsYY-4', 'https://youtu.be/ka-QoKJHsYY?t=698s', null, '2024-01-26 00:00:00+00'::timestamptz, '2024-01-26 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$두피 스파나 ASMR 마사지가 두피 건강에 정말 도움이 되나요?$AAQ$, $AAA$두피가 건강한 상태라면 가끔 기분 전환용으로 마사지를 받아도 괜찮지만, **두피가 건조·가렵고 빨갛거나 각질이 일어나는 경우에는 권고드리지 않습니다**. 일시적으로 두피가 깨끗해 보일 수 있어도 근본 문제는 해결되지 않기 때문입니다.

오히려 **물리적 자극이 두피 컨디션을 만성화시키고 악화시킬 수가** 있어요. 머리를 감을 때도 비듬을 없애려고 세게 긁어내는 분들이 많은데, 이렇게 마찰을 주면 일종의 악순환처럼 더 심해질 수 있습니다. 머리는 뜨거운 물보다 미온수로 감고, 거품을 충분히 내서 손톱 말고 손가락 끝으로 살살 마사지하듯 3분에서 5분 이내로 감는 것이 권장됩니다. 두피도 피부이기 때문에 자극을 최소화하는 관리가 핵심이에요.$AAA$, array['두피마사지', '두피스파', '두피자극', '비듬관리', '머리감는법']::text[], 2024, '-D_igIpeQu4-1', 'https://youtu.be/-D_igIpeQu4?t=36s', null, '2024-02-01 00:00:00+00'::timestamptz, '2024-02-01 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$비듬의 원인은 무엇이고 위생과 관련이 있나요?$AAQ$, $AAA$비듬은 **피부에서 탈락된 각질 덩어리**로 위생과는 상관이 없으며, 원인은 크게 세 가지로 나뉩니다. 머리를 정말 안 감으면 심해질 수 있지만 깨끗이 감아도 생길 수 있는 게 비듬이에요.

첫째, **두피가 너무 건조하거나 너무 기름져도 생길 수 있는데**, 하얗게 떨어지는 비듬은 대부분 건조해서 일어나는 경우입니다. 겨울에 피부가 트듯이 두피도 마른 땅처럼 변하면서 각질이 일어나죠. 둘째는 염증으로, 두피에 지루피부염이나 건선, 다양한 습진이 생기면 염증 반응이 심해지면서 각질이 일어납니다. 셋째는 미생물 영향이에요. 두피처럼 피지샘이 많은 곳을 좋아하는 균의 개체수가 늘어나거나 외부에서 곰팡이균이 옮으면 각질이 심해질 수 있습니다.$AAA$, array['비듬원인', '두피건조', '지루피부염', '두피염증', '각질']::text[], 2024, '-D_igIpeQu4-2', 'https://youtu.be/-D_igIpeQu4?t=78s', null, '2024-02-01 00:00:00+00'::timestamptz, '2024-02-01 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$건조하고 각질 있는 두피에 보습제를 어떻게 발라야 하나요?$AAQ$, $AAA$**두피가 건조해서 갈라지고 각질이 일어나는 경우 두피 전용 보습제를 가르마를 따라 발라 톡톡 두드려 흡수**시켜 주세요. 두피도 피부이기 때문에 얼굴처럼 보습 관리가 필요합니다.

제로이드 루트힐 모이스처라이저 같은 두피용 보습제 제품이 나와 있는데, MD 제품으로 의료기기 분류이며 달맞이꽃오일·글리세린·판테놀·히알루론산 같은 보습 성분이 들어 있어요. 또 **징크글루코네이트라는 항염 작용과 균·피지를 잡아주는 성분**도 포함됩니다. 사용법은 입구가 길게 되어 있어 세워서 가르마를 따라 쭉 짜준 뒤 톡톡 두드려 흡수시키면 됩니다. 두피에 연고 처방을 받은 경우라면 보습제를 먼저 발라 촉촉하게 한 후 염증이 심한 곳엔 스테로이드, 뾰루지엔 항생제 연고를 바르는 순서가 좋아요.$AAA$, array['두피보습제', '제로이드루트힐', '징크글루코네이트', '두피건조', '보습관리']::text[], 2024, '-D_igIpeQu4-3', 'https://youtu.be/-D_igIpeQu4?t=192s', null, '2024-02-01 00:00:00+00'::timestamptz, '2024-02-01 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$약용 샴푸와 일반 비듬 샴푸는 어떻게 다른가요?$AAQ$, $AAA$**약용 샴푸는 미생물 억제 항균 성분이 들어간 의약품 샴푸**이고, 일반 비듬 샴푸는 시중에서 구매 가능한 기능성 제품입니다. 두피 컨디션에 따라 골라 사용하는 것이 중요해요.

약용 샴푸에는 니조랄·나졸액·케이프록스액·토피록스액 같은 항진균 샴푸가 있고, 클로벡스·듀오벡스 같은 스테로이드 샴푸도 있어요. 사용법은 두피를 적시고 일정량을 골고루 바른 뒤 **3분에서 5분 정도 두었다가 씻어내며 항진균과 스테로이드 샴푸를 번갈아 쓰는 것**이 만성 염증 조절에 효과적입니다. 일반 시중 제품으로는 헤드앤숄더에 피록톤 올아민이라는 진균 억제 성분이 들어 있고, 징크피리치온·셀레늄 솔파이드·살리실릭 애씨드는 항균·항염증 작용과 과도한 각질 탈락을 돕는 성분이에요. 멘톨·페퍼민트는 함유량이 높으면 자극이 될 수 있으니 너무 시원한 것만 찾는 건 좋지 않습니다.$AAA$, array['약용샴푸', '니조랄', '비듬샴푸', '피록톤올아민', '징크피리치온']::text[], 2024, '-D_igIpeQu4-4', 'https://youtu.be/-D_igIpeQu4?t=292s', null, '2024-02-01 00:00:00+00'::timestamptz, '2024-02-01 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$목주름 예방을 위한 홈케어 방법은 어떤 것이 있나요?$AAQ$, $AAA$목주름 예방 홈케어는 **얼굴 화장품 목까지 바르기, 목 스트레칭, 비타민C·A·선크림 도포** 세 가지가 핵심입니다. 얼굴에는 좋은 앰플과 크림을 열심히 바르면서 목은 소홀히 하시는 분들이 많은데, 저녁 세안 후 얼굴에 바르고 남은 크림을 손에 발라 없애지 말고 목에도 발라주세요.

주말에는 **보습제를 바른 후 따뜻한 물에 적신 수건을 목에 5분 정도 올려두면 보습 효과**가 좋아져요. 그 후 보습제를 톡톡 두드려 흡수시키면 됩니다. 스트레칭은 목 근육이 세로 방향이라 가로 주름이 잘 생기는 만큼 반대로 턱을 위로 당겨주는 동작을 핸드폰 사용 후 보상처럼 해주세요. 비타민C 앰플은 항산화 효과를 위해 아침에, 비타민A 크림은 자극이 될 수 있어 저녁에 바르고, 선크림은 얼굴뿐 아니라 목까지 골고루 발라주는 게 중요합니다.$AAA$, array['목주름홈케어', '목스트레칭', '보습제', '비타민C', '선크림']::text[], 2024, 'wFSVmqCdt5w-1', 'https://youtu.be/wFSVmqCdt5w?t=82s', null, '2024-02-08 00:00:00+00'::timestamptz, '2024-02-08 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$스티바A 크림으로 깊은 목주름이 좋아질 수 있나요?$AAQ$, $AAA$스티바A 크림은 얇은 잔주름에는 도움이 되지만 **깊은 가로 목주름에는 5년 정도 발라도 한계가 있습니다**. 영상 속 김종식 원장님도 5년간 꾸준히 발랐지만 깊은 주름까지는 없어지지 않더라고 솔직하게 말씀하세요.

**스티바A 크림은 얇은 잔주름과 피부결 개선에는 꾸준히 바르면 좋아지는 효과**가 있지만, 깊은 주름은 좀 부족한 느낌이 있어요. 목주름의 가로 주름은 사실 타고난 영향이 가장 크기 때문에 홈케어로 한계가 있을 수 있어요. 노화나 구부정한 자세, 휴대폰을 자주 보는 테크 라인 등이 원인이 되는데, 원인을 알면 예방은 가능하지만 이미 깊게 새겨진 주름은 다른 접근이 필요합니다. 이런 경우엔 필러 시술을 고려하는 것이 솔직한 답이 될 수 있어요.$AAA$, array['스티바A크림', '목주름한계', '트레티노인', '깊은주름', '잔주름']::text[], 2024, 'wFSVmqCdt5w-2', 'https://youtu.be/wFSVmqCdt5w?t=732s', null, '2024-02-08 00:00:00+00'::timestamptz, '2024-02-08 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$목주름 필러 시술의 효과는 얼마나 오래가나요?$AAQ$, $AAA$목주름 필러는 **1년이 지나도 효과가 잘 유지되며, 심지어 2년까지 효과가 지속되는 경우**도 논문으로 확인됩니다. 시술 후 2개월과 1년 사진을 비교했을 때 1년이 지나도 유지가 잘 되고, 2개월보다 1년 뒤가 오히려 더 좋아지는 모습도 볼 수 있어요.

실제 논문 사진에서는 **2년이 지나도 가로 주름 부위는 잘 유지되는 모습**을 보여주는데, 주변 피부는 2년 동안 전체적으로 노화됐지만 필러 시술 부위만은 유지력이 좋다는 점이 흥미롭습니다. 시술은 앉아서 진행하는데 누우면 목이 펴져 주름이 잘 안 보이기 때문이에요. 통증은 윤곽주사나 보톡스의 반의 반 정도라 마취크림만 발라도 충분히 참을 수 있고, 엠보싱은 길면 일주일 짧으면 2-3일이면 사라집니다. 멍이 들 수 있어 목폴라를 입을 수 있는 겨울에 시술하는 게 좋아요.$AAA$, array['목주름필러', '필러지속기간', '필러효과', '가로주름필러', '필러통증']::text[], 2024, 'wFSVmqCdt5w-3', 'https://youtu.be/wFSVmqCdt5w?t=387s', null, '2024-02-08 00:00:00+00'::timestamptz, '2024-02-08 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$목주름 필러는 어떤 성질의 필러를 써야 하나요?$AAQ$, $AAA$목주름 필러는 **반드시 퍼지는 성질의 필러를 사용해야 합니다**. 뭉치는 성질의 필러를 쓰면 엠보싱이 오래가거나 안 없어지는 일이 생길 수 있어요.

필러는 크게 뭉치는 성질과 퍼지는 성질로 나뉘는데, **코나 턱처럼 모양을 만드는 부위에는 뭉치는 필러가 적합**하지만 목주름처럼 얕고 가로로 긴 주름을 채울 때는 정반대가 필요합니다. 만약 코에 퍼지는 성분의 필러를 쓰면 아바타처럼 퍼져버리고, 목에 뭉치는 필러를 쓰면 엠보싱이 오래 남아 다시 녹여야 하는 일이 생길 수 있어요. 영상 속 원장님도 그런 경험 때문에 몇 번 필러를 다시 녹여본 적이 있다고 합니다. 작은 용량으로도 볼륨이 잘 채워지므로 많은 용량을 시술하지 않아도 되며, 필러의 물성을 잘 선택하는 것이 중요해요.$AAA$, array['목주름필러물성', '퍼지는필러', '뭉치는필러', '필러선택', '엠보싱']::text[], 2024, 'wFSVmqCdt5w-4', 'https://youtu.be/wFSVmqCdt5w?t=470s', null, '2024-02-08 00:00:00+00'::timestamptz, '2024-02-08 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$히알루론산 성분은 피부에 어떤 효과가 있나요?$AAQ$, $AAA$히알루론산은 **수분을 자기 몸보다 1000배 정도까지 함유할 수 있는 성분**으로 보습 효과가 핵심입니다. 우리 몸에 실제로 존재하는 성분이며 피부뿐 아니라 관절·뼈·안구에서도 세포 구조를 이루는 데 중요한 역할을 해요.

다만 **콜라겐 재생과 리프팅 효과 광고는 과장된 면**이 있고, 실제로는 보습·항염 효과가 주된 기능이에요. 히알루론산은 물을 끌어당겨 습윤 효과를 내는 것 외에 항염 효과로 염증을 좋아지게 하는 작용도 있어, 여드름·지루성 피부염·아토피 피부염처럼 염증이 많거나 민감한 피부에도 도움이 됩니다. 화장품으로 콜라겐 재생이나 리프팅 효과까지 기대하기보다는 촉촉하고 전반적으로 광이 나는 보습 효과 정도로 이해하면 정확해요. 피부과 시술이나 관절 주사, 안약 성분으로도 폭넓게 활용되는 안전한 성분이죠.$AAA$, array['히알루론산', '보습효과', '항염효과', '수분유지', '피부진정']::text[], 2024, '9NopfxHDdr8-1', 'https://youtu.be/9NopfxHDdr8?t=90s', null, '2024-02-15 00:00:00+00'::timestamptz, '2024-02-15 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$고분자량과 저분자량 히알루론산은 어떻게 다른가요?$AAQ$, $AAA$**저분자량 히알루론산은 표피 아래쪽까지 투과되는 반면, 고분자량은 표면에 남아 수분을 끌어당기는 역할**을 합니다. 두 가지가 적절히 배합된 제품을 고르는 것이 가장 좋아요.

피부에는 500달톤 룰이 있어 분자량 500달톤 이상은 투과가 어려운데, **히알루론산은 많게는 몇 백만 달톤에 이를 정도로 분자량이 큰 물질**이에요. 연구결과를 보면 고분자량은 표피에서 거의 통과를 못하지만, 저분자량은 일반적인 표피 두께인 80마이크로미터 정도까지 충분히 투과합니다. 고분자량은 피부 표면에서 주변 물을 끌어당겨 광채 효과를 내고, 아토피처럼 각질층이 무너진 경우 바깥에서 수분을 잡아주는 역할이 중요해요. 진피 속까지는 저분자량도 투과하지 못하므로 화장품의 한계를 이해하고 사용하는 것이 좋습니다.$AAA$, array['저분자히알루론산', '고분자히알루론산', '분자량', '표피투과', '500달톤']::text[], 2024, '9NopfxHDdr8-2', 'https://youtu.be/9NopfxHDdr8?t=180s', null, '2024-02-15 00:00:00+00'::timestamptz, '2024-02-15 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$히알루론산 화장품을 고를 때 전성분표는 어떻게 봐야 하나요?$AAQ$, $AAA$**전성분표에서 분자량별 히알루론산 성분명을 구분**해서 확인하면 됩니다. 화장품 성분명은 한국어가 아니라 영어식 표기로 기재되어 있어 처음 보면 어려워 보이지만, 분자량 크기별로 분류가 가능해요.

**고분자 히알루론산은 소듐하이알루로네이트 크로스폴리머와 소듐하이알루로네이트**라고 표기되어 있고, 중분자는 하이드록시프로필트라이모늄 하이알루로네이트와 소듐아세틸레이티드 히알루로네이트가 해당됩니다. 저분자는 포타슘하이알루로네이트, 하이드롤라이즈드 하이알루로닉애씨드, 하이드롤라이즈드소듐 하이알로네이트가 대표적이고, 가장 분자량이 작은 하이알루로닉애씨드도 저분자량에 속해요. 저분자량만 잔뜩 든 제품보다는 고분자·저분자가 적절히 배합된 제품이 표면 광채와 표피 침투 두 가지 효과를 모두 누릴 수 있어 가장 이상적입니다.$AAA$, array['전성분표', '소듐하이알루로네이트', '히알루론산표기', '화장품성분', '분자량분류']::text[], 2024, '9NopfxHDdr8-3', 'https://youtu.be/9NopfxHDdr8?t=309s', null, '2024-02-15 00:00:00+00'::timestamptz, '2024-02-15 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$인공눈물을 피부에 발라도 되나요?$AAQ$, $AAA$인공눈물에는 **순도가 높은 저분자 히알루론산이 들어 있어 피부에 발라도 안전**하지만, 전문의약품이라 활용에는 번거로움이 있습니다. 눈에 넣어도 될 정도로 안전하고 흡수도 잘 되며 화장품 원료보다 순도가 높아요.

인공눈물을 넣다가 눈가에 흐른 것을 휴지로 닦아내지 말고 **톡톡 두드려 흡수시키면 오히려 피부에 좋을 수 있어요**. 다만 처방을 받기 위해 안과 진료 후 약국에서 구매해야 하는 번거로움이 있고, 순수 히알루론산 성분만 들어 있는 인공눈물을 찾기도 어려우며 알 수 없는 성분이 포함될 수 있는 위험성이 있어요. 이런 점을 다 감수하면서 굳이 처방받아 바를 필요가 있을까 하는 생각이 들 정도라, 일반 히알루론산 화장품을 사용하는 것이 더 합리적인 선택이 될 수 있습니다.$AAA$, array['인공눈물피부', '저분자히알루론산', '전문의약품', '안전성', '가성비']::text[], 2024, '9NopfxHDdr8-4', 'https://youtu.be/9NopfxHDdr8?t=242s', null, '2024-02-15 00:00:00+00'::timestamptz, '2024-02-15 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$MTS 시술은 어떤 원리로 피부에 효과를 내나요?$AAQ$, $AAA$MTS는 **마이크로니들 테라피 시스템의 약자로 미세한 바늘로 피부에 작은 상처를 내어 회복 과정에서 콜라겐을 형성**시키는 시술입니다. 1995년 미국의 성형외과 의사가 미세한 바늘로 피부에 상처를 내고 치료에 사용한 것이 시작이에요.

**엄청 얇은 바늘로 미세한 상처만 내면 회복 과정에서 콜라겐이 형성되고 피부가 재생**되면서 모공이 좋아지고 염증·여드름이 개선되며 탄력이 생깁니다. 피부과에서는 미세한 상처를 낸 뒤 좋은 성분을 두드려 넣으면 더 효과가 좋다는 점을 응용해 발전시켜 왔어요. 히알루론산처럼 분자량이 커서 피부에 침투가 어려운 성분도 MTS를 통해 침투력을 높일 수 있어, 단순히 앰플을 바르기만 하는 것보다 확실히 효과가 있는 시술 방식입니다.$AAA$, array['MTS', '마이크로니들', '콜라겐형성', '피부재생', '성분침투']::text[], 2024, 'kVGDrxCgZnE-1', 'https://youtu.be/kVGDrxCgZnE?t=70s', null, '2024-02-22 00:00:00+00'::timestamptz, '2024-02-22 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$가정용 MTS와 병원용 MTS는 어떻게 다른가요?$AAQ$, $AAA$가정용은 **0.25mm짜리 표피용**, 병원용은 **0.75mm 짜리 깊은 침투용**으로 침투 깊이와 통증 정도에서 차이가 큽니다. 표피층은 0.1mm도 안 되므로 0.25mm짜리의 반만 들어가도 표피에 충분한 자극을 줄 수 있어요.

가정용 0.25mm는 별로 안 아프고 여러 번 문지르면 약간 살짝 홍반이 생기는 정도가 적당합니다. **너무 과하게 욕심내서 피나게 문지르거나 자극하지 말고**, 살짝 따끔하다 싶을 정도가 좋아요. 반면 병원용 0.75mm는 마취크림 없이는 엄청 아프고, 제대로 문지르면 피가 조금 나는데 이것이 가장 큰 차이입니다. 표피에는 혈관이 없어 피가 안 나지만 진피층에는 혈관이 있어 깊이 들어가면 피가 날 수 있죠. 사용 시에는 피부에 붙은 채로 옮기지 말고 떼어내고 부위를 옮겨 문지르는 것이 중요해요.$AAA$, array['MTS깊이', '가정용MTS', '병원용MTS', '0.25mm', '표피두께']::text[], 2024, 'kVGDrxCgZnE-2', 'https://youtu.be/kVGDrxCgZnE?t=150s', null, '2024-02-22 00:00:00+00'::timestamptz, '2024-02-22 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$MTS 시술을 절대 받으면 안 되는 사람은 누구인가요?$AAQ$, $AAA$**피부가 민감하거나 트러블이 잘 생기는 분들은 MTS를 사용하지 않는 것이 좋습니다**. 피부 장벽 자체가 좋지 않은 상태에서 MTS는 위험할 수 있어요.

**MTS 시술 자체가 피부 장벽을 일부러 살짝 무너뜨렸다가 회복시키는 시술**이기 때문에, 원래 장벽이 약한 분이라면 회복이 어렵고 트러블이 더 심해질 수 있습니다. 여행을 갔다 와서 자외선을 많이 봐서 피부가 안 좋을 때도 사용하지 않는 것이 좋아요. 사용 빈도는 일주일에 한 번이나 한 달에 1-2회 정도가 적당하며, 살짝 자극을 줘서 침투시켰으면 피부가 회복할 시간을 충분히 줘야 해요. 또한 집에서 완벽한 무균 상태를 만들기 어렵기 때문에 일회용 제품을 쓰거나 알코올로 소독해야 하며, 트러블이나 염증이 생기면 피부과 치료가 필요할 수 있습니다.$AAA$, array['MTS금기', '민감성피부', '피부장벽', '사용빈도', 'MTS소독']::text[], 2024, 'kVGDrxCgZnE-3', 'https://youtu.be/kVGDrxCgZnE?t=399s', null, '2024-02-22 00:00:00+00'::timestamptz, '2024-02-22 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$MTS 후에는 어떤 성분의 앰플을 발라야 하나요?$AAQ$, $AAA$**MTS 후에는 피부 고민에 맞는 유효 성분을 바른 뒤 진정 효과가 좋은 밤 타입 크림으로 마무리**하는 것이 좋습니다. 자극을 받은 직후라 진정 케어가 필수예요.

색소나 기미가 고민이라면 **나이아신아마이드·트라넥사믹애씨드 성분이 든 디스컬러레이션 디펜스 같은 제품**이 효과적이고, 항산화 효과를 원한다면 비타민C·E·페룰릭 애씨드가 함께 든 CE페룰릭이 도움이 됩니다. 보습이나 푸석함이 고민이라면 히알루론산 앰플, 탄력이나 주름 개선이 목표라면 아데노신이나 펩타이드 성분이 효과를 줄 수 있어요. 바른 후에는 시카 성분이 들어간 두꺼운 밤 타입 보습제를 살짝 덮듯이 발라주거나 마스크팩을 올리는 것도 좋은데, 에센스 성분이 너무 많이 든 제품은 따가울 수 있으니 주의가 필요합니다.$AAA$, array['MTS앰플', '나이아신아마이드', '트라넥사믹애씨드', 'MTS후관리', '시카밤']::text[], 2024, 'kVGDrxCgZnE-4', 'https://youtu.be/kVGDrxCgZnE?t=313s', null, '2024-02-22 00:00:00+00'::timestamptz, '2024-02-22 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$백반증은 어떤 질환이고 왜 발생하나요?$AAQ$, $AAA$백반증은 **피부의 멜라닌 세포를 자기 면역세포가 공격해 색소세포가 소실되어 피부 곳곳이 하얗게 변하는 자가면역 질환**입니다. 우리나라 사람 100명 중 한 명이 고통받고 있을 정도로 흔한 질환이에요.

자가면역이란 **나의 면역세포가 나의 일부를 침입자로 규정하고 공격하는 비정상적인 면역 반응**을 말합니다. 공격하는 세포에 따라 류마티스 관절염, 염증성 장질환, 갑상선 기능 항진증 등 다양한 자가면역 질환이 발생하며 백반증도 그중 하나죠. 그래서 면역력을 올린다는 인삼이나 홍삼은 오히려 백반증에 좋지 않다는 점이 중요해요. 비정상적인 자가면역 반응을 떨어뜨려 줘야 치료가 되기 때문입니다. 백인 피부는 원래 하얘서 티가 잘 나지 않아 서양에서는 대수롭지 않게 여기는 경향이 있어 신약 개발이 더디게 진행되어 왔어요.$AAA$, array['백반증', '자가면역질환', '멜라닌세포', '색소소실', '면역억제']::text[], 2024, 'cZXZ88wUgeY-1', 'https://youtu.be/cZXZ88wUgeY?t=153s', null, '2024-02-29 00:00:00+00'::timestamptz, '2024-02-29 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$백반증 자외선 치료와 엑시머 레이저는 어떻게 다른가요?$AAQ$, $AAA$전신 자외선 치료는 큰 원통부스에서 전신을 치료하고, **엑시머 레이저와 팔라스 레이저는 작은 부위만 골라 치료**할 수 있는 차이가 있습니다. 311nm 주변 파장은 화상 위험이 적으면서 면역 반응을 효과적으로 억제해요.

전신 자외선 치료는 **주 2-3회 반복하며 피부가 선홍색이 될 때까지 에너지를 증량하는 방식으로 6개월에서 1년 이상 장기 치료**가 필요한 경우가 많습니다. 치료 초기 반응은 적어도 1개월 이상, 보통 2-3개월 이후 관찰되며 경우에 따라 6개월 이후에 나타나기도 해요. 단점은 작은 병변에도 전신을 치료해야 한다는 점과 큰 원통에 혼자 들어가기 어려운 어린 아이들의 치료가 곤란하다는 점입니다. 반면 엑시머 레이저는 부위별로 에너지 조절이 가능하고 통증이 없어 갓난 아기도 어려움 없이 치료할 수 있으며 더 빠르게 효과가 나타나요.$AAA$, array['백반증자외선치료', '엑시머레이저', '311nm파장', '전신광선치료', '백반증치료기간']::text[], 2024, 'cZXZ88wUgeY-2', 'https://youtu.be/cZXZ88wUgeY?t=234s', null, '2024-02-29 00:00:00+00'::timestamptz, '2024-02-29 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$백반증 치료에 프로토픽 연고는 얼마나 효과적인가요?$AAQ$, $AAA$프로토픽 연고 단독 요법은 메타분석 결과 **18%의 치료 효과**를 보였으며, 얼굴 백반증에서는 **65%의 환자에게 단독으로도 효과**가 있다고 보고됩니다. 스테로이드가 들어있지 않은 비스테로이드성 면역 억제 연고로 널리 사용돼요.

특히 **엑시머 레이저 치료에 프로토픽 연고를 하루 2회 함께 발랐을 때 치료 성공률을 2배가량 높이고 실패율을 절반으로 줄일 수 있었다**는 연구가 있습니다. 치료가 어려운 손과 발 백반증도 엑시머 단독으로는 거의 치료되지 않지만 프로토픽을 병행하면 의미 있는 결과가 나와요. 또한 치료 종결 후에도 백반증이 있던 부위에 프로토픽을 지속적으로 바르면 재발률을 40%에서 10%까지 줄일 수 있습니다. 처음 바를 때 화끈거리는 작열감이 있지만 대부분 2주 내에 사라지며, 도포 부위에 여드름·모낭염이 생기면 가라앉을 때까지 도포를 중단해야 해요.$AAA$, array['프로토픽연고', '타크로리무스', '백반증연고', '엑시머병용', '재발예방']::text[], 2024, 'cZXZ88wUgeY-3', 'https://youtu.be/cZXZ88wUgeY?t=549s', null, '2024-02-29 00:00:00+00'::timestamptz, '2024-02-29 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$백반증 스테로이드 연고는 어떻게 사용해야 하나요?$AAQ$, $AAA$백반증 치료 스테로이드 연고는 **강한 스테로이드를 단기간 짧게 쓰고 끊는 것이 약한 스테로이드를 장기 사용하는 것보다 효과적**입니다. 약한 강도는 백반증에 효과가 거의 없다고 밝혀져 있어요.

스테로이드 연고는 크게 **7단계의 강도로 나뉘는데 강한 스테로이드만 효과가 있는 것**으로 보고됩니다. 다만 부위에 따라 사용을 피해야 할 곳이 있는데, 눈 주변은 안압을 올릴 수 있어 사용하지 않는 것이 좋고, 겨드랑이나 사타구니처럼 피부가 연한 부분은 쉽게 틀 수 있어 피해야 해요. 오래 사용하면 피부가 푸석푸석해지고 얇아지며 혈관이 발달하고 내성이 생겨 효과가 떨어질 수 있어 장기 도포는 권장되지 않습니다. 또한 연고는 하얀 곳만 골라 바르지 말고 주변으로 넓게 도포하는 것이 새 병변 예방에 도움이 되며, 특히 손끝·손마디·손등 백반증은 전체에 도포하는 것이 권장돼요.$AAA$, array['백반증스테로이드', '강한스테로이드', '스테로이드부작용', '연고도포법', '단기치료']::text[], 2024, 'cZXZ88wUgeY-4', 'https://youtu.be/cZXZ88wUgeY?t=386s', null, '2024-02-29 00:00:00+00'::timestamptz, '2024-02-29 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$백반증에 먹는 약은 어떻게 복용하나요?$AAQ$, $AAA$백반증이 번지는 경우 **스테로이드 경구약을 체중에 맞춰 처방하며, 2주에서 6개월 이상 복용하기도 합니다**. 자가면역 반응이 전신적으로 일어나는 상태이기 때문에 경구약으로 막아야 해요.

스테로이드는 효과적인 면역 억제 호르몬제이지만 장기 복용 시 **몸이 붓고 체중이 증가하거나 위염·골밀도 감소 같은 부작용**이 발생할 수 있어요. 이를 피하면서 효과를 유지하기 위해 다양한 주기요법이 발달했는데, 가장 일반적인 방법은 처음 2주는 매일 복용하고 이후엔 토요일과 일요일 아침에만 복용하는 미니펄스 요법입니다. 즉 이틀 먹고 5일 쉬는 방식이에요. 당뇨나 골다공증이 심해 스테로이드 사용이 어려운 경우 몇 가지 대체 약도 있으니 주치의와 상의해 결정하는 것이 좋아요. 1-2알로는 조절이 잘 되지 않아 체중 기반 처방이 필요합니다.$AAA$, array['백반증경구약', '스테로이드복용', '미니펄스요법', '면역억제제', '백반증진행']::text[], 2024, 'cZXZ88wUgeY-5', 'https://youtu.be/cZXZ88wUgeY?t=649s', null, '2024-02-29 00:00:00+00'::timestamptz, '2024-02-29 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$백반증 피부이식 수술은 언제 결정하나요?$AAQ$, $AAA$피부이식 수술은 **백반증이 1년 이상 커지지 않고 새 병변이 생기지 않은 안정화 상태일 때 결정**합니다. 솜털이 하얗게 변한 백모가 잔뜩 생긴 경우엔 다른 치료가 어려워 이식이 필요해요.

수술법은 본인의 다른 피부에서 색소세포를 가져오는 방식인데, 최근에는 **0.5mm-0.8mm의 작은 펀치로 정상피부를 얻어 백반증 부위에 심어주는 SST 미세펀치 이식술**이 널리 시행됩니다. 넓은 면적은 피부를 세포 단위로 분리해 한꺼번에 수술하는 세포이식 방법을 사용해요. 다만 부분 이식이라 심어진 색소세포가 주변으로 퍼지려면 수술 후 자외선 치료나 엑시머 레이저가 필요합니다. 새로 생기거나 번지는 상태에서는 수술해도 효과가 좋지 않으므로 시기 결정이 중요하며, 환자의 나이·백반증 종류·크기·위치에 따라 성공률과 부작용 위험이 다르니 경험 있는 피부과 전문의와 상의해야 해요.$AAA$, array['백반증이식수술', '미세펀치이식', '세포이식', '안정화상태', 'SST']::text[], 2024, 'cZXZ88wUgeY-6', 'https://youtu.be/cZXZ88wUgeY?t=706s', null, '2024-02-29 00:00:00+00'::timestamptz, '2024-02-29 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$스티바A 크림 단종 후 대체할 수 있는 레티노이드 제품은 무엇이 있나요?$AAQ$, $AAA$스티바A 크림 단종 시 대체 후보로는 디페린, 아크리프, 투앤티, 비타리프트A 크림이 있습니다. 이들은 모두 비타민A 유도체인 레티노이드 계열로, 각질세포 턴오버를 빠르게 해 피부결을 매끈하게 하고 콜라겐 합성을 유도해 탄력을 개선해요. 세대별로는 트레티노인이 1세대, 디페린의 아다팔렌이 3세대, **아크리프의 트리파로텐이 4세대 레티노이드**입니다.

투앤티 크림은 스티바A와 유효성분이 완전히 동일한 1세대 레티노이드이고, 디페린은 미국에서 OTC로 판매될 만큼 대중화된 3세대로 좀 더 마일드한 편입니다. 아크리프는 가장 최근에 나온 신약으로, 2019년 미국 FDA에서 9세 이상 얼굴과 몸의 여드름 치료제로 승인을 받았어요. 비타리프트A 크림은 전문의약품이 아닌 화장품으로, **레티날 성분이 피부에서 레티노산으로 전환되어** 레티노이드 효과를 내며 자극이 가장 적습니다.$AAA$, array['스티바A', '레티노이드', '대체제', '디페린', '아크리프', '비타리프트A']::text[], 2024, 'GnzkIDdyxtc-1', 'https://youtu.be/GnzkIDdyxtc?t=118s', null, '2024-03-04 00:00:00+00'::timestamptz, '2024-03-04 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$디페린 크림은 어떤 피부 타입에 잘 맞나요?$AAQ$, $AAA$디페린은 피지 분비가 많은 지성피부나 여드름이 잘 생기는 분에게 잘 맞는 3세대 레티노이드입니다. 아다팔렌 0.1%를 주 유효성분으로 하며, **친유성이 높아서** 유분기에 친화적인 성질을 갖고 있어요. 그래서 피지 분비가 많거나 여드름이 종종 나는 분이 홈케어로 피부결까지 개선하고 싶을 때 효과가 좋습니다.

제형 선택도 피부 타입에 따라 다르게 권해 드려요. 지성피부는 산뜻한 겔 타입이 좋고, 건성피부는 크림 타입이 더 적합합니다. 한 연구에서는 128명을 대상으로 **디페린 0.3%와 트레티노인 0.05%를 24주간 하루 한 번 발라 비교했을 때** 눈가 주름·이마주름·색소에서 비슷한 개선 효과를 보였어요. 스티바A에 비해 확실히 마일드하기 때문에 예민한 피부에서 레티노산을 홈케어로 처음 시도하려는 분에게도 권해 드립니다.$AAA$, array['디페린', '아다팔렌', '지성피부', '여드름', '친유성']::text[], 2024, 'GnzkIDdyxtc-2', 'https://youtu.be/GnzkIDdyxtc?t=251s', null, '2024-03-04 00:00:00+00'::timestamptz, '2024-03-04 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$아크리프 크림은 어떻게 발라야 효과가 좋나요?$AAQ$, $AAA$아크리프 크림은 처음에는 쌀알 크기만큼 짜서 보습제와 섞어 취침 전 하루 한 번 얼굴 전체에 발라야 합니다. 트리파로텐 0.005%가 주 유효성분인 4세대 레티노이드로, 가장 최근에 나온 신약이에요. **이전 세대에 비해 분해 속도가 빠르기 때문에** 얼굴뿐 아니라 가슴이나 등 같은 넓은 면적에도 부작용이 덜한 큰 장점이 있습니다.

2019년 미국 FDA에서 9세 이상의 얼굴과 몸 여드름 치료제로 승인을 받았습니다. 다만 9세 이상이 바를 수 있다고 해서 순하다고 오해하고 많은 양을 한꺼번에 바르면 피부가 확 뒤집어질 수 있어요. **쌀알 크기에 보습제 손가락 한 마디만큼을 섞어** 천천히 적응시키는 것이 핵심입니다. 제형은 겔과 크림 중간 정도로 발림성이 좋고, 펌핑 형식이라 양 조절이 편한 점도 장점이에요.$AAA$, array['아크리프', '트리파로텐', '4세대레티노이드', '사용법', '여드름치료']::text[], 2024, 'GnzkIDdyxtc-3', 'https://youtu.be/GnzkIDdyxtc?t=357s', null, '2024-03-04 00:00:00+00'::timestamptz, '2024-03-04 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$레티노이드를 처음 사용하는 예민한 피부는 어떤 제품이 좋나요?$AAQ$, $AAA$레티노이드 입문자나 예민한 피부에는 비타리프트A 크림 같은 레티날 화장품을 권해 드립니다. 이 제품은 전문의약품이 아닌 화장품으로, 의사 처방 없이 시중에서 쉽게 구매할 수 있는 닥터디퍼런트의 제품이에요. **자극감이 적은 레티날로 이루어져** 부담 없이 바를 수 있다는 게 큰 장점입니다.

레티날을 피부에 바르면 레티노산으로 전환되면서 원하는 레티노이드 효과를 볼 수 있어요. 현재 사용 중인 비타A리프트 포르테는 **레티날 0.1%가 함유되어 있고**, 시중에는 다양한 농도의 레티날 제품들이 있습니다. 계속해서 농도가 높아지면서 업그레이드되고 있는 제품이라 앞으로도 기대가 되는 후보입니다. 대체재 후보 중 자극이 제일 적기 때문에 예민한 피부나 스킨케어로 레티노이드를 처음 입문하는 분에게 잘 맞아요.$AAA$, array['레티날', '비타리프트A', '예민피부', '레티노이드입문', '화장품']::text[], 2024, 'GnzkIDdyxtc-4', 'https://youtu.be/GnzkIDdyxtc?t=586s', null, '2024-03-04 00:00:00+00'::timestamptz, '2024-03-04 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$임신 중에도 레티노이드 연고나 레티놀 화장품을 사용해도 되나요?$AAQ$, $AAA$임신 준비 기간과 임신 기간 동안에는 바르는 레티노이드와 레티놀 화장품 모두 사용을 중단해야 합니다. 먹는 레티노이드는 사람과 동물 모두에서 태아 기형이 증명된 **'Category X' 약물**이에요. 바르는 레티노이드는 태아에 큰 문제가 없다는 연구 보고가 있긴 하지만, 위험을 감수하면서 임산부가 바를 이유는 없습니다.

주름 개선용으로 많이 쓰는 레티놀 기능성 화장품도 마찬가지입니다. **임신 초기 여성 235명을 대상으로 한 연구에서** 태아 발달에 영향을 줄 수 있어 사용하지 않는 게 좋다고 보고했어요. 그래서 레티날 크림을 꾸준히 바르던 분이 임신 후 어떤 크림으로 바꿔야 하는지 물어보시면 바쿠치올을 권해 드립니다. 바쿠치올은 식물 유래 성분이고 레티놀과 유사한 기능을 하면서 자극감도 적어 임산부 대체 화장품으로 적합합니다.$AAA$, array['임신', '레티노이드', '레티놀', '바쿠치올', '임산부화장품']::text[], 2024, '3WhIyPMKCKc-1', 'https://youtu.be/3WhIyPMKCKc?t=74s', null, '2024-03-07 00:00:00+00'::timestamptz, '2024-03-07 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$임신 중에 생긴 기미는 레이저 토닝으로 치료해도 되나요?$AAQ$, $AAA$임신 중 레이저 토닝은 꼭 필요한 경우가 아니면 권해 드리지 않습니다. 임신을 하면 약 반 이상이 기미가 생기는데, **에스트로겐과 프로게스테론** 같은 여성호르몬 증가로 멜라닌 색소가 늘어나기 때문이에요. 보통 임신 선이 발생하는 2분기 무렵 잘 생깁니다.

출산 후에는 기미가 옅어지거나 없어지기도 하므로, 이 시기에는 산모와 태아의 건강에 더 신경 쓰는 것이 좋아요. 레이저 토닝 자체가 태아에게 직접적으로 기형을 유발하지는 않아 이론적으로는 받을 수 있지만, **임산부 대상 장기간 대규모 연구가 없기 때문에** 신중해야 합니다. 다만 결혼식을 앞둔 경우에는 의사 상의 후 낮은 에너지로 받는 것은 괜찮습니다. 기미 예방이 필요하다면 유기자차보다 무기자차 선크림을 권해 드리고, 가시광선까지 차단하는 틴티드 선크림도 도움이 됩니다.$AAA$, array['임신기미', '레이저토닝', '무기자차', '임산부미백', '선크림']::text[], 2024, '3WhIyPMKCKc-2', 'https://youtu.be/3WhIyPMKCKc?t=149s', null, '2024-03-07 00:00:00+00'::timestamptz, '2024-03-07 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$임신 중 여드름이 심해졌는데 어떤 연고를 발라도 괜찮나요?$AAQ$, $AAA$임신 중 여드름에는 아젤리아 연고와 클린다마이신 성분 연고를 권해 드립니다. 임신 중에는 호르몬 불균형으로 피지 분비량이 늘면서 여드름이 새로 생기거나 심해질 수 있어요. 평소 먹지 않던 밀가루나 단 음식 섭취 증가, 수면 질 저하, 스트레스도 영향을 미칩니다.

먹는 약은 복용할 수 없으니 바르는 약 중에서는 아젤리아 연고를 발라 보거나, 더 심한 부위에는 **클린다마이신 항생제 성분의 듀오클린, 크레오신티, 아크닌액**을 써볼 수 있어요. 클린다마이신은 **'Category B'로 임산부 사용이 가능**하기 때문입니다. 크레오신티, 듀오클린, 아크닌액은 의사 처방이 필요한 연고이고, 여드름이 1~2개 정도면 그러려니 해도 너무 많거나 심하게 곪으며 커지는 경우에는 피부과 압출 관리를 권해 드립니다.$AAA$, array['임신여드름', '아젤리아', '클린다마이신', '듀오클린', '임산부연고']::text[], 2024, '3WhIyPMKCKc-3', 'https://youtu.be/3WhIyPMKCKc?t=318s', null, '2024-03-07 00:00:00+00'::timestamptz, '2024-03-07 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$결혼식을 앞둔 임산부는 어떤 시술을 받을 수 있나요?$AAQ$, $AAA$결혼식을 앞둔 임산부는 압출, AHA·PHA 필링, LDM·SONO 초음파 관리 정도를 받아볼 수 있습니다. 여드름이 심한 경우 압출 관리가 가능하고, 더 심하면 **AHA 성분인 GA필링**을 받아볼 수 있어요. 초음파 관리인 LDM·SONO와 연예인 필링이라 불리는 PHA 필링도 가능합니다.

반면 써마지나 올리지오 같은 고주파 시술은 몸에 전류를 흘려주기 때문에 권해 드리지 않아요. 울쎄라·슈링크 같은 초음파 시술도 태아 초음파와 달리 시술 시 얼굴에 열을 가하면서 통증이 유발되어 마취 연고가 필요하고, 긴장으로 힘을 주면 태아에게 안 좋은 영향을 줄 수 있어 권해 드리지 않습니다. **마취 연고 성분 중 리도카인은 Category B 약물**로 꼭 필요한 경우 국소적으로 사용 가능하지만, 굳이 필요하지 않은 시술에 무분별하게 쓰는 것은 자제하는 게 좋습니다.$AAA$, array['임산부시술', 'GA필링', '울쎄라', '써마지', '리도카인']::text[], 2024, '3WhIyPMKCKc-4', 'https://youtu.be/3WhIyPMKCKc?t=430s', null, '2024-03-07 00:00:00+00'::timestamptz, '2024-03-07 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$임산부의 홈케어 루틴은 어떻게 구성하는 게 좋나요?$AAQ$, $AAA$임산부 홈케어는 이중 세안 후 비타민C, 보습제 순으로 바르면 됩니다. 클렌징밀크와 클렌징폼으로 이중 세안을 하고, 임신 전에 쓰던 디페린이나 레티날 크림은 중단해요. **대신 비타민C 제품을 미백·항산화·항염용으로** 아침저녁 바르고, 그 후 보습제로 마무리합니다.

여드름이 올라오면 압출 관리를 받거나, 받지 못할 때는 아젤리아 연고나 크레오신티를 부위에 사용해요. 압출 후 얼굴이 붉어지거나 민감해지면 비타민B5 성분의 재생 세럼을 가끔 사용합니다. 너무 건조한 피부라면 재생 세럼을 루틴에 함께 두는 게 좋고, **나이아신아마이드 성분이나 보습 최고인 히알루론산 성분**도 권해 드려요. 이들 성분은 모두 임산부에게 안전하게 사용 가능하므로 정답은 없고, 본인에게 맞는 화장품을 잘 선별해서 함께 쓰면 좋습니다.$AAA$, array['임산부홈케어', '비타민C', '보습제', '나이아신아마이드', '히알루론산']::text[], 2024, '3WhIyPMKCKc-5', 'https://youtu.be/3WhIyPMKCKc?t=606s', null, '2024-03-07 00:00:00+00'::timestamptz, '2024-03-07 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$비수면 호흡마취는 일반 수면마취와 어떻게 다른가요?$AAQ$, $AAA$비수면 호흡마취는 가스를 흡입해 몽롱한 상태로 시술받는 마취로, 수면마취와 달리 푹 잠들지는 않습니다. 수면 내시경처럼 혈관으로 마취제를 주입하면 푹 자고 일어났을 때 시술이 끝나 있고 기억도 없는 반면, **비수면 마취는 졸음이 오는 가스를 마시는** 방식이라 더 얕게 잠든 상태가 됩니다.

수면 내시경은 금식이 필요하고 본인은 마취가 깬 것 같아도 실제로 깨지 않는 경우가 있어 하루 동안 운전을 금하지만, **비수면 마취는 금식이 필요 없고 시술 전 마취에 임하며 회복 속도가 빠른 점이 장점**입니다. 마취가 끝나면 산소를 높게 틀어 그 상태로 3분간 숨을 쉬면 대부분 정상으로 회복돼요. 병원에서는 안전을 위해 15분 정도 지켜본 뒤 귀가하도록 안내합니다. 느낌은 잠들 것 같다는 느낌이 쭉 이어지는, 마치 술에 만취한 느낌이라고 보시면 돼요.$AAA$, array['비수면마취', '호흡마취', '수면마취비교', '회복시간', '금식']::text[], 2024, 'J6-J2_y8v2E-1', 'https://youtu.be/J6-J2_y8v2E?t=48s', null, '2024-03-21 00:00:00+00'::timestamptz, '2024-03-21 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$비수면 호흡마취는 어떤 방식으로 시술이 진행되나요?$AAQ$, $AAA$비수면 호흡마취는 호스를 입에 물거나 마스크로 가스를 흡입하면서 진행됩니다. 얼굴 전체 시술의 경우 호스를 입에 물고 구강 호흡을 해야 해서 **코마개를 코에 끼고서 시술**받습니다. 드물게 입으로만 호흡하기 어려운 경우에는 코와 입 둘 다 호흡할 수 있는 마스크를 사용해요.

시술 중에는 기계에서 아산화질소와 산소의 농도를 조절하고, 환자 손톱에 산소 포화도 장치를 붙여 실시간으로 산소 농도를 보며 진행합니다. 어떤 느낌이냐면 내시경 수면마취 때처럼 잠들어 버리는 것이 아니라, **잠들 것 같다는 느낌이 쭉 이어지는 마치 술에 만취한 느낌**이에요. 환자분들이 아파하지 않으니 의사 입장에서도 부담 없이 시술할 수 있고, 시술 중 고개 방향을 바꿔 달라는 협조 요청에도 응해 주실 수 있는 점이 장점입니다.$AAA$, array['호흡마취방법', '아산화질소', '코마개', '산소포화도', '시술방법']::text[], 2024, 'J6-J2_y8v2E-2', 'https://youtu.be/J6-J2_y8v2E?t=109s', null, '2024-03-21 00:00:00+00'::timestamptz, '2024-03-21 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$비수면 호흡마취를 하면 통증이 얼마나 줄어드나요?$AAQ$, $AAA$비수면 호흡마취를 하면 일반 마취 대비 약 74% 통증이 감소합니다. 피부암 수술 환자 400명을 대상으로 한 논문에서 국소 주사 마취 시 통증을 줄이는 방법을 비교했는데, **그냥 마취한 경우 4.6점, 비수면 마취는 1.2점**으로 74% 감소했어요. 통증은 0점(전혀 안 아픔)부터 10점(극심한 통증)까지 점수로 매겼습니다.

다른 방법들과 비교하면 냉찜질이 3점으로 35%, 진동기와 마취 연고가 각각 3.6점으로 22%, 22%의 진통효과를 보였어요. 즉 **비수면 호흡마취가 냉찜질·진동기·마취연고보다 진통 효과가 압도적으로 큽니다**. 이 논문은 리도카인 마취제를 주입하는 아픈 주사 결과이고, 대부분의 피부과 시술은 이보다 덜 아프기 때문에 진통 효과는 70% 이상 더 좋을 것으로 예상됩니다. 실제 환자들도 마취 연고만 바르는 것보다 호흡마취가 50% 이상 통증을 줄여 줬다고 답했어요.$AAA$, array['통증감소', '비수면마취효과', '마취비교', '진통효과', '리도카인']::text[], 2024, 'J6-J2_y8v2E-3', 'https://youtu.be/J6-J2_y8v2E?t=162s', null, '2024-03-21 00:00:00+00'::timestamptz, '2024-03-21 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$비타민C는 아침에 발라도 되나요 저녁에 발라야 하나요?$AAQ$, $AAA$비타민C는 밤이 아니라 아침이나 낮에 바르는 것이 더 좋습니다. 비타민C가 빛·열·공기에 약해 햇빛을 받으면 안 된다고 알고 있는 분들이 많은데, 반대로 생각해 **자외선으로 피부가 손상되는 것이 낮이기 때문에** 자외선으로부터 보호하기 위해 낮에 바르면 더 좋은 효과를 누릴 수 있어요.

다만 비타민C를 바르고 자외선을 받으면 산화되어 본 기능을 잃을 수 있는 것은 맞습니다. 그래서 **아침 혹은 낮에 비타민C를 바른 뒤 자외선 차단제를 덧발라** 자외선을 차단해야 효과를 제대로 누릴 수 있어요. 결론은 아침·낮에 발라도 되고, 오히려 아침·낮에 바르면 더 좋다는 것입니다. 비타민C 나이트크림 라벨에 저녁에 바르라고 쓰여 있어 고민하는 분들이 많지만, 자외선 차단제를 함께 발라 주는 것이 핵심입니다.$AAA$, array['비타민C', '낮바르기', '자외선차단', '산화', '사용시간']::text[], 2024, 'tZuO6L0Q1M0-1', 'https://youtu.be/tZuO6L0Q1M0?t=58s', null, '2024-03-27 00:00:00+00'::timestamptz, '2024-03-27 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$비타민C를 먹는데 피부에도 따로 발라야 하나요?$AAQ$, $AAA$비타민C는 먹는 것과 바르는 것의 기전이 달라 두 가지 모두 하는 것이 좋습니다. 먹는 비타민C는 위장에서 흡수되어 항산화력으로 몸이 건강해지고 피부가 좋아지는 효과를 내지만, **피부까지 가려면 우리가 원하는 만큼 충분한 양이 도달하지 않을 수 있어요.** 반면 피부에 직접 바르면 농축된 비타민C가 피부에 닿기 때문에 효과가 더 잘 나타납니다.

바를 때는 콜라겐 생성이나 피부 미백 효과 같은 우리가 원하는 효과들을 더 잘 느낄 수 있어요. **결론은 섭취와 바르기가 상호 보완은 가능하지만 상호 대체는 불가능하다는 것**입니다. 즉 둘 중 하나만 한다고 다른 하나의 효과를 완전히 대신할 수 없어요. 그래서 섭취도 하고 바르기도 하면 피부에 정말 좋습니다. 먹는 비타민C만으로는 피부 효과가 부족할 수 있다는 점을 기억해 주세요.$AAA$, array['비타민C', '복용바르기', '콜라겐생성', '미백효과', '상호보완']::text[], 2024, 'tZuO6L0Q1M0-2', 'https://youtu.be/tZuO6L0Q1M0?t=116s', null, '2024-03-27 00:00:00+00'::timestamptz, '2024-03-27 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$비타민C를 바르면 따가운데 사용해도 괜찮나요?$AAQ$, $AAA$비타민C 따가움은 농도와 빈도 조절, 혼합 사용으로 줄일 수 있어 꼭 중단할 필요는 없습니다. **비타민C의 pH가 3 정도로 상당히 낮아** 따가움을 많이 느낄 수밖에 없고, 농도가 높아질수록 자극감이 심해질 수 있어요.

따가움을 느낀다면 시도해 볼 방법이 있어요. 첫 번째는 농도가 낮은 제품부터 시작해 점점 농도를 높여 가는 것이고, 두 번째는 처음에는 일주일 1~2회로 시작해 점점 빈도를 늘려 피부에 적응시키는 것입니다. 세 번째는 원액 사용 시 계속 따갑다면 **원래 쓰는 보습제에 비타민C 앰플을 2~3방울 떨어뜨려 섞어서** 쓰는 방법이에요. 이렇게 해도 계속 따갑다면 순수 비타민C 대신 자극감이 적은 비타민C 유도체 성분을 찾아서 쓰는 것도 좋습니다. 비타민C 유도체는 안정성이 더 뛰어나고 자극이 적은 대신 효과는 순수 비타민C보다 다소 떨어집니다.$AAA$, array['비타민C따가움', '농도조절', '비타민C유도체', 'pH', '보습제혼합']::text[], 2024, 'tZuO6L0Q1M0-3', 'https://youtu.be/tZuO6L0Q1M0?t=266s', null, '2024-03-27 00:00:00+00'::timestamptz, '2024-03-27 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$비타민C 앰플이 노랗게 변했는데 그대로 써도 되나요?$AAQ$, $AAA$비타민C 앰플이 노랗게 변했다면 산화된 것이지만 절대 쓰면 안 되는 건 아닙니다. 비타민C가 빛·열·공기에 약해 변성된 것이 맞아요. 산화된 비타민C는 두 가지 변화가 생깁니다. 첫째 **효과가 떨어지고**, 둘째 피부 자극감이 더 심해질 수 있어요.

유통기한이 남았어도 색상 변화는 변성을 의미하므로 주의가 필요합니다. 결론은 색깔이 조금 변했다고 절대 쓰면 안 되는 건 아니지만, 개봉 후에는 최대한 빨리 사용하는 게 좋다는 거예요. 만약 **색깔 변성이 너무 심하거나 이상한 냄새가 나거나 질감이 변한 것 같다면** 제품이 상했을 가능성이 있어 사용 중단을 권해 드립니다. 효과적으로 바르려면 첫째, 개봉 후 아껴 바르지 말고 색깔 변하기 전에 빨리 사용하고 둘째, 변성을 막기 위해 서늘하고 빛이 없는 곳에 보관해야 합니다.$AAA$, array['비타민C앰플', '산화변성', '보관법', '유통기한', '사용중단']::text[], 2024, 'tZuO6L0Q1M0-4', 'https://youtu.be/tZuO6L0Q1M0?t=482s', null, '2024-03-27 00:00:00+00'::timestamptz, '2024-03-27 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$눈가에 다른 부위보다 주름이 잘 생기는 이유가 무엇인가요?$AAQ$, $AAA$눈가는 우리 몸에서 가장 피부가 얇고 피지선이 적어 주름이 잘 생깁니다. 다른 부위보다 **피부가 얇은 데다 피지선이 적기 때문에** 쉽게 건조해지고 주름이 잘 생기는 부위예요. 그래서 보습 관리가 특히 중요합니다.

또한 나이가 들면서 노화와 자외선 등에 의해 **피부를 지지하던 콜라겐과 엘라스틴이 감소하기 때문에** 주름이 점점 더 깊어지게 됩니다. 그래서 눈가용 제품에는 보습과 주름·탄력 개선 성분이 꼭 필요해요. 보습을 위해서는 수분 공급을 돕는 글리세린, 히알루론산, 판테놀 성분이 도움이 되고, 나이아신아마이드는 보습과 미백 효과로 눈 밑이 칙칙한 분들께 좋아요. 수분을 잡아 주는 스쿠알렌·천연 오일·시어버터 성분이 함유된 제품을 고르면 됩니다.$AAA$, array['눈가주름', '피부얇음', '콜라겐엘라스틴', '보습성분', '히알루론산']::text[], 2024, 'GC15qhAWOy8-1', 'https://youtu.be/GC15qhAWOy8?t=38s', null, '2024-04-05 00:00:00+00'::timestamptz, '2024-04-05 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$아이크림 대용으로 바세린이나 비판텐을 발라도 되나요?$AAQ$, $AAA$바세린이나 비판텐을 눈가에 사용할 수는 있지만 장기간 사용은 권해 드리지 않습니다. 바세린은 수분을 공급하기보다 **이미 있는 수분을 날아가지 않도록 기름막을 형성**해 주는 성분이라, 먼저 수분 공급 성분을 바른 뒤 그 위에 아주 얇게 발라야 해요. 지성피부나 트러블이 잘 생기는 분은 얼굴 전체에 바르는 건 피하는 게 좋습니다.

또한 눈가라도 너무 두껍게 바르거나 장기간 사용하면 비립종이나 다래끼를 유발할 수 있어 눈에 들어가지 않도록 조심해야 합니다. 비판텐은 **덱스판테놀 성분이 피부 재생에 도움을 주지만** 연고여서 끈적거리고, 트러블을 잘 일으키는 라놀린이 들어 있어요. 장기간 사용 시에는 비판텐보다 판테놀 성분이 들어간 화장품을 바르는 걸 권해 드립니다.$AAA$, array['바세린', '비판텐', '아이크림대용', '비립종', '판테놀']::text[], 2024, 'GC15qhAWOy8-2', 'https://youtu.be/GC15qhAWOy8?t=169s', null, '2024-04-05 00:00:00+00'::timestamptz, '2024-04-05 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$마데카솔 종류별로 아이크림으로 써도 되는 것과 안 되는 것이 무엇인가요?$AAQ$, $AAA$마데카솔은 단독 성분만 든 연고·겔·분말은 시도 가능하지만 복합 마데카솔·마데카솔 케어는 절대 안 됩니다. 마데카솔의 **주 원료인 센텔라 아시아티카는 진피의 섬유아세포를 자극해** 콜라겐 합성을 촉진하는 것은 맞습니다. 하지만 제품별 성분이 달라 주의가 필요해요.

마데카솔 케어 제품은 네오마이신 성분의 항생제가 혼합되어 있고, **복합 마데카솔은 항생제와 스테로이드 성분까지 들어 있어** 절대 아이크림 대용으로 사용해서는 안 됩니다. 반면 마데카솔 연고·겔·분말은 센텔라정량추출물 단독 성분이라 아이크림으로 시도해 볼 수는 있어요. 다만 분말은 콜로이드성 이산화규소와 탤크 성분이 진물을 흡수하는 역할을 해 장기간 사용 시 피부가 오히려 건조해질 수 있고, 마데카솔 겔은 무수에탄올 등 첨가제가 오래 사용 시 자극이 될 수 있어 아이크림 대용으로 어렵습니다.$AAA$, array['마데카솔', '센텔라아시아티카', '복합마데카솔', '스테로이드', '아이크림']::text[], 2024, 'GC15qhAWOy8-3', 'https://youtu.be/GC15qhAWOy8?t=260s', null, '2024-04-05 00:00:00+00'::timestamptz, '2024-04-05 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$이미 깊어진 눈가 주름에는 어떤 시술이 좋나요?$AAQ$, $AAA$이미 깊어진 눈가 주름에는 아이써마지, 아이리쥬란, 보톡스 시술을 권해 드립니다. 웃을 때 생기는 주름은 사실 아이크림으로는 효과를 보기 어렵기 때문이에요. **아이써마지는 눈꺼풀 위쪽도 시술 가능하다는 게 장점**으로, 아이울쎄라는 눈꺼풀 바로 위로 들어가지 않는 것과 차이가 있습니다. 눈가 팁은 기존 써마지 팁보다 작게 만들어졌고 안구 보호 렌즈를 착용해 부작용을 예방합니다.

아이리쥬란은 기존 얼굴용 리쥬란보다 **점도를 낮춰 멍과 엠보싱이 덜 생기고 통증도 줄인 눈가 전용 제품**입니다. 보톡스는 근육을 움직이지 못하게 해 웃을 때 짓는 주름에 효과가 있어요. 시술 한 번으로 주름이 완전히 사라지지는 않지만, 노화로 콜라겐이 계속 감소하니 1년에 한 번 정도 주기적으로 받아 5~10년 뒤 피부 상태를 유지하는 일종의 보험 같은 시술이라고 보면 됩니다.$AAA$, array['아이써마지', '아이리쥬란', '보톡스', '눈가시술', '주기적관리']::text[], 2024, 'GC15qhAWOy8-4', 'https://youtu.be/GC15qhAWOy8?t=384s', null, '2024-04-05 00:00:00+00'::timestamptz, '2024-04-05 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$VT리들샷은 어떤 원리로 피부에 효과를 내나요?$AAQ$, $AAA$VT리들샷은 시카 리들이라는 바늘 모양 입자가 각질층에 미세한 구멍을 내 유효 성분 흡수를 돕는 원리입니다. **시카 리들은 실리카와 병풀추출물로 이루어진 바늘 모양 입자**이며, 실리카의 화학 명칭은 스피큘로 피부과 해초 필링에 쓰이는 성분이에요.

바늘 모양 미세 입자가 각질층에 미세한 구멍을 내면 그 구멍으로 에센스의 유효 성분이 흡수됩니다. 멀쩡한 피부에 물리적으로 구멍을 내놓았으니 피부가 재생을 시작하면서 더 좋아지는 원리예요. 피부과의 MTS 시술과 비슷한데, **MTS는 바늘 롤러로 직접 구멍을 내는 반면 VT리들샷은 그 롤러 역할을 하는 입자가 화장품에 들어 있는** 형태입니다. 시카 리들은 피부 제일 바깥인 각질층에만 살짝 구멍을 내고, 매일 새 각질이 만들어지면서 기존 각질이 탈락할 때 함께 자연적으로 떨어지므로 안전성은 크게 걱정하지 않아도 됩니다.$AAA$, array['VT리들샷', '시카리들', '실리카', 'MTS', '각질층']::text[], 2024, 'fILJTripb54-1', 'https://youtu.be/fILJTripb54?t=82s', null, '2024-04-09 00:00:00+00'::timestamptz, '2024-04-09 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$VT리들샷과 다이소 VT리들샷은 성분이 다른가요?$AAQ$, $AAA$두 제품은 미세침 두께·길이와 화장품 유효 성분이 완전히 동일합니다. VT Cosmetics가 판매하는 일반 VT리들샷과 같은 회사가 만들어 다이소에서 판매하는 일회용 VT리들샷은 처음에 다를 줄 알았지만, 회사 문의 결과 **구성 성분 자체가 아예 똑같다**고 답변받았어요.

가격과 용량 차이가 큽니다. **리들샷300은 50ml에 43,000원 정도지만 다이소 제품은 3천원에 12ml씩 6개**가 들어 있어요. 용량 대비로 보면 다이소 제품이 약 3.5배 더 저렴한 셈입니다. 이런 가격 차이 때문에 다이소 제품이 대란템이 된 것으로 보여요. 두 제품 중 무엇을 골라도 미세침 두께·길이와 화장품 유효 성분이 같으니, 가격과 사용 편의(일회용 vs 통)만 고려해서 선택하면 됩니다.$AAA$, array['VT리들샷', '다이소제품', '가격비교', '성분동일', '용량']::text[], 2024, 'fILJTripb54-2', 'https://youtu.be/fILJTripb54?t=44s', null, '2024-04-09 00:00:00+00'::timestamptz, '2024-04-09 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$VT리들샷을 비타민A나 비타민C와 같이 사용해도 되나요?$AAQ$, $AAA$VT리들샷을 비타민A·비타민C와 함께 사용하는 것은 절대 권해 드리지 않습니다. **VT리들샷 자체가 굉장히 자극감이 있는데** 스티바A 크림과 비타민C도 따가울 수 있는 성분이에요. 자극이 있는 제품들을 동시에 쓰면 피부 부담이 크게 늘어납니다.

홈케어 화장품은 안전이 가장 먼저예요. 과도한 효과 기대보다는 안전하게 쓰면서 약간의 좋은 효과를 내는 게 가장 좋습니다. **VT리들샷처럼 피부에 큰 자극을 주는 제품에 필링이나 비타민A·C를 더하는 것은 매우 비추천**입니다. 만약 같이 쓰고 싶다면 번갈아 쓰거나, VT리들샷을 쓰는 날에는 재생크림이나 수분크림 같은 가벼운 크림류를 함께 쓰는 게 가장 좋아요. 내 피부에 잘 맞고 안전한지를 먼저 잘 생각하고 사용하는 것을 항상 권해 드립니다.$AAA$, array['VT리들샷', '비타민A', '비타민C', '병용금지', '수분크림']::text[], 2024, 'fILJTripb54-3', 'https://youtu.be/fILJTripb54?t=375s', null, '2024-04-09 00:00:00+00'::timestamptz, '2024-04-09 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$VT리들샷은 어떤 사람에게 효과가 좋나요?$AAQ$, $AAA$VT리들샷은 피부가 튼튼하고 모공이 고민이거나 화장이 잘 안 먹는 분에게 효과가 좋습니다. 실제로 VT리들샷 700을 발라 보면 사포를 문지르는 듯한 느낌이 있고, 자고 일어나 세안할 때까지도 따가운데 **시카 리들이 피부에 남아 있는 느낌은 약 12시간 정도**예요. 그만큼 피부가 매끈해지고 시술받은 듯한 느낌을 받을 수 있습니다.

**가장 효과를 잘 느낄 분은 피부가 튼튼하면서 모공이 고민이거나 화장이 잘 안 먹고 잘 뜨는 분들**입니다. 피부가 매끈해지면 순간적으로 화장이 잘 되는 느낌을 받기 때문이에요. 반면 트러블·여드름·염증이 있는 분에게는 권해 드리기 어렵습니다. 트러블이 많아 깊은 침투 관리를 원한다면 골드PTT 시술이 더 적합해요. 또한 실리카를 매일 바르면 얼굴에서 완전히 다 없어질지 정확히 알기 어려우므로 가끔 바르는 것을 권해 드립니다.$AAA$, array['VT리들샷효과', '모공', '지속시간', '화장잘먹음', '트러블금기']::text[], 2024, 'fILJTripb54-4', 'https://youtu.be/fILJTripb54?t=219s', null, '2024-04-09 00:00:00+00'::timestamptz, '2024-04-09 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$쥬베룩은 효과가 바로 나타나지 않는 시술인가요?$AAQ$, $AAA$쥬베룩은 적금형 스킨부스터로 효과가 서서히 나타나는 시술입니다. 리쥬란이나 물광주사처럼 맞자마자 바로 효과가 나타나는 종류와 달리, **쥬베룩은 콜라겐 씨앗을 심는 시술**이에요. 한 번, 두 번, 세 번 적립하듯 맞아 줬을 때 씨앗이 토양에 심어져 열매를 맺듯이 피부가 좋아집니다.

한 달 간격으로 보통 세 번 정도를 권해 드리고, **세 번 씨앗을 뿌린 뒤 6개월·1년·1년 반·2년에 걸쳐** 서서히 시간이 지나면서 열매가 맺히는 느낌입니다. 그래서 진료실에서 쥬베룩을 맞았는데 효과를 모르겠다고 하시는 분들이 많은 이유는 이런 적금형 특성 때문이에요. 바로 좋아지고 싶은 분들보다는 내 피부를 꾸준히 가꾸고 관리하고 싶은 분들에게 훨씬 더 권해 드립니다. 천천히 콜라겐이 재생되며 탄력이 생기고 주름도 개선됩니다.$AAA$, array['쥬베룩', '적금형스킨부스터', '콜라겐씨앗', '효과지속', 'PDLLA']::text[], 2024, 'uRYgg7VTfzE-1', 'https://youtu.be/uRYgg7VTfzE?t=60s', null, '2024-04-15 00:00:00+00'::timestamptz, '2024-04-15 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$쥬베룩은 스컬트라처럼 결절이 잘 생기나요?$AAQ$, $AAA$쥬베룩은 스컬트라와 구조가 달라 결절 부작용이 현저히 낮습니다. 스컬트라의 문제점 중 하나였던 결절이 생기는 부작용이 쥬베룩에서는 매우 드물게 나타나요. 수년간 많은 쥬베룩 시술을 해 온 경험상 **결절처럼 동그랗게 뭉치는 현상이 생기더라도** 고주파 열로 녹이거나 손 마사지만으로도 굉장히 잘 풀어집니다.

쥬베룩이 효과를 내는 방식은 **비어 있는 공 같은 입자를 피부 안에 넣는 것**으로 생각하면 좋아요. 비어 있는 공이 피부 안에 들어가면 그 안으로 콜라겐이 차고, 비어 있는 껍질은 서서히 물처럼 녹아 피부 안에서 흡수돼 사라집니다. 그래서 피부 안에 아무것도 남지 않고 내 피부만 서서히 차오르기 때문에 효과도 좋고 부작용도 적어요. 다만 눈가 주변과 입가 주변은 피부가 얇거나 움직임이 많아 결절·이물반응 가능성이 있으므로 주의해서 시술해야 합니다.$AAA$, array['쥬베룩결절', '스컬트라비교', '부작용', '고주파마사지', '이물반응']::text[], 2024, 'uRYgg7VTfzE-2', 'https://youtu.be/uRYgg7VTfzE?t=133s', null, '2024-04-15 00:00:00+00'::timestamptz, '2024-04-15 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$쥬베룩과 리쥬란은 어떻게 다른가요?$AAQ$, $AAA$쥬베룩은 서서히 효과가 나타나고 리쥬란은 즉각 효과가 나타나는 결이 다른 스킨부스터입니다. 리쥬란은 **폴리뉴클레오타이드 성분으로 된 리쥬란 힐러**가 원래 이름으로, 피부에 상처·염증·여드름을 회복시키는 힐링 효과가 탁월합니다. 트러블·여드름·홍조가 많은 분께 추천되고 맞자마자 전체적으로 피부가 좋아져요.

리쥬란의 장점은 즉각적으로 매우 좋아진다는 점이지만, 단점은 **시간이 지나 효과가 떨어지면 피부가 원래 상태로 되돌아간다**는 거예요. 그래서 결혼식 같은 중요한 일 전이나 피부 염증·트러블이 심할 때 한 번씩 맞는 것을 권해 드립니다. 반면 쥬베룩은 PDLLA 소재로 콜라겐 씨앗을 심어 서서히 피부가 좋아지는 적금형 시술이에요. 피부가 얇고 푸석하며 잔주름이 많고 탄력이 떨어진 분, 모공이 늘어져 보이고 나이 들어 보이는 분에게 잘 맞습니다.$AAA$, array['쥬베룩리쥬란비교', '폴리뉴클레오타이드', '리쥬란힐러', 'PDLLA', '스킨부스터']::text[], 2024, 'uRYgg7VTfzE-3', 'https://youtu.be/uRYgg7VTfzE?t=188s', null, '2024-04-15 00:00:00+00'::timestamptz, '2024-04-15 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$쥬베룩과 쥬베룩 볼륨은 어떻게 다른가요?$AAQ$, $AAA$쥬베룩 볼륨은 입자가 훨씬 커서 볼륨 채우기에 가까운 시술입니다. **쥬베룩이 탁구공만 하다면 쥬베룩 볼륨은 축구공만한 크기**의 입자라고 생각하면 돼요. 입자 크기 차이로 시술 목적이 달라집니다.

쥬베룩 볼륨은 볼륨 효과가 훨씬 크기 때문에 **필러 대신 옆볼·팔자주름·눈 밑·관자 같은 부위의 볼륨을 전반적으로 채우는 데** 효과가 좋아요. 얼굴 볼륨이 떨어진 분에게 잘 맞습니다. 반면 일반 쥬베룩은 전반적인 탄력과 모공 개선, 피부가 탄탄해지는 느낌을 줄 때 훨씬 좋아요. 그래서 쥬베룩은 스킨부스터 쪽에 가깝고, 쥬베룩 볼륨은 필러처럼 피부를 채워 주는 쪽에 가깝습니다. 시술은 가루로 된 쥬베룩을 생리식염수와 피부 재생에 도움되는 물질로 수화시킨 뒤 주사기로 뽑아 엠보싱이 생길 정도로 피부 표면층에 한 땀 한 땀 주사합니다.$AAA$, array['쥬베룩볼륨', '입자크기', '필러대체', '옆볼팔자주름', '수화']::text[], 2024, 'uRYgg7VTfzE-4', 'https://youtu.be/uRYgg7VTfzE?t=315s', null, '2024-04-15 00:00:00+00'::timestamptz, '2024-04-15 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$튼살은 왜 생기고 붉은 튼살과 흰 튼살은 어떻게 다른가요?$AAQ$, $AAA$튼살은 살이 늘어나는 속도를 콜라겐과 엘라스틴이 따라가지 못해 찢어지면서 생기는 변화입니다. 갑작스러운 체중 증가, 성장기, 임신, 스테로이드 장기 사용 등으로 피부가 빠르게 늘어날 때 아래층의 탄력 섬유가 변성되어 발생합니다.

초기에는 콜라겐 뼈대가 무너지면서 염증 반응이 생기고 혈관이 넓어져 **붉은 튼살로 보이게 되고요**, 시간이 흘러 방치하면 흉터 조직과 유사한 흰 튼살로 변합니다. **흰 튼살은 치료가 어렵다고 알려져 있어**, 초기 단계인 붉은 튼살일 때 치료를 시작해야 효과가 훨씬 더 좋습니다. 그래서 튼살이 보이기 시작하면 색이 붉을 때 빠르게 피부과를 찾아보시는 것이 권장됩니다.$AAA$, array['튼살', '붉은튼살', '흰튼살', '콜라겐', '탄력섬유']::text[], 2024, 'y1qPplWOdQ0-1', 'https://youtu.be/y1qPplWOdQ0?t=103s', null, '2024-04-22 00:00:00+00'::timestamptz, '2024-04-22 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$튼살 크림이 정말 효과가 있나요?$AAQ$, $AAA$튼살 크림은 특별한 기능보다는 보습력이 뛰어난 제품으로 보는 것이 정확합니다. 클라랑스, 비오템, 아토팜, 일리윤, 버츠비 같은 인기 제품을 분석해 보면 대부분 보습 성분과 식물추출물이 주를 이루고, 가격은 일반 바디 크림보다 약 2~3배 가량 높은 편입니다.

튼살에 효과적이라고 알려진 화장품 성분은 **센텔라아시아티카와 히알루론산** 정도이고, 코코아 버터·올리브오일·아몬드 오일은 효과가 없다고 밝혀져 있어요. 화장품을 바르는 것만으로는 부족해진 콜라겐을 채우기가 거의 불가능하기 때문에, **튼살을 완전히 예방하거나 치료할 수 있는 것은 아니고** 도움이 될 수 있다 정도로 정리됩니다. 가격이 부담된다면 집에 있는 보습제에 바세린이나 오일을 섞어 충분히 발라주는 것만으로도 도움이 됩니다.$AAA$, array['튼살크림', '보습성분', '센텔라', '히알루론산', '바세린']::text[], 2024, 'y1qPplWOdQ0-2', 'https://youtu.be/y1qPplWOdQ0?t=160s', null, '2024-04-22 00:00:00+00'::timestamptz, '2024-04-22 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$임산부도 바를 수 있는 튼살 관리 방법은 무엇인가요?$AAQ$, $AAA$임산부는 비타민A 제제인 스티바A 크림이나 디페린 같은 연고를 피하고, 보습제와 마사지로 관리하는 것이 안전합니다. 비타민A 연고는 섬유아세포를 자극해 콜라겐 생성을 돕지만 기형아 출산 확률이 있어 임산부는 사용을 안 하는 것이 좋습니다.

실제로 임산부가 보습 크림을 매일 틈나는 대로 바르고 마사지를 충분히 해주면 배가 당기는 통증이 줄어드는 효과를 경험할 수 있어요. 논문에서도 **총 6주간 지속적으로 마사지를 했을 때 약 36% 정도 피부 탄력도가 좋아졌다**는 결과가 있습니다. 다만 화장품을 바르는 것만으로 부족한 콜라겐을 채우기는 거의 불가능에 가까워, 모든 튼살을 예방하거나 치료할 수 있는 것은 아니고 도움이 될 수 있다 정도로 보시는 것이 맞습니다.$AAA$, array['임산부튼살', '보습마사지', '비타민A금기', '튼살예방', '스티바A']::text[], 2024, 'y1qPplWOdQ0-3', 'https://youtu.be/y1qPplWOdQ0?t=222s', null, '2024-04-22 00:00:00+00'::timestamptz, '2024-04-22 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$이미 생긴 튼살은 어떤 시술로 치료할 수 있나요?$AAQ$, $AAA$이미 생긴 튼살은 브이빔, 쥬베룩, 미라젯, 울트라 펄스 앙코르 같은 시술로 단계별로 치료합니다. 붉은 튼살 단계에서는 브이빔이라는 혈관 레이저로 붉은 부위를 치료해 흰색 튼살로 넘어가는 것을 최대한 막을 수 있고, 치료 효과도 꽤 좋은 편입니다.

이미 흉터 조직으로 변한 흰색 튼살은 **콜라겐 씨앗이라 불리는 쥬베룩 같은 콜라겐 부스터를 주사해** 내 몸에 있는 콜라겐으로 다시 채우는 원리로 접근합니다. 콜라겐이 부족한 부위에 일정한 양을 균일하게 투여하는 미라젯이 치료 효과와 색소침착 개선이 좋아 각광받고 있고, 표면이 쭈글쭈글해진 부위에는 **울트라 펄스 앙코르라는 프랙셔널 레이저가 콜라겐 생성에 도움**을 줍니다. 두 레이저 기계가 비싼 편인 만큼 개선 속도나 효과가 좋아, 장비가 있는 피부과에서 상담을 받아보는 것이 좋습니다.$AAA$, array['브이빔레이저', '쥬베룩', '미라젯', '프랙셔널레이저', '콜라겐부스터']::text[], 2024, 'y1qPplWOdQ0-4', 'https://youtu.be/y1qPplWOdQ0?t=477s', null, '2024-04-22 00:00:00+00'::timestamptz, '2024-04-22 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$운동 후 열이 오르면 트러블이 생기는데 정말 관련이 있나요?$AAQ$, $AAA$운동 후 트러블은 열 자체보다 땀과 피지가 모공을 막아 생기는 경우가 많다고 학생 본인도 추정합니다. 인터뷰에 응한 체육교육과 학생은 운동을 하고 나서 열이 올라오면 트러블이 많이 올라오는 경험을 했고, 본인은 그 원인을 땀이 피부의 모공을 막기 때문이 아닐까로 설명했어요.

실제로 운동을 자주 하는 사람들은 **땀이 많이 나면 컨트롤 하기가 어렵다고** 공통적으로 호소합니다. 댄스 동아리 학생들도 새벽 연습 동안 세수도 못하고 땀을 흘리고 잠도 못 자면서 트러블이 올라오는 사례를 들었어요. 자막 안에서는 의료진의 정밀한 메커니즘 설명까지 나오지는 않지만, 운동과 땀, 모공 막힘이 같은 흐름에서 자주 거론되며 **운동 후 빠른 세안과 땀 관리가 공통된 고민**으로 정리됩니다.$AAA$, array['운동트러블', '땀모공', '운동후세안', '체온피부', '여드름']::text[], 2024, 'lKoOXOllm94-1', 'https://youtu.be/lKoOXOllm94?t=174s', null, '2024-04-24 00:00:00+00'::timestamptz, '2024-04-24 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$지성 피부의 피지를 관리하려면 짜야 하나요, 팩을 써야 하나요?$AAQ$, $AAA$지성 피부의 피지는 짜기보다는 필 오프 팩 같은 도구를 일주일에 두 번 정도 사용하는 정도가 학생들의 실제 관리 방법으로 거론됩니다. 인터뷰에 응한 학생은 트러블과 피지에 대한 고민이 많아 **피지를 짜기보다는 필 오프 팩 같은 거를 써요**라고 답했고, 사용 빈도는 일주일에 두 번 정도라고 밝혔어요.

돼지코 패치 같은 시중 제품을 써본 다른 학생은 **돼지코 패치로 피부 고민 해결이 되지 않는다**고 답한 사례도 있습니다. 자막 안에서 의료진이 짜는 행위 자체에 대해 의학적으로 평가하는 부분은 등장하지 않으므로, 일반인 학생들의 경험에 따르면 짜는 대신 팩이나 패치 같은 도구를 일정 주기로 쓰는 쪽이 우선 선택되는 흐름으로 정리됩니다.$AAA$, array['피지관리', '필오프팩', '돼지코패치', '지성피부', '트러블관리']::text[], 2024, 'lKoOXOllm94-2', 'https://youtu.be/lKoOXOllm94?t=345s', null, '2024-04-24 00:00:00+00'::timestamptz, '2024-04-24 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$건성 피부인데 어떻게 관리해야 좋나요?$AAQ$, $AAA$건성 피부 관리는 본인에게 맞는 방법을 적극적으로 찾으려는 태도와 꾸준한 보습이 출발점입니다. 인터뷰에 응한 한 학생은 본인이 건성 피부라고 답하면서 **건조함을 해결할 방법이 없어서 찾고싶다**고 솔직하게 말했고, 평소에는 집에서 굴러다니는 로션 하나만 사용하는 정도라고 답했어요.

외국에서 자란 한 학생은 몸이 전체적으로 건조해 수분 크림이나 로션을 잘 바르는 편이지만 하루에 한 번만 바른다고 답했는데, 이에 대해 인터뷰어는 **완전 건조 피부면 아침과 저녁으로 발라줘야 한다고 하던데요**라는 통념을 인용했습니다. 술 마신 다음날에는 수분이 빠져 속당김이 심해진다는 학생도 있어, 자기 전에 **수분 패드를 붙이고 자거나 로션을 열심히 바르는** 방법이 자주 거론됩니다.$AAA$, array['건성피부', '보습루틴', '수분패드', '로션', '피부당김']::text[], 2024, 'lKoOXOllm94-3', 'https://youtu.be/lKoOXOllm94?t=292s', null, '2024-04-24 00:00:00+00'::timestamptz, '2024-04-24 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$집에서 각질 제거는 얼마나 자주 해야 하나요?$AAQ$, $AAA$특별한 문제가 없으면 굳이 주기적으로 할 필요는 없고, 안 해도 되는 정도로 권장됩니다. 각질은 피부 제일 겉에서 피부를 보호해주는 막 같은 역할을 하기 때문에, 무조건 벗겨내야 하는 것이 아니라 **과도하게 제거하면 보호막을 벗겨내는 것과 똑같습니다**.

내일 중요한 일이 있거나 더 깔끔한 모습이 필요한 날에 어쩌다 한 번은 할 수 있지만, **피부가 좋아지게 하려고 주기적으로 하는 것은 권하지 않습니다**. 오히려 각질이 뜬다는 것은 피부 상태가 좋지 않다는 신호이므로, 건조하거나 안 맞는 게 있구나로 인지하고 피부 장벽을 좋아지게 할 클렌저나 제품을 찾아 쓰는 것이 더 중요해요. 원장님 본인도 각질 제거는 안 한다고 밝혔습니다.$AAA$, array['각질제거', '피부장벽', '필링젤', '보호막', '홈케어']::text[], 2024, 'LRFDz4QzM1M-1', 'https://youtu.be/LRFDz4QzM1M?t=51s', null, '2024-04-26 00:00:00+00'::timestamptz, '2024-04-26 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$약산성 클렌저와 약알칼리성 클렌저는 어떻게 다른가요?$AAQ$, $AAA$피부 원래 환경과의 일치도, 그리고 기름을 닦아내는 강도에서 본질적으로 다른 두 제품입니다. **피부는 원래 약산성이기 때문에**, 약산성 클렌저는 피부 환경과 비슷하게 만들어 놓은 제품이라 씻고 난 후에도 원래 피부와 비슷한 상태가 되며 약간 미끌미끌할 수 있어요.

반면 약알칼리성은 비누에 가까운 제품이라 기름 성분이 더 잘 씻겨 나가고, 쓰고 나면 뽀득뽀득한 느낌이 듭니다. 무조건 좋고 나쁨으로 나눌 수는 없고, 피부가 너무 기름지고 유분기가 많다면 알칼리성을 써 트러블을 줄이는 게 좋고, **피부가 예민하고 건조하고 얇은 사람들은 약산성 제품을 사용하는 게 좋고** 필요에 따라 번갈아 사용하면 됩니다. 뽀득한 느낌이 좋아 약알칼리성을 계속 쓰면 보호 기름까지 닦여 장기적으로는 건조해지고 가렵거나 따가워질 수 있습니다.$AAA$, array['약산성클렌저', '약알칼리성', '세안제선택', '피부장벽', '유분관리']::text[], 2024, 'LRFDz4QzM1M-2', 'https://youtu.be/LRFDz4QzM1M?t=176s', null, '2024-04-26 00:00:00+00'::timestamptz, '2024-04-26 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$기초 화장품은 몇 개를 발라야 적당한가요?$AAQ$, $AAA$개수는 절대적으로 중요하지 않고, 본인 피부에 맞는 2~3개로 불편하지 않으면 충분합니다. 원장님은 본인은 보통 2개를 쓰고, 신경 쓰는 날에는 3개 정도 쓴다고 밝히며 **앰플·로션 그리고 건조한 날엔 크림 한 번 정도가 끝**이라고 설명했어요.

트러블이 나고 피부가 좋지 않은 분들은 자꾸 무언가를 더 바르려 해서 6~7개씩 사용하게 되는데, 사용 제품이 많아질수록 그 중 본인 피부에 맞지 않는 제품이 있을 확률도 높아져 악순환이 됩니다. 그래서 **본인 피부에 잘 맞는 제품 2~3개 정도를 발라서 건조하지 않고 기름지지 않고 불편하지 않으면 됩니다**. 올인원 제품 하나만 써도 불편하지 않으면 그대로 써도 무방하다고 권합니다.$AAA$, array['기초화장품개수', '스킨케어루틴', '올인원', '민감성피부', '악순환']::text[], 2024, 'LRFDz4QzM1M-3', 'https://youtu.be/LRFDz4QzM1M?t=263s', null, '2024-04-26 00:00:00+00'::timestamptz, '2024-04-26 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$트러블이 자주 날 때는 어떤 성분 화장품을 골라야 하나요?$AAQ$, $AAA$AHA·BHA 성분과 '논코메도제닉' 인증 제품을 함께 살펴보는 것이 우선 권장됩니다. AHA(Alpha Hydroxy Acid)와 BHA(Beta Hydroxy Acid)는 산 성분으로, 각질을 부드럽게 해주고 빨리 떨어져 나가게 해주며 피지를 줄여주는 역할을 합니다. 계속 트러블이 나고 각질이 뜨는 분들은 잘 맞는 경우 AHA·BHA가 들어간 토너나 클렌저를 써주면 도움이 돼요.

또 하나 살펴볼 점은 **'논코메도제닉'이라고 써있는 제품인지**입니다. '코메도'가 모공 속에 박혀 있는 피지를 뜻하는데, 과다 피지를 유발하는 성분이 있어 이를 유발하지 않도록 인증받은 제품들이 있어요. 트러블이 잦다면 이 인증 제품을 골라 쓰는 것이 좋고, **피부가 민감하고 건조하고 얇은 분들은 민감성 피부를 위한 제품을 쓰는 것**도 함께 챙기면 좋습니다.$AAA$, array['AHA', 'BHA', '논코메도제닉', '민감성피부', '트러블관리']::text[], 2024, 'LRFDz4QzM1M-4', 'https://youtu.be/LRFDz4QzM1M?t=302s', null, '2024-04-26 00:00:00+00'::timestamptz, '2024-04-26 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$집에서 스크럽이나 닦토로 각질 제거를 자주 해도 되나요?$AAQ$, $AAA$피부과 전문의 입장에서는 말리고 싶은 행위에 가깝습니다. 각질도 중요한 보호막인데 거슬린다고 계속 밀어내면 사실 피부는 그 보호막을 잃는 것이기 때문이에요. 필링젤을 너무 자주 하거나 과하게 하면 **피부 보호막인 각질이 벗겨져 오히려 피부가 민감해질 수 있다는** 점이 가장 중요한 포인트입니다.

주기·세기·방법을 정확히 모르고 시작하면 하루 이틀은 매끈해지는 것 같다가, 시간이 지날수록 붉어지고 따갑고 각질이 일어나는 악순환이 생깁니다. 혼자 관리가 어렵고 피부가 민감하다면 피부과에서 필링을 받는 게 좋고, 집에서 한다면 **얼굴은 부드럽게 롤링되는 필링젤을 1분 이내로만** 사용하며 한 달에 2~3회 정도가 권장됩니다. 스크럽은 얼굴보다는 팔꿈치·무릎·정강이처럼 각질이 두꺼운 부위에 해주세요.$AAA$, array['홈케어각질', '스크럽주기', '필링젤', '피부보호막', '민감피부']::text[], 2024, 'iKVuk3aluZ8-1', 'https://youtu.be/iKVuk3aluZ8?t=33s', null, '2024-04-30 00:00:00+00'::timestamptz, '2024-04-30 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$피부과 박피는 어떤 종류가 있고 어떻게 다른가요?$AAQ$, $AAA$박피는 방식에 따라 화학적 박피, 물리적 박피, 레이저 박피로 나뉘고 깊이에 따라 표층·중층·심층 박피로 구분됩니다. 화학 박피는 약물로 피부에 외상을 입혀 일부를 벗겨내는 방식이고, 약물의 종류·농도·바르는 겹수·도포 시간에 따라 깊이가 달라져요.

물리적 박피는 미세한 크리스탈 입자나 사포 같은 거친 면으로 밀어내는 방식이고, 집에서 하는 때밀이와 다양한 스크럽 제품이 여기에 해당합니다. 레이저 박피는 점 제거 시 쓰는 CO2 레이저나 어븀 레이저로 피부를 원하는 층까지 파괴하는 방식이에요. **특히 동양인 피부는 색소 이상이 생길 위험이 크기 때문에**, 많은 병원들이 물리적·레이저 박피보다 **화학 박피 중에서도 표층 박피를 가장 널리 사용하고** 있습니다.$AAA$, array['화학박피', '물리적박피', '레이저박피', '표층박피', '색소이상']::text[], 2024, 'iKVuk3aluZ8-2', 'https://youtu.be/iKVuk3aluZ8?t=159s', null, '2024-04-30 00:00:00+00'::timestamptz, '2024-04-30 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$AHA와 BHA는 어떤 차이가 있고 어디에 좋은가요?$AAQ$, $AAA$AHA는 물 친화성, BHA는 기름 친화성이라는 점에서 본질적으로 다른 두 성분입니다. AHA(Alpha Hydroxy Acid)는 락틱 애시드·글라이콜릭 애시드·씨트릭 애시드가 속하며, 물과 친하고 분자량이 작아 다소 자극이 될 수 있지만 **피부 표면의 잔주름·색소·광노화 효과를 보입니다**.

BHA는 살리실산과 같은 말이고, 기름 성분과 더 친해 AHA보다 모공에 잘 침투하며 피부 자극이 더 적고 항염증 효과도 있어요. 그래서 BHA는 주로 지성피부나 특히 여드름성 피부에 사용하면 막힌 모공을 열어주고 울퉁불퉁한 좁쌀을 완화하며 여드름 후 색소도 좋아지게 합니다. 기미와 잡티 치료에는 **AHA·BHA를 잘 조합한 제품을 써서 표피 세포 주기를 빠르게 해 멜라닌이 축적된 세포를 탈락시키는** 방식으로 톤이 밝아지는 효과를 노립니다.$AAA$, array['AHA', 'BHA', '살리실산', '글라이콜릭산', '여드름성피부']::text[], 2024, 'iKVuk3aluZ8-3', 'https://youtu.be/iKVuk3aluZ8?t=313s', null, '2024-04-30 00:00:00+00'::timestamptz, '2024-04-30 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$필링 시술은 어떤 사람이 받으면 안 되나요?$AAQ$, $AAA$건조하고 민감한 분, 특히 아토피 피부염이 있는 분은 필링이 권장되지 않습니다. 잘못 시술을 받았다가 오히려 피부가 더 뒤집어지는 수가 있기 때문이에요. 이외에도 얼굴에 상처가 있거나 포진 같은 감염성 피부병이 있거나, 휴가를 다녀온 지 얼마 안 돼 얼굴이 벌겋게 그을린 상태라면 필링이 적합하지 않습니다.

필링 시술 직전과 직후에는 미세한 상처를 낼 수 있는 **왁싱이나 면도는 가급적 하지 마시고**, 강한 햇빛 노출도 조심해야 해요. 시술 후에는 광범위 자외선 차단제를 꼼꼼히 바르고 보습제도 충분히 도포해 건조해지지 않게 관리해야 합니다. 약한 박피는 다음날부터 화장이 가능하지만, **시술 후 2~3일 정도는 피부가 민감하므로 레티놀 계열 화장품 사용은 자제하는 것**이 좋습니다.$AAA$, array['필링금기', '아토피피부', '왁싱면도', '시술후관리', '자외선차단']::text[], 2024, 'iKVuk3aluZ8-4', 'https://youtu.be/iKVuk3aluZ8?t=437s', null, '2024-04-30 00:00:00+00'::timestamptz, '2024-04-30 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$시중에 파는 편평사마귀 연고는 정말 효과가 있나요?$AAQ$, $AAA$시중에 나와 있는 편평사마귀 연고는 사실 효과가 없습니다. 성분을 살펴보면 주로 병풍추출물 같은 재생 성분이나 세라마이드 같은 보습 위주 성분으로 이뤄져 있고, 각질을 제거하기 위해 AHA 같은 산성분이 포함된 제품도 있어요. 특별한 항바이러스 성분이 들어 있지 않다는 뜻입니다.

이런 연고가 나온 이유는 편평사마귀가 **만지거나 긁으면 더 번지는 자가접종의 특성** 때문이에요. 피부가 건조하거나 장벽이 무너지고 상처가 나면 상대적으로 잘 번지기 때문에, 보습·재생 성분으로 피부장벽을 회복시키면 전염 예방에 어느 정도 도움이 될 수는 있죠. 그래서 굳이 따로 구입할 필요 없이, **세콜지 성분의 피부 장벽을 강화시킬 수 있는 보습제**를 충분히 자주 도포해 주시면 됩니다.$AAA$, array['편평사마귀연고', '자가접종', '피부장벽', '보습제', '사마귀번짐']::text[], 2024, '5mA2eVFd5Bw-1', 'https://youtu.be/5mA2eVFd5Bw?t=141s', null, '2024-05-07 00:00:00+00'::timestamptz, '2024-05-07 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$편평사마귀 치료에는 어떤 방법들이 있나요?$AAQ$, $AAA$현재로서 가장 확실한 방법은 레이저이며, 보조 수단으로 알다라 크림·시메티딘·자궁경부암 백신을 고려할 수 있습니다. 바르는 약 알다라 크림은 이미퀴모드 성분으로 면역세포를 자극해 항바이러스 효과를 내는데, 적응증은 생식기·항문 주위 사마귀, 광선각화증, 표재성 기저세포암이라 **편평사마귀 적응증 외 사용은 권장되지 않습니다**.

경구약 시메티딘은 체중 1kg당 40mg 고용량으로 사용했을 때 세포매개 면역을 강화해 효과가 있다는 논문이 있지만, 일부 환자에서만 효과가 있는 오프라벨 치료이고 간수치 상승·여성형 유방·유즙 분비 같은 부작용이 있어 제한적으로 사용됩니다. **자궁경부암 4가 백신은 6, 11, 16, 18번형을 예방하므로** 3·10·28번형이 원인인 편평사마귀에는 큰 효과가 없지만, 사례 보고가 있고 남녀 모두 권고되는 백신이라 미접종자라면 권해 드립니다.$AAA$, array['알다라크림', '이미퀴모드', '시메티딘', '자궁경부암백신', 'HPV']::text[], 2024, '5mA2eVFd5Bw-2', 'https://youtu.be/5mA2eVFd5Bw?t=215s', null, '2024-05-07 00:00:00+00'::timestamptz, '2024-05-07 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$편평사마귀 레이저 치료는 재발하면 어떻게 해야 하나요?$AAQ$, $AAA$재발하더라도 빠른 시간 내에 재치료를 반복하는 것이 완치율을 높이는 방법입니다. 레이저는 깎아 없앤 병변은 제거되지만 시술 당시 거의 보이지 않던 병변이 있을 수 있고, **바이러스 자체가 레이저로 완전히 제거되는 것은 아니다 보니 재발할 수밖에 없어요**.

그래서 제거 후에도 병변이 재발하지 않는지 잘 살펴보고, 관찰되면 빠른 시간 내에 피부과에서 치료받는 것을 반복하다 보면 **완치율이 점점 높아지고 재발하더라도 이전보다 훨씬 적게 발생합니다**. 의사마다 시술 방법이 달라 모든 병원이 재생테이프를 붙이는 건 아니고, 편평사마귀는 표피층 변화만 동반되는 병변이라 깎아낼 필요가 없어 테이프 없이 시술하기도 해요. 이 경우 물이 닿아도 돼 가벼운 세안이 가능하고 접촉피부염이 있는 분에게도 시술할 수 있다는 장점이 있습니다.$AAA$, array['사마귀레이저', '이산화탄소레이저', '재발치료', '재생테이프', '어붐야그']::text[], 2024, '5mA2eVFd5Bw-3', 'https://youtu.be/5mA2eVFd5Bw?t=329s', null, '2024-05-07 00:00:00+00'::timestamptz, '2024-05-07 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$임산부에게 편평사마귀가 빠르게 번지면 어떻게 하나요?$AAQ$, $AAA$면역력이 떨어진 임산부에서는 빠르게 번질 수 있어, 출산 후 가급적 빨리 피부과에서 제거하는 것이 권장됩니다. 임산부에서 편평사마귀가 빠르게 번지는 경우가 많고, **수유를 하는 가슴 부위까지 번지는 경우도 있어** 가족 전염 위험이 함께 커지기 때문이에요.

편평사마귀는 감기처럼 바이러스 질환이라 치료가 재발을 완전히 막지는 못하지만, 점차 번지고 가족에게 전염될 수 있어 손 놓고 있을 수는 없습니다. 출산 직후 제거가 어렵다면 재발과 번짐을 막기 위해 **면역력을 높이기 위해 스트레스를 조절하고 적당한 운동과 균형 잡힌 식습관과 수면의 질을 높이는 노력**이 도움이 됩니다. 비타민·영양제도 예방에 도움이 될 수 있습니다.$AAA$, array['임산부사마귀', '면역력저하', '수유부위전염', '출산후치료', '가족전염']::text[], 2024, '5mA2eVFd5Bw-4', 'https://youtu.be/5mA2eVFd5Bw?t=366s', null, '2024-05-07 00:00:00+00'::timestamptz, '2024-05-07 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$기미 연고는 어떤 성분으로 만들어지고 어떻게 작용하나요?$AAQ$, $AAA$기미 연고는 1975년 알버트 클리그만이 제시한 클리그만 포뮬러를 기반으로 한 세 가지 성분의 조합입니다. 색소를 만드는 타이로신아제 효소를 저해하는 **하이드로퀴논이라는 미백 성분**, 노화된 진피를 더 탄탄하게 만들어주는 트레티노인이라는 레티노이드 계열 약물, 그리고 스테로이드로 구성됩니다.

스테로이드는 그 자체로도 피부를 밝게 해주는 역할을 하면서 동시에 하이드로퀴논과 트레티노인을 발랐을 때 생길 수 있는 자극과 염증 반응을 줄여 줍니다. 처음 사용된 함량은 **하이드로퀴논 5%, 트레티노인 0.1%, 덱사메타손 0.1%였는데**, 자극감이 너무 심해 국내에서는 농도를 낮춰 판매하고 있어요. 매일매일 5~7주 정도 도포하면 기미와 주근깨 같은 색소가 좋아진다고 보고된 논문이 있습니다.$AAA$, array['클리그만포뮬러', '하이드로퀴논', '트레티노인', '스테로이드', '타이로신아제']::text[], 2024, 'uL935Bc3mpQ-1', 'https://youtu.be/uL935Bc3mpQ?t=73s', null, '2024-05-09 00:00:00+00'::timestamptz, '2024-05-09 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$트리루스트라와 멜라논 크림은 어떻게 다른가요?$AAQ$, $AAA$트리루스트라가 더 자극적이고, 멜라논 크림이 더 순한 편이라는 점에서 본질적으로 다른 두 제품입니다. 트리루스트라는 갈더마 트리루마크림의 국내 카피 약으로, 하이드로퀴논 4%·트레티노인 0.05%에 한 단계 더 강한 스테로이드인 플루오시놀아세토니드를 사용했어요. 원래 포뮬러보다는 덜 자극적이지만 동양인에게는 자극이 되는 경우가 많았습니다.

그래서 트레티노인을 확 줄인 게 동아제약 멜라논 크림이에요. **하이드로퀴논 5%는 그대로 두고 트레티노인을 0.003%로 많이 낮췄고**, 스테로이드도 약한 하이드로코티손으로 배합했습니다. 따라서 **피부가 민감한 편이라면 트리루스트라보다는 멜라논 크림을 사용하는 게 더 안전하다**고 보면 됩니다. 처음 약 3개월은 이런 복합 제제를 쓰고, 이후에는 스티바A 크림·아크리프 같은 레티노이드나 다른 미백 기능성 화장품으로 유지하는 흐름이 권장됩니다.$AAA$, array['트리루스트라', '멜라논크림', '트리루마', '민감피부', '기미연고선택']::text[], 2024, 'uL935Bc3mpQ-2', 'https://youtu.be/uL935Bc3mpQ?t=170s', null, '2024-05-09 00:00:00+00'::timestamptz, '2024-05-09 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$기미 연고를 오래 쓰면 어떤 부작용이 생길 수 있나요?$AAQ$, $AAA$기미 연고는 효과적인 미백 성분이지만 안심하고 오래 쓸 수 있는 것은 아닌 양날의 검입니다. 흔하게는 자극적 성분으로 인한 접촉 피부염, 각질이 일어남, 홍조가 생길 수 있고, 스테로이드 성분이라 장기간 사용했을 때 **혈관 확장과 피부 위축 같은 부작용**이 생길 수 있습니다.

가장 문제가 될 수 있는 건 하이드로퀴논 장기 도포로 피부가 도리어 까매지는 외인성 갈색증, 또는 반대로 색이 빠지는 백색 피부증입니다. 이 때문에 미국에서는 처방전 없이는 하이드로퀴논 제품을 못 사도록 규정을 만들었어요. 부작용은 주로 피부색이 어두울수록, 4%가 넘는 농도를 몇 년간 사용했을 때 위험이 올라가지만 **1% 낮은 농도나 6개월 이내 사용에서도 생긴 보고**가 있어, 하이드로퀴논 함량 4% 이내·연속 사용 3개월 이내, 전문의 상담 후 사용이 권장됩니다.$AAA$, array['외인성갈색증', '백색피부증', '하이드로퀴논부작용', '피부위축', '장기사용금기']::text[], 2024, 'uL935Bc3mpQ-3', 'https://youtu.be/uL935Bc3mpQ?t=255s', null, '2024-05-09 00:00:00+00'::timestamptz, '2024-05-09 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$기미 연고는 어떻게 발라야 자극이 덜한가요?$AAQ$, $AAA$기미 연고는 꼭 밤에만 사용하고, 처음에는 로션 위에 소량만 도포하는 것이 자극을 줄이는 핵심입니다. 자극이 되는 성분이므로 부작용을 최소화하기 위해서는 **밤에만 사용**해야 하고, 처음 바를 때는 로션 같은 기초 화장품을 먼저 바른 뒤 마지막으로 색소 있는 부위에 소량만 도포하는 것이 좋아요.

적응이 어느 정도 되면 맨 피부에 연고를 먼저 바르고 그 위에 로션을 덧발라도 되지만, **초기에 사용할 때는 로션으로 막을 만들어 준 다음에 연고를 바르는 것**이 자극감을 줄여 줍니다. 낮에 외출할 때는 자외선 차단제도 잘 발라줘야 하고, 레이저 치료를 강하게 받는다면 피부가 민감해진 상태라 부작용 확률이 높아질 수 있어 담당 의사와 상의 후 사용하는 것이 좋습니다. 연속 사용 기간은 가급적 3개월을 넘기지 마세요.$AAA$, array['기미연고사용법', '자외선차단', '야간도포', '민감피부적응', '레이저병행']::text[], 2024, 'uL935Bc3mpQ-4', 'https://youtu.be/uL935Bc3mpQ?t=345s', null, '2024-05-09 00:00:00+00'::timestamptz, '2024-05-09 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$스킨보톡스 효과는 얼마나 가나요?$AAQ$, $AAA$스킨보톡스는 **3~4개월 간격으로 맞는** 시술입니다. 5~6개월 간격으로 맞는 근육보톡스에 비해 효과 지속이 짧은데, 이는 보톡스를 많이 희석해서 피부층에 얇게 주사하기 때문이에요. 너무 진한 농도로 주사하면 용량이 과해져 표정이 이상해지거나 입이 비뚤어지는 부작용이 있을 수 있어 적당한 농도가 권장됩니다.

짧게 지속되더라도 꾸준히 맞으면 누적 효과가 있는데, 13년 동안 연 2~3회씩 미간과 이마 보톡스를 맞은 일란성 쌍둥이는 13년간 단 2회만 받은 쌍둥이보다 이마 잔주름이 거의 없었어요. 보톡스를 반복해서 맞으면 그 시간만큼 피부가 주름지는 것으로부터 보호되어 노화가 천천히 이루어집니다. **1년에 3번, 5분씩만 투자해서 노화를 미룰 수 있다는 점이** 강조됩니다.$AAA$, array['스킨보톡스주기', '보톡스희석', '쌍둥이연구', '노화지연', '잔주름']::text[], 2024, 'iXoBCDGSN5k-1', 'https://youtu.be/iXoBCDGSN5k?t=85s', null, '2024-05-14 00:00:00+00'::timestamptz, '2024-05-14 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$보톡스를 자주 맞으면 내성이 정말 생기나요?$AAQ$, $AAA$반은 맞고 반은 틀린 이야기로, 시술 빈도와 보톡스 분자 크기가 내성 생성에 영향을 줍니다. 내성은 우리 몸이 보톡스를 이물질로 인식해 항체를 만들어 제거해버려 효과를 못 내게 되는 현상입니다. **시술 빈도가 늘어나면 그만큼 내성이 생길 확률이 늘어나고**, 보톡스 중에서도 덩치가 큰 종류가 잡힐 확률이 더 높습니다.

보톡스는 실제 기능을 하는 빨간 부분과 이를 감싸는 단백질로 구성돼 있는데, **단백질 부분을 제거하고 순수하게 기능 부분만 남긴 2세대 보톡스가 제오민**입니다. 단백질이 없어 내성이 생길 확률이 현저히 낮은 대신 가격이 비싸요. 그래서 나온 게 코어톡스인데, 제오민처럼 크기를 줄였으면서 국내산이라 가격이 저렴합니다. 내성이 고민이라면 제오민이나 코어톡스로 시술받는 것을 고려해볼 만합니다.$AAA$, array['보톡스내성', '제오민', '코어톡스', '항체생성', '2세대보톡스']::text[], 2024, 'iXoBCDGSN5k-2', 'https://youtu.be/iXoBCDGSN5k?t=157s', null, '2024-05-14 00:00:00+00'::timestamptz, '2024-05-14 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$스킨보톡스가 많이 아프다고 하는데 정말 그런가요?$AAQ$, $AAA$스킨보톡스는 엄청 아픈 시술이 맞습니다. 근육 보톡스처럼 한두 부위만 맞는 게 아니라 얼굴 전체에 맞다 보니 아프고, **근육층보다 피부 층에 신경이 더 많이 분포하기 때문**에 더 아픕니다. 그래서 스킨보톡스를 받는데 많이 아프지 않다면 피부층에 잘 들어가고 있는지 의심해 봐야 해요.

통증을 줄이려면 **마취크림을 1시간 이상 바르는 것이 추천**되고, 그래도 너무 무섭다면 수면마취나 비수면 호흡마취를 권합니다. 일반적인 부작용으로는 주사 시술 시 생기는 멍이 있을 수 있고, 입가 근육에 작용해 근육을 마비시키면 밥을 먹거나 말할 때 표정이 다소 부자연스러워질 수 있어요. 너무 깊게 주입되면 얼굴 근육에 영향을 미쳐 표정이 어색해질 수 있어 시술자의 섬세한 주입이 중요합니다.$AAA$, array['스킨보톡스통증', '마취크림', '신경분포', '주사부작용', '근육마비']::text[], 2024, 'iXoBCDGSN5k-3', 'https://youtu.be/iXoBCDGSN5k?t=296s', null, '2024-05-14 00:00:00+00'::timestamptz, '2024-05-14 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$스킨보톡스를 받으면 모공과 피부결이 정말 좋아지나요?$AAQ$, $AAA$62명을 대상으로 한 논문에서 시술 90일 후 피부 거친 정도와 모공이 의미 있게 개선된 것으로 나타났습니다. 시술 전과 후를 비교한 결과 **피부 거친 정도는 7.5점에서 5점으로 약 30% 가량 감소했고**, 모공 점수도 3점에서 5점으로 개선됐어요. 점수가 높을수록 모공이 안 보이는 척도라는 점도 함께 제시됐습니다.

원리는 보톡스가 피부에 작용하면 모공 크기를 줄이고 피지 분비를 효과적으로 줄여 피부 요철이 줄어들기 때문이에요. 그 결과 **속광이 도는 듯한 반들반들한 피부**가 됩니다. 다만 스킨보톡스는 확 예뻐지는 시술이 아니라 한 듯 안 한 듯 자연스럽게 피부결을 좋게 하고 환한 인상을 만들어주는 시술입니다. 시술 시 잡혔으면 하는 잔주름이 있다면 상담 때 꼭 말씀해 주시는 것이 좋습니다.$AAA$, array['모공축소', '피지분비감소', '피부결개선', '속광', '보톡스효과논문']::text[], 2024, 'iXoBCDGSN5k-4', 'https://youtu.be/iXoBCDGSN5k?t=336s', null, '2024-05-14 00:00:00+00'::timestamptz, '2024-05-14 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$스스로 짜도 되는 여드름과 짜면 안 되는 여드름은 어떻게 구분하나요?$AAQ$, $AAA$크기가 작고 노란 농이 표면에 맺힌 여드름은 면봉으로 살짝 압출해도 되지만, 딱딱하고 아픈 여드름은 절대 건드리면 안 됩니다. 염증 단계가 지나면 붉은기가 줄고 죽은 피부 조직과 염증 세포가 섞이면서 노랗게 농이 생기는데, 이 상태는 어차피 세수나 로션 도중 자연스럽게 터지기도 해서 혼자 처치해도 됩니다.

반면 만지기만 해도 아프고 단단한 느낌의 여드름은 **염증이 깊이 자리하고 있어 손으로는 깨끗하게 짜낼 수 없습니다.** 무리하게 건드리면 염증이 더 커지거나 주변 피부에 상처가 나서 흉터로 남습니다. 이런 경우 병원에서 염증 주사를 맞고 도구로 배출구를 만든 뒤 압출하는 것이 가장 좋고, 하얀 좁쌀 여드름도 피지가 피부 밑에 뭉친 형태여서 짜기보다는 디페린·아크리프 같은 레티노이드 연고로 관리하는 것이 적합합니다.$AAA$, array['여드름압출', '농포여드름', '결절여드름', '좁쌀여드름', '흉터예방']::text[], 2024, 'fyWzqW2gDoo-1', 'https://youtu.be/fyWzqW2gDoo?t=42s', null, '2024-05-21 00:00:00+00'::timestamptz, '2024-05-21 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$염증 주사는 어떤 성분이고 모든 여드름에 맞아도 되나요?$AAQ$, $AAA$염증 주사는 트리암시놀론이라는 스테로이드를 묽게 희석해서 모낭 주변 염증 세포에 주사하는 치료입니다. 비장의 약물이 따로 있는 것은 아니고 아주 작은 주사기로 모낭 주변 염증 세포가 모인 곳에 약물을 넣어 염증을 가라앉히는 방식입니다.

모든 여드름에 맞을 수 있는 것은 아니고, **깊고 단단한 빨간 몽우리 형태의 병변에만** 맞으시는 게 좋습니다. 얕고 작은 병변에 주사하면 스테로이드 때문에 피부가 일시적으로 함몰될 수 있고, 그런 작은 병변은 연고나 약으로도 어느 정도 가라앉힐 수 있습니다. 당장 병원에 가기 어렵다면 애크논 연고를 듬뿍 바르고 반창고로 덮어두는 방법으로 빨갛고 아픈 증상을 어느 정도 완화할 수 있습니다.$AAA$, array['염증주사', '트리암시놀론', '스테로이드주사', '결절여드름', '애크논']::text[], 2024, 'fyWzqW2gDoo-2', 'https://youtu.be/fyWzqW2gDoo?t=316s', null, '2024-05-21 00:00:00+00'::timestamptz, '2024-05-21 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$여드름 패치 두 종류는 언제 어떻게 구분해서 써야 하나요?$AAQ$, $AAA$여드름 패치는 짠 후 붙이는 하이드로콜로이드 단독 패치와 짜기 전에 붙이는 기능성 성분 패치로 나뉩니다. 짜고 난 후에는 엘라밴드 같은 하이드로콜로이드 필름 단독 제품이 진물을 빨아들이고 상처를 드레싱해주는 역할을 합니다.

짜기 전에 쓰는 패치는 **티트리·나이아신아마이드·판테놀·병풀추출물·살리실산** 같은 진정·재생 성분이 들어 있고, 어떤 제품은 끝에 돌기가 달려 유효성분을 더 깊이 침투시키도록 만들어졌습니다. 초기 붉어진 단계엔 릴리프 제품, 살짝 단단한 단계엔 돌기 달린 제품을 쓰고, 진물이 나는 상처엔 기능성 성분이 자극이 될 수 있으니 하이드로콜로이드 단독 패치가 적합합니다. 패치는 스킨케어 전에 세안 직후 물기를 닦고 붙이는 것이 유효성분 전달에 더 효과적입니다.$AAA$, array['여드름패치', '하이드로콜로이드', '릴리프패치', '스팟패치', '패치사용법']::text[], 2024, 'fyWzqW2gDoo-3', 'https://youtu.be/fyWzqW2gDoo?t=380s', null, '2024-05-21 00:00:00+00'::timestamptz, '2024-05-21 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$입 주변 여드름이 자꾸 나는데 어떻게 관리해야 하나요?$AAQ$, $AAA$입 주변과 턱은 성인형 여드름이 자주 생기는 대표적인 U존 부위로, 꼼꼼한 세안과 모공이 막히지 않는 화장품 선택이 핵심입니다. 호르몬뿐 아니라 스트레스·수면·생활습관·화장·세안 루틴 등 다양한 원인이 작용하고 입 주변 자체 피부 특성도 기여합니다.

선크림이나 화장품 잔여물이 입 주변 오목한 곳에 남아 모공을 막기 쉬우므로 입 주변과 턱 밑까지 깔끔하게 씻고, 헤어 제품도 충분히 헹궈내야 합니다. 평소엔 **살리실산 성분의 폼클렌저로 과도한 각질을 줄이고 논코메도제닉 화장품**을 사용하는 것이 좋습니다. 연고는 피지를 녹이는 디페린이나 약국에서 살 수 있는 아젤리아(아젤라익산) 연고가 도움이 되고, 큰 염증이 반복되면 먹는 약·염증 주사 또는 피지샘을 억제하는 레이저를 국소적으로 시술해 트러블 양을 줄일 수 있습니다.$AAA$, array['입주변여드름', 'U존트러블', '성인여드름', '논코메도제닉', '아젤라익산']::text[], 2024, 'fyWzqW2gDoo-4', 'https://youtu.be/fyWzqW2gDoo?t=530s', null, '2024-05-21 00:00:00+00'::timestamptz, '2024-05-21 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$심술보(마리오네트 라인)는 왜 생기나요?$AAQ$, $AAA$심술보는 입꼬리 내림근의 과한 수축과 중력에 의한 처짐, 두 가지가 합쳐져 생깁니다. 마리오네트 라인은 인형극에서 줄에 매달려 움직이는 인형의 입 주변 주름과 비슷하게 입 옆에 잡히는 주름을 말합니다.

첫 번째 원인은 입꼬리를 내리는 근육의 과도한 수축으로, 본인도 모르는 사이 평소에 이 근육에 힘이 들어가 있는 경우가 많습니다. 두 번째 원인은 **유지인대가 탄력을 잃으면서 지방층이 중력에 의해 더 축 늘어지는 것**입니다. 유지인대는 지방층을 끈처럼 지탱하는 구조물인데, 나이가 들면 점점 힘을 잃어 처짐이 심해집니다. 결국 근육의 과사용과 구조물 약화가 동시에 진행되면서 입 옆에 깊은 선이 자리잡는 것입니다.$AAA$, array['마리오네트라인', '심술보', '입꼬리내림근', '유지인대', '노화주름']::text[], 2024, 'ZuOad5VN0dk-1', 'https://youtu.be/ZuOad5VN0dk?t=84s', null, '2024-05-24 00:00:00+00'::timestamptz, '2024-05-24 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$심술보에 울쎄라는 왜 권하지 않나요?$AAQ$, $AAA$울쎄라는 심술보 부위에 신경 손상 위험이 있어 먼저 추천하지 않는 시술입니다. 울쎄라는 턱 라인 잡는 데는 좋지만, 심술보를 따라 지나가는 신경이 있어 입 주변에는 주의가 필요합니다.

울쎄라는 순간적으로 높은 열을 점으로 만들고 그 점이 신경에 닿으면 손상이 옵니다. **잘못하면 입이 돌아갈 수도 있는데**, 대부분 회복은 되지만 몇 달 정도 양치질할 때 물이 새거나 웃을 때 입이 삐뚤어지는 경우가 생깁니다. 실제 울쎄라 프로토콜에도 심술보 부위는 신경 표시와 함께 시술하지 말라고 표기되어 있고, 또 지방세포 파괴로 인한 볼꺼짐 부작용도 함께 고려해야 합니다. 그래서 심술보에는 점이 아닌 차곡차곡 열을 쌓아 올리는 방식인 티타늄 리프팅을 선호합니다.$AAA$, array['울쎄라', '심술보시술', '신경손상', '안면신경', '리프팅부작용']::text[], 2024, 'ZuOad5VN0dk-2', 'https://youtu.be/ZuOad5VN0dk?t=299s', null, '2024-05-24 00:00:00+00'::timestamptz, '2024-05-24 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$티타늄 리프팅은 울쎄라와 어떻게 다른가요?$AAQ$, $AAA$티타늄 리프팅은 서서히 열을 쌓아 올리는 방식이라 울쎄라보다 신경 손상과 볼꺼짐 위험이 낮은 시술입니다. 원래는 제모 레이저인데 검정·빨강·물에 반응해 열을 주는 원리를 리프팅에 응용한 것입니다.

울쎄라가 순간적으로 높은 열을 점으로 만들어 신경에 닿으면 손상이 오는 반면, **티타늄은 서서히 차곡차곡 열을 쌓아 나가는 방식이라** 입 주변이나 광대 밑에 시술해도 부작용이 적습니다. 지방세포가 파괴되어 볼꺼짐이 생길 수 있는 울쎄라와 달리 티타늄은 지방세포가 파괴되지 않고, 이불을 압축팩에 넣었다가 시간이 지나면 손상 없이 돌아오는 것과 비슷합니다. 다만 유지 기간이 다소 짧은 편이어서 써마지·오푸스·3DEEP 같은 고주파 시술과 병합하면 시너지가 좋습니다.$AAA$, array['티타늄리프팅', '울쎄라비교', '고주파병합', '심술보치료', '비절개리프팅']::text[], 2024, 'ZuOad5VN0dk-3', 'https://youtu.be/ZuOad5VN0dk?t=359s', null, '2024-05-24 00:00:00+00'::timestamptz, '2024-05-24 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$심술보가 살짝 보이기 시작할 때 집에서 어떻게 관리할 수 있나요?$AAQ$, $AAA$심술보 초기에는 입꼬리 내림근의 긴장을 푸는 습관 교정과 볼살 유지가 가장 기본적인 관리입니다. 평소 윗어금니와 아래어금니 사이를 꽉 깨물지 않고 살짝 벌린 뒤 입술을 가볍게 다무는 자세를 의식적으로 연습하시면 좋습니다.

마치 여권 사진을 찍을 때처럼 자연스러운 표정인데, 처음엔 어색해도 정상입니다. **입꼬리 내림근이 많이 경직되어 있어서** 의식하지 않으면 잘 안 되는 경우가 많고, 잘 안 되면 입꼬리 옆을 살살 문질러 스트레칭하듯 풀어주는 것도 도움이 됩니다. 중력에 대한 대비로는 적절한 볼살을 유지하는 것이 좋고, 생길락 말락 하는 단계에서는 입꼬리 보톡스 두 방으로 입꼬리가 살짝 올라가는 효과도 기대할 수 있습니다.$AAA$, array['심술보예방', '표정관리', '입꼬리보톡스', '볼살유지', '안면스트레칭']::text[], 2024, 'ZuOad5VN0dk-4', 'https://youtu.be/ZuOad5VN0dk?t=124s', null, '2024-05-24 00:00:00+00'::timestamptz, '2024-05-24 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$약산성과 약알칼리성 클렌저는 어떻게 다른가요?$AAQ$, $AAA$약산성 클렌저는 순한 계면활성제로 피부 장벽을 보호하고, 약알칼리성 클렌저는 세정력이 강한 계면활성제로 피지·메이크업을 깨끗하게 씻어냅니다. 두 제품의 차이는 계면활성제의 강도에 있으며 사용 후 감촉으로도 구분됩니다.

약산성 클렌저는 씻고 난 후 살짝 미끄덩거리고 잘 안 씻긴 듯한 느낌이 들지만 피부 장벽을 무너뜨리지 않습니다. 약알칼리성 클렌저는 씻고 나서 **피부가 당기고 건조한 뽀독한 느낌**이 드는데 메이크업과 피지를 깨끗이 닦아주는 대신 너무 자주 쓰면 장벽이 손상될 수 있습니다. 약알칼리성이라도 판테놀이나 히알루론산 성분이 함께 들어 있으면 세정력은 살리면서 수분감을 줄 수 있어 무조건 약산성이 좋고 약알칼리성이 나쁘다고 단정할 수는 없습니다.$AAA$, array['약산성클렌저', '약알칼리성클렌저', '계면활성제', '폼클렌저', '피부장벽']::text[], 2024, '6NhrPShhmvE-1', 'https://youtu.be/6NhrPShhmvE?t=236s', null, '2024-05-29 00:00:00+00'::timestamptz, '2024-05-29 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$내 피부 타입에 맞는 클렌저는 어떻게 고르나요?$AAQ$, $AAA$건조·예민·홍조 피부엔 순한 약산성, 두껍고 유분기 많은 피부엔 약알칼리성, 복합성 피부는 부위별로 나눠 쓰는 것이 기본입니다. 피부 타입과 컨디션에 따라 같은 사람도 다른 제품을 써야 합니다.

피부가 얇고 건조하며 홍조가 있다면 **순한 약산성 클렌저가 적합**합니다. 반대로 모공이 크고 트러블이 잦은 두꺼운 피부는 세정력이 강한 약알칼리성 클렌저로 가끔 과도한 유분을 빼주는 것이 중요할 수 있습니다. 복합성 피부는 볼은 약산성, T존은 약알칼리성으로 나눠 쓰면 되고, 계절별로는 겨울엔 순한 약산성, 여름엔 세정력 강한 약알칼리성이 적합합니다. 시간대로는 아침엔 간단한 약산성, 저녁 이중세안 마무리엔 적당히 세정력 있는 제품을 쓰는 것이 좋습니다.$AAA$, array['피부타입별클렌저', '복합성피부', '클렌저선택법', '이중세안', '계절별세안']::text[], 2024, '6NhrPShhmvE-2', 'https://youtu.be/6NhrPShhmvE?t=129s', null, '2024-05-29 00:00:00+00'::timestamptz, '2024-05-29 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$거품 테스트로 클렌저 세정력을 어떻게 확인하나요?$AAQ$, $AAA$거품을 내봤을 때 쫀쫀하고 풍성하게 잘 나면 세정력이 강한 클렌저일 가능성이 높습니다. 약산성 클렌저는 약한 계면활성제를 써서 자연스러운 거품이 많이 나지 않기 때문에 거품기가 달려 있는 경우가 많습니다.

거품기로 거품을 냈더라도 비벼보면 금방 사라지는 경우가 약산성이고, **거품이 쫀쫀하고 풍성하게 유지되면 세정력이 좋고 마무리감이 매끈한 약알칼리성**일 가능성이 높습니다. 여드름이 자주 나는 피부는 전성분에서 BHA 성분, 즉 살리실릭애씨드가 들어 있는지 확인하면 좋습니다. 살리실산은 모공 속 피지를 줄이고 염증을 가라앉히는 기능이 있어 트러블성 피부에 도움이 됩니다. 제품 상세 페이지와 전성분을 함께 살펴 본인 피부 컨디션에 맞는 제품을 골라야 합니다.$AAA$, array['거품테스트', '세정력확인', '살리실산', 'BHA클렌저', '전성분확인']::text[], 2024, '6NhrPShhmvE-3', 'https://youtu.be/6NhrPShhmvE?t=389s', null, '2024-05-29 00:00:00+00'::timestamptz, '2024-05-29 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$올바른 세안 방법은 어떻게 되나요?$AAQ$, $AAA$세안 시간은 30초에서 길어도 60초 이내로, 손바닥이 아닌 손가락으로 부드럽게 문지르는 것이 기본 원칙입니다. 계면활성제가 피부에 머무는 시간이 길어지면 자극이 누적되기 때문입니다.

거품을 충분히 낸 다음 피부에 마사지하는 시간을 **30초 정도, 길어도 60초로 짧게 유지**하는 것이 좋습니다. 손바닥은 손가락보다 면적이 넓고 거칠어 피부에 자극이 되므로 손가락으로 부드럽게 세안해야 하고, 시간대에 따라 아침은 순한 약산성, 저녁은 세정력 있는 제품으로 나눠 씁니다. 부위별로도 건조한 볼은 약산성, 유분기 많은 T존은 세정력 있는 제품을 적용할 수 있습니다. 세안제와 세안법만 바꿔도 피부가 좋아지는 차이를 체감할 수 있습니다.$AAA$, array['세안시간', '세안방법', '손가락세안', '부위별세안', '세안루틴']::text[], 2024, '6NhrPShhmvE-4', 'https://youtu.be/6NhrPShhmvE?t=475s', null, '2024-05-29 00:00:00+00'::timestamptz, '2024-05-29 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$선크림 바른 다음에도 이중세안을 꼭 해야 하나요?$AAQ$, $AAA$기름 성분이 많은 일반 선크림은 폼클렌저만으로 깨끗이 지워지지 않아 클렌징 오일이나 밤으로 1차 세안이 필요합니다. 실제로 손등에 선크림을 펴 바르고 폼클렌저로만 씻어 보면 잔주름 사이사이에 선크림이 그대로 남는 것을 볼 수 있습니다.

자외선 차단제는 기본적으로 기름 성분이 많이 들어 있고, 특히 **백탁이 일어나는 무기자차는 폼클렌저만으로는 깨끗하게 지울 수 없습니다.** 그래서 기름은 기름으로 닦아내듯 클렌징 오일이나 밤으로 1차 세안을 한 뒤 2차로 폼클렌저로 마무리해야 합니다. 다만 이지워시 타입이라고 표기되어 있거나 물리적 차단제가 들어 있지 않은 가벼운 사용감의 선크림이라면 폼클렌저 한 번만으로도 깨끗하게 지워질 수 있어 매번 이중세안이 필수는 아닙니다.$AAA$, array['이중세안', '선크림클렌징', '무기자차세안', '클렌징오일', '1차세안']::text[], 2024, '49t9ToD-9zQ-1', 'https://youtu.be/49t9ToD-9zQ?t=46s', null, '2024-06-05 00:00:00+00'::timestamptz, '2024-06-05 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$클렌징 오일을 쓰는데 좁쌀 여드름이 계속 나는 이유는 무엇인가요?$AAQ$, $AAA$클렌징 오일이 제대로 유화되지 않거나 본인 피부 타입에 맞지 않아 모공에 잔여물이 남으면 좁쌀 여드름이 생길 수 있습니다. 오일은 손에 물이 묻지 않은 상태에서 발라 롤링을 시작해야 하고, 이후 손가락에 물을 묻혀 한 번 더 문질러 하얗게 유화시키는 과정이 반드시 필요합니다.

물을 묻힌 손에 오일을 대충 짜서 문지른 뒤 바로 헹구면 **유화 과정이 빠져 오일이 그대로 모공에 남게 되고** 트러블의 원인이 됩니다. 또 다른 이유는 피부 타입 불일치입니다. 트러블성·지성·모공이 큰 피부는 오일이 모공에 남으면 트러블을 유발하기 때문에 클렌징 밀크나 워터처럼 다른 제형을 시도해 보는 것이 좋습니다. 반대로 건조한 피부나 메이크업이 진한 날엔 클렌징 오일이 가장 효과적인 1차 세안제가 됩니다.$AAA$, array['클렌징오일', '유화과정', '좁쌀여드름', '오일사용법', '지성피부클렌징']::text[], 2024, '49t9ToD-9zQ-2', 'https://youtu.be/49t9ToD-9zQ?t=126s', null, '2024-06-05 00:00:00+00'::timestamptz, '2024-06-05 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$클렌징 오일, 밤, 워터, 밀크는 어떻게 다른가요?$AAQ$, $AAA$클렌징 오일이 세정력이 가장 좋고, 밤은 오일과 거의 같은 원리, 워터는 가장 가볍지만 닦아내는 자극이 있으며 밀크와 크림은 중간 제형입니다. 1차 클렌저는 메이크업·선크림·피지 같은 기름 성분을 닦아내는 역할을 합니다.

클렌징 오일은 70~80% 이상이 오일이고 계면활성제가 함께 들어 있어 **메이크업이나 선크림을 가장 잘 씻어내는 제형**입니다. 클렌징 밤은 상온에서 고체가 되는 오일을 모은 것이라 피부 체온에 녹아 오일과 거의 같은 방식으로 작동하며 유화 과정이 필수입니다. 클렌징 워터는 90% 이상이 정제수라 산뜻하지만 화장솜으로 닦아내는 동작이 예민 피부에 자극이 될 수 있습니다. 클렌징 밀크는 묽고 크림은 되직하며 크림 쪽이 기름 성분이 더 많아 세정력이 한 단계 더 좋습니다.$AAA$, array['클렌징오일', '클렌징밤', '클렌징워터', '클렌징밀크', '1차클렌저비교']::text[], 2024, '49t9ToD-9zQ-3', 'https://youtu.be/49t9ToD-9zQ?t=205s', null, '2024-06-05 00:00:00+00'::timestamptz, '2024-06-05 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$클렌징 워터나 패드는 어떤 피부에 비추천인가요?$AAQ$, $AAA$예민하고 얇고 홍조가 있는 피부는 닦아내는 동작 자체가 자극이 되어 클렌징 워터와 패드를 피하는 것이 좋습니다. 화장솜에 적셔 닦아내는 방식이 메이크업 제거 시 힘이 들어가 마찰 자극을 키우기 때문입니다.

피부 장벽이 튼튼한 분에겐 산뜻한 사용감의 좋은 선택일 수 있지만, **얇고 홍조가 있는 예민 피부는 닦아내는 마찰이 자극이 되어** 트러블을 유발할 수 있습니다. 또 대용량 클렌징 패드는 시간이 지나면서 증발해 마지막 부분이 마르고 거칠어지는데, 이런 상태로 사용하면 피부를 상하게 할 수 있으니 절대 사용하지 말아야 합니다. 산뜻한 사용감을 포기할 수 없다면 거품 용기에 클렌징 워터를 넣어 거품으로 세안하는 방법이 대안이 됩니다.$AAA$, array['클렌징워터', '클렌징패드', '예민피부', '홍조피부', '마찰자극']::text[], 2024, '49t9ToD-9zQ-4', 'https://youtu.be/49t9ToD-9zQ?t=303s', null, '2024-06-05 00:00:00+00'::timestamptz, '2024-06-05 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$얼굴 근육 운동(얼굴 홈트)은 왜 필요한가요?$AAQ$, $AAA$써마지·울쎄라·쥬베룩 같은 시술은 대부분 근육까지 영향을 주지 못하기 때문에 얼굴 근육 운동이 빈자리를 채워줍니다. 나이가 들면 피부·지방층·근육이 모두 늘어지고 흘러내리는데, 몸의 근육처럼 얼굴 근육도 강화가 필요합니다.

특히 앞광대를 포함한 **중안면 부위는 지방이 빠지고 큰광대근이 힘을 잃어 처짐이 심해집니다.** 일종의 근손실 현상으로, 큰광대근을 강화시키면 노화 해결에 도움이 됩니다. 핵심은 입을 살짝 벌리고 어금니가 닿지 않게 한 상태에서 혀로 입천장을 살짝 미는 느낌을 주며 활짝 웃는 것입니다. 처음엔 광대 쪽이 떨리거나 뻐근할 수 있는데 안 쓰던 근육을 쓸 때의 정상 반응이고, 미리 살살 문질러 스트레칭하면 도움이 됩니다.$AAA$, array['얼굴홈트', '큰광대근', '중안면노화', '안면근육운동', '동안얼굴']::text[], 2024, '4DdDRwsNibc-1', 'https://youtu.be/4DdDRwsNibc?t=83s', null, '2024-06-11 00:00:00+00'::timestamptz, '2024-06-11 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$입꼬리 당김근 운동은 어떻게 하나요?$AAQ$, $AAA$입을 살짝 벌리고 어금니가 닿지 않은 상태에서 편안하게 미소를 짓고 입꼬리를 당기는 자세를 유지하는 등척성 운동입니다. 손가락으로 입꼬리를 살짝 들어 미소 모양을 잡은 뒤 손가락을 떼면서도 긴장을 늦추지 않고 그 표정을 유지하는 것이 핵심입니다.

이런 운동은 턱걸이가 아니라 **철봉 매달리기 같은 등척성 운동 개념이라** 근육이 울퉁불퉁 벌크업되지 않고 자연스럽게 근력이 늘어납니다. 평소 덜 쓰던 근육을 강화하면 예쁜 표정이 자연스럽게 나옵니다. 시간이 부족하면 큰광대근 운동과 묶어, 입을 살짝 벌리고 혀로 입천장을 미는 느낌으로 활짝 웃으면서 입꼬리를 함께 당기면 됩니다. 잘 안 되는 게 정상이고, 헬스처럼 꾸준히 하면 점차 표정이 좋아지고 어려 보이는 효과가 나타납니다.$AAA$, array['입꼬리당김근', '등척성운동', '표정근운동', '안면스트레칭', '동안운동']::text[], 2024, '4DdDRwsNibc-2', 'https://youtu.be/4DdDRwsNibc?t=218s', null, '2024-06-11 00:00:00+00'::timestamptz, '2024-06-11 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$레비나스와 엠페이스는 각각 어떤 시술인가요?$AAQ$, $AAA$레비나스는 체외 충격파로 근육을 풀어주고 엠페이스는 전기 자극으로 근육을 수축시켜 강화하는 시술입니다. 집에서 하는 얼굴 홈트가 익숙하지 않은 분께 피부과에서 도움을 드릴 수 있는 두 가지 방법입니다.

레비나스는 물리치료에 쓰이는 체외 충격파 장비로 탁탁탁 충격을 줘서 뭉친 근육을 풀어주는데, **일종의 경락처럼 붓기가 빠지고 얼굴이 작아지는 느낌**을 줍니다. 엠페이스는 근육이 전기적 자극을 받으면 스스로 수축하는 원리를 이용해 큰광대근과 입꼬리 당김근을 타겟으로 EMS 자극과 고주파 열을 동시에 줍니다. 시술 받는 본인은 가만히 있어도 근육이 자발적으로 수축하면서 강화됩니다. 다만 정확한 근육을 제대로 자극해야 효과가 있으므로 PT처럼 숙련된 의사에게 받는 것이 중요합니다.$AAA$, array['레비나스', '엠페이스', '체외충격파', 'EMS자극', '안면근육시술']::text[], 2024, '4DdDRwsNibc-3', 'https://youtu.be/4DdDRwsNibc?t=306s', null, '2024-06-11 00:00:00+00'::timestamptz, '2024-06-11 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$얼굴 근육 운동은 얼마나 자주 해야 효과가 있나요?$AAQ$, $AAA$얼굴 근육 운동도 헬스처럼 꾸준함이 가장 중요한 효과 요인입니다. 처음엔 잘 안 되고 광대 쪽이 떨리거나 뻐근한 느낌이 정상이며, 안 쓰던 근육을 쓸 때 누구나 겪는 반응입니다.

무게 못 드는 초보가 시간이 지나면서 들 수 있는 무게가 늘듯, **꾸준히 트레이닝하면 얼굴 근육 근력이 늘어나면서 표정이 점점 좋아집니다.** 5년, 10년 젊어지는 효과까지 기대할 수 있다고 합니다. 집에서 하기 어려우면 트레이너처럼 피부과 도움을 받을 수 있는데, 레비나스로 스트레칭하듯 근육을 풀어주고 엠페이스로 근력 운동을 대신해 처진 지방층을 자연스럽게 리프팅시키는 조합이 효과적입니다. 다만 잘못된 PT가 안 한 것만 못하듯 얼굴 근육 이해가 높은 숙련된 시술자에게 받는 것이 중요합니다.$AAA$, array['얼굴운동빈도', '꾸준함', '동안유지', '근력강화효과', '안면트레이닝']::text[], 2024, '4DdDRwsNibc-4', 'https://youtu.be/4DdDRwsNibc?t=451s', null, '2024-06-11 00:00:00+00'::timestamptz, '2024-06-11 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$선크림은 SPF만 높으면 다 좋은 건가요?$AAQ$, $AAA$SPF만 높다고 좋은 선크림은 아니며, 기미·노화 고민이 있다면 자외선 A와 블루라이트 차단이 더 중요합니다. SPF는 따가운 느낌과 화상을 일으키는 자외선 B의 차단력을 나타내는 지수이지만, 자외선 B는 다행히 유리창을 통과하지 못합니다.

그래서 실내 생활이나 차 운전 위주인 분들은 SPF가 꼭 높을 필요는 없습니다. 정작 유리를 통과하는 빛은 자외선 A와 블루라이트인데, **자외선 A는 피부 깊숙이 들어와 노화와 기미를 악화시킵니다.** 활성산소를 만드는 빛의 비율을 보면 자외선 B가 4%, 자외선 A가 46%, 블루라이트가 50%로 블루라이트의 영향이 가장 큽니다. 따라서 기미가 고민이라면 SPF만 보지 말고 PA 지수와 블루라이트 차단 여부를 함께 확인해야 합니다.$AAA$, array['SPF오해', '자외선A차단', '블루라이트', '활성산소', '기미예방']::text[], 2024, 'uPa-DvAheIo-1', 'https://youtu.be/uPa-DvAheIo?t=62s', null, '2024-06-19 00:00:00+00'::timestamptz, '2024-06-19 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$블루라이트는 어떻게 차단할 수 있나요?$AAQ$, $AAA$블루라이트 차단 수치는 선크림에 표기되지 않으므로 산화철 성분이 들어 있는 제품을 선택하는 것이 방법입니다. 산화철은 공식 자외선 차단 성분은 아니지만 피부색을 표현하기 위해 비비나 파운데이션에 들어가는 성분으로, 블루라이트를 차단하는 효과가 있습니다.

전자기기에서 나오는 블루라이트보다 **햇빛 속 블루라이트 양이 10배 더 많고**, 자외선 A보다도 활성산소를 더 많이 만들어내기 때문에 차단이 중요합니다. 선크림 전성분에 적색산화철·황색산화철·흑색산화철이 포함되어 있는지 확인하면 되고, 톤업 선크림은 보통 산화철 성분이 들어 있습니다. 만약 쓰는 선크림에 산화철이 없다면 선크림을 바른 뒤 비비크림이나 파운데이션을 한 번 더 덧발라 주는 것으로 블루라이트 차단 효과를 충분히 얻을 수 있습니다.$AAA$, array['블루라이트차단', '산화철성분', '톤업선크림', '비비크림', '기미관리']::text[], 2024, 'uPa-DvAheIo-2', 'https://youtu.be/uPa-DvAheIo?t=176s', null, '2024-06-19 00:00:00+00'::timestamptz, '2024-06-19 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$무기자차와 유기자차는 어떻게 다른가요?$AAQ$, $AAA$무기자차는 피부 표면에 막을 형성해 자외선을 반사·산란시키고, 유기자차는 피부에 흡수되어 자외선의 열을 흡수합니다. 자차는 자외선 차단제의 줄임말로 작용 방식에 따라 둘로 나뉩니다.

무기자차는 발랐을 때 **하얀 막을 형성해 자외선을 차단하지만 백탁 현상이 따라옵니다.** 유기자차는 화학 성분이 피부에 흡수되어 작용하기 때문에 민감성 피부에서는 눈 시림이나 따가움이 생길 수 있습니다. 그래서 민감성 피부에는 무기자차를 권하는 편입니다. 두 방식의 장점을 결합한 혼합자차도 있는데, 백탁이 살짝 있지만 심하지 않고 로션처럼 부드럽게 발리며 촉촉하게 마무리됩니다. 톤업이 부담스러운 분에겐 산화철 없이 자외선 A를 가장 많이 차단하는 멕소릴 400 성분 제품이 대안이 됩니다.$AAA$, array['무기자차', '유기자차', '민감성피부선크림', '백탁현상', '혼합자차']::text[], 2024, 'uPa-DvAheIo-3', 'https://youtu.be/uPa-DvAheIo?t=274s', null, '2024-06-19 00:00:00+00'::timestamptz, '2024-06-19 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$기미가 있는 사람에게 맞는 선크림 사용법은 무엇인가요?$AAQ$, $AAA$기미가 있다면 PA 지수가 높고 산화철 성분이 포함된 선크림을 쓰거나, 산화철 없는 선크림 위에 비비·파운데이션을 덧발라 블루라이트까지 차단해야 합니다. SPF만 보지 말고 PA 지수와 자외선 A·블루라이트 차단을 함께 챙기는 것이 핵심입니다.

외출 시엔 SPF50·PA++++ 무기자차에 산화철이 함께 들어간 제품이 자외선 A와 블루라이트까지 차단해주어 좋고, 화장하는 날엔 산화철 없는 보습형 선크림 위에 **비비크림을 덧발라 블루라이트를 충분히 잘 차단할 수 있습니다.** 톤업이 부담스러우면 멕소릴 400 성분이 들어간 선크림처럼 색상 없이 자외선 A 전 파장을 차단하는 제품도 대안입니다. 가장 중요한 것은 발림감·눈 시림·사용감이 본인에게 맞아야 자주 덧바르게 되고 결국 차단 효과가 유지된다는 점입니다.$AAA$, array['기미선크림', 'PA지수', '산화철선크림', '선크림덧바르기', '멕소릴400']::text[], 2024, 'uPa-DvAheIo-4', 'https://youtu.be/uPa-DvAheIo?t=211s', null, '2024-06-19 00:00:00+00'::timestamptz, '2024-06-19 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$얼굴 전체 제모 레이저는 어떤 사람에게 추천하나요?$AAQ$, $AAA$얼굴 제모 레이저는 화장이 잘 뜨거나 칙칙해 보이는 사람, 코·나비존 블랙헤드처럼 보이는 짧은 털이 있는 사람, 모낭염·여드름·홍조 고민이 있는 사람에게 추천됩니다. 솜털이 많으면 본인은 모른 채로 얼굴이 어둡고 칙칙해 보이는 경우가 많습니다.

피부샵의 더마플래닝이나 왁싱은 털만 깎거나 뽑아내기 때문에 효과가 지속되지 못하고 자극으로 인그로운 헤어 트러블이 잘 생깁니다. 반면 **제모 레이저는 털집 자체를 지속적으로 파괴해 반영구적 제모로 갈 수 있고** 자극도 더 적습니다. 코 주변에 블랙헤드처럼 보이는 까만 점은 사진을 확대해 보면 사실 소극성 속모증으로, 모공에 짧은 털이 자라난 것이라 제모 레이저로 쉽게 해결됩니다. 여드름·모낭염·홍조도 털과 함께 붙은 피지선에서 기인하므로 털밭을 없애면 증상이 좋아질 수 있습니다.$AAA$, array['얼굴제모레이저', '솜털제거', '소극성속모증', '모낭염개선', '화장뜸']::text[], 2024, '_OzrE2BwSU8-1', 'https://youtu.be/_OzrE2BwSU8?t=70s', null, '2024-06-25 00:00:00+00'::timestamptz, '2024-06-25 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$얼굴 제모 레이저는 어떤 원리로 모낭염·홍조에도 효과가 있나요?$AAQ$, $AAA$털과 피지선은 바늘과 실처럼 붙어 있어 털집을 파괴하면 피지선 관련 트러블도 함께 줄어듭니다. 피부에 털이 존재하는 곳에는 전부 피지선이 붙어 있고, 이 피지선의 과다 분비와 막힘이 블랙헤드·화이트헤드·여드름의 시작입니다.

블랙헤드와 화이트헤드에 피부에 함께 사는 여드름균이 감염되면 붉은 여드름으로 진행되고, 홍조 부위를 확대해 보면 **모낭 주위에 염증 세포가 몰리면서 혈관이 늘어나 있는 모습**을 볼 수 있습니다. 즉 여드름·모낭염·홍조가 모두 털과 피지선에서 기인하기 때문에 근본적으로 털밭을 없애주면 증상이 좋아질 수 있는 것입니다. 얼굴의 솜털은 머리카락·눈썹·코털과 달리 거의 기능을 하지 않는다고 알려져 있고, 솜털 제거가 피부를 예민하게 만든다는 객관적 자료는 아직 입증된 바가 없습니다.$AAA$, array['제모레이저원리', '피지선', '모낭염기전', '홍조개선', '여드름원인']::text[], 2024, '_OzrE2BwSU8-2', 'https://youtu.be/_OzrE2BwSU8?t=198s', null, '2024-06-25 00:00:00+00'::timestamptz, '2024-06-25 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$얼굴 제모 레이저는 몇 회 받아야 효과가 있나요?$AAQ$, $AAA$솜털이 많은 경우 1회 시술만으로도 얼굴이 매끈해지지만, 그 외 일반적인 경우에는 4주 간격으로 5회 정도면 만족감을 느낄 수 있습니다. 환자 대부분이 5회 시점에서 만족하고 이후 10회·15회로 연장하는데, 회차가 거듭될수록 효과가 더 뚜렷해집니다.

첫 사진 사례는 5회 시행 후의 결과이고, 모낭염·홍조로 스트레스가 컸던 두 번째 사례는 **5회 후 만족해 연장해 10회까지 받고 더 좋아진 모습**입니다. 4주 간격이라 자주 방문할 필요가 없고 적은 횟수로도 효과를 보는 것이 큰 장점입니다. 시술 후엔 자극감이나 특별한 불편이 없고 10분 정도 진정 팩만 올려주면 일상생활이 바로 가능하기 때문에 더 매력적입니다. 다만 모든 시술이 그렇듯 효과 예측이 가능한 시술자에게 충분한 상담 후 결정해야 합니다.$AAA$, array['제모레이저횟수', '5회시술', '4주간격', '효과지속', '다운타임']::text[], 2024, '_OzrE2BwSU8-3', 'https://youtu.be/_OzrE2BwSU8?t=358s', null, '2024-06-25 00:00:00+00'::timestamptz, '2024-06-25 00:00:00+00'::timestamptz),
  ('93b30a7c-bd6f-4a98-b7fe-2c169cf07962'::uuid, 'qa', 'qa', 'published', true, $AAQ$얼굴 제모 레이저는 어떤 부작용이 있나요?$AAQ$, $AAA$초반 일시적 모낭염과 까무잡잡한 피부·기미 환자에서 색소 변화가 주된 부작용이며, 반드시 피부과 전문의 상담 후 받아야 안전합니다. 처음 자극을 받으면 일시적으로 염증이 생기면서 모낭염이 발생할 수 있지만, 회차가 거듭될수록 모낭이 파괴되어 모낭염이 점차 줄어듭니다.

처음 시술 후 모낭염이 발생하면 이후 예방적으로 약을 함께 처방받게 됩니다. 더 중요한 부작용은 색소 관련 위험입니다. 제모 레이저는 **털 생성에 관계하는 부분의 멜라닌 세포를 타겟으로** 하기 때문에 멜라닌이 많아 피부가 까무잡잡한 분은 너무 강하게 시술하면 화상이나 일시적 딱지가 생길 수 있고 기미가 있다면 더 심해질 수 있습니다. 그렇다고 너무 약하게 하면 효과가 없으므로 경험이 많은 시술자에게 받아야 합니다.$AAA$, array['제모레이저부작용', '모낭염', '색소침착', '화상위험', '기미악화']::text[], 2024, '_OzrE2BwSU8-4', 'https://youtu.be/_OzrE2BwSU8?t=294s', null, '2024-06-25 00:00:00+00'::timestamptz, '2024-06-25 00:00:00+00'::timestamptz);
